globalThis.__BQ = {"aktivasyonEnerji":{"ilkokul":{"kolay":[{"q":"Bir kibriti yakmak için önce ne yapmak gerekir?","fig":"<svg viewBox='0 0 220 90'><rect x='0' y='0' width='220' height='90' fill='#f5f7fa'/><rect x='40' y='55' width='90' height='6' fill='#33415588'/><circle cx='130' cy='58' r='8' fill='#e0552b'/><path d='M60 50 L120 52' stroke='#2b6be0' stroke-width='3'/><path d='M114 46 L122 52 L114 58' fill='none' stroke='#2b6be0' stroke-width='3'/><text x='55' y='40' fill='#1a2b45' font-size='11'>sürtme</text></svg>","steps":[{"t":"Başlangıç","a":"sürtmek","d":"Kibriti yakmak için önce kutuya sürterek ona biraz <b>enerji</b> vermek gerekir."},{"t":"Sonra","a":"yanar","d":"Bu küçük başlangıç enerjisi verilince kibrit yanmaya başlar."}],"ans":"Önce sürterek biraz <b>başlangıç enerjisi</b> vermek gerekir."},{"q":"Bir oyunu başlatmak için ilk önce küçük bir itme gerekiyorsa, tepkimeler için de buna benzer ne gerekir?","steps":[{"t":"İlk itme","a":"başlangıç","d":"Bir şeyin başlaması için çoğu zaman küçük bir <b>başlangıç enerjisi</b> gerekir."},{"t":"Tepkimede","a":"aynı şey","d":"Kimyasal tepkimeler de başlamak için böyle bir enerji ister."}],"ans":"Bir <b>başlangıç enerjisi</b> gerekir."},{"q":"Tepenin üstündeki bir topu öbür yana yuvarlamak için önce ne yapmalısın?","fig":"<svg viewBox='0 0 220 110'><rect x='0' y='0' width='220' height='110' fill='#f5f7fa'/><path d='M10 95 Q110 10 210 95' fill='none' stroke='#1a2b45' stroke-width='3'/><circle cx='40' cy='80' r='9' fill='#e0552b'/><path d='M55 78 L80 60' stroke='#2b6be0' stroke-width='3'/><path d='M74 58 L82 60 L78 67' fill='none' stroke='#2b6be0' stroke-width='3'/><text x='90' y='30' fill='#1a2b45' font-size='12'>tepe</text></svg>","steps":[{"t":"Tepe var","a":"yukarı it","d":"Topu önce tepenin üstüne kadar <b>itmek</b> gerekir."},{"t":"Sonra","a":"kendi yuvarlanır","d":"Tepeyi geçince top kendiliğinden öbür yana yuvarlanır."}],"ans":"Önce topu <b>tepeye kadar itmek</b> gerekir."},{"q":"Tepkimenin başlaması için gereken bu başlangıç enerjisinin özel bir adı vardır. Genel olarak bu enerji ne işe yarar?","steps":[{"t":"Görevi","a":"başlatmak","d":"Bu enerji tepkimeyi <b>başlatmak</b> için harcanır."},{"t":"Olmazsa","a":"başlamaz","d":"Yeterli başlangıç enerjisi verilmezse tepkime başlamaz."}],"ans":"Tepkimeyi <b>başlatmaya</b> yarar."},{"q":"Mum yanarken neden önce çakmakla tutuşturmak gerekir?","steps":[{"t":"Kendi yanmaz","a":"başlangıç","d":"Mum kendiliğinden tutuşmaz, ona önce bir <b>başlangıç enerjisi</b> vermek gerekir."},{"t":"Çakmak","a":"enerji verir","d":"Çakmak alevi bu başlangıç enerjisini sağlar ve mum yanmaya başlar."}],"ans":"Yanması için <b>başlangıç enerjisi</b> gerektiğinden."}],"zor":[{"q":"Topu küçük bir tepeden aşırmak büyük bir tepeden aşırmaktan daha kolaydır. Tepkimeler için bu ne anlama gelir?","steps":[{"t":"Küçük tepe","a":"kolay","d":"Küçük tepeyi aşmak için az enerji yeter, top kolayca geçer."},{"t":"Büyük tepe","a":"zor","d":"Büyük tepe için çok enerji gerekir, geçmesi zorlaşır."},{"t":"Tepkimede","a":"küçük eşik hızlı","d":"Gereken başlangıç enerjisi <b>küçükse</b> tepkime daha kolay ve hızlı başlar."}],"ans":"Gereken enerji <b>küçükse</b> tepkime daha kolay başlar."},{"q":"Tepkimeyi başlatmak için gereken eşik enerjiye bilimde ne ad verilir?","steps":[{"t":"Eşik enerji","a":"aktivasyon enerjisi","d":"Tepkimenin başlaması için gereken en az enerjiye <b>aktivasyon enerjisi</b> denir."},{"t":"Kısaltma","a":"Ea","d":"Bu enerji kısaca <b>Ea</b> ile gösterilir."}],"ans":"Buna <b>aktivasyon enerjisi (Ea)</b> denir."},{"q":"Aktivasyon enerjisi düşük olan bir tepkime mi yoksa yüksek olan mı daha hızlı başlar?","steps":[{"t":"Düşük eşik","a":"kolay aşılır","d":"Eşik düşükse tanecikler bu enerjiye kolay ulaşır."},{"t":"Sonuç","a":"daha hızlı","d":"Düşük <b>Ea'lı</b> tepkime daha hızlı başlar."}],"ans":"<b>Düşük</b> aktivasyon enerjili tepkime daha hızlı başlar."},{"q":"Odun ateşi başlatmak için neden tutuşturucu (çıra) kullanılır?","steps":[{"t":"Odun zor tutuşur","a":"yüksek eşik","d":"Kalın odunun yanması için gereken başlangıç enerjisi yüksektir."},{"t":"Çıra","a":"kolay tutuşur","d":"İnce çıra düşük enerjiyle tutuşur ve gereken ısıyı verir."},{"t":"Sonuç","a":"eşik aşılır","d":"Çıranın verdiği ısı odunun <b>eşik enerjisini</b> aşmasını sağlar."}],"ans":"Odunun <b>başlangıç (eşik) enerjisini</b> aşmasını sağlamak için."},{"q":"İki kişi bir kapıyı açmak için önce kilidi açmak zorundaysa, bu durum tepkimedeki neye benzer?","steps":[{"t":"Kilit engeli","a":"eşik","d":"Kapıyı açmadan önce aşılması gereken bir engel (kilit) vardır."},{"t":"Tepkimede","a":"aktivasyon enerjisi","d":"Tepkimede de aşılması gereken bir enerji engeli, yani <b>aktivasyon enerjisi</b> vardır."},{"t":"Aşınca","a":"tepkime olur","d":"Bu engel aşıldığında tepkime gerçekleşir."}],"ans":"Aşılması gereken <b>aktivasyon enerjisi</b> engeline benzer."}]},"ortaokul":{"kolay":[{"q":"Aktivasyon enerjisi (Ea) nedir?","steps":[{"t":"Tanım","a":"eşik enerji","d":"Bir tepkimenin başlayabilmesi için gereken en az enerjiye <b>aktivasyon enerjisi</b> denir."},{"t":"Gösterim","a":"Ea","d":"Kısaca Ea sembolüyle gösterilir ve birimi genellikle kJ'dür."}],"ans":"Tepkimenin başlaması için gereken <b>eşik enerjidir</b>."},{"q":"Aktivasyon enerjisi düşük olan tepkimeler neden daha hızlıdır?","steps":[{"t":"Düşük eşik","a":"kolay aşılır","d":"Eşik düşükse taneciklerin daha büyük kısmı bu enerjiye ulaşabilir."},{"t":"Sonuç","a":"hızlı","d":"Daha çok tanecik eşiği aştığı için tepkime <b>hızlı</b> ilerler."}],"ans":"Eşik kolay aşıldığı için tepkime <b>hızlanır</b>."},{"q":"Tepkime sırasında bağların yeniden düzenlendiği, kararsız ara yapıya ne ad verilir?","steps":[{"t":"Ara yapı","a":"aktifleşmiş kompleks","d":"Eski bağların koptuğu, yeni bağların oluşmaya başladığı kararsız yapıya <b>aktifleşmiş kompleks</b> denir."},{"t":"Diğer adı","a":"geçiş hâli","d":"Buna geçiş hâli de denir; enerjinin en yüksek olduğu noktadır."}],"ans":"Buna <b>aktifleşmiş kompleks (geçiş hâli)</b> denir."},{"q":"Katalizör tepkime hızını nasıl artırır?","steps":[{"t":"Katalizör","a":"Ea'yı düşürür","d":"Katalizör, tepkimeye daha düşük aktivasyon enerjili yeni bir yol açar."},{"t":"Sonuç","a":"daha çok tanecik aşar","d":"Eşik düştüğü için daha çok tanecik aşar, tepkime <b>hızlanır</b>."}],"ans":"<b>Aktivasyon enerjisini</b> düşürerek hızlandırır."},{"q":"Bir kibritin kendiliğinden yanmamasını aktivasyon enerjisiyle açıklayın.","steps":[{"t":"Yüksek eşik","a":"Ea büyük","d":"Kibrit başının tutuşması için gereken aktivasyon enerjisi yüksektir."},{"t":"Sürtme","a":"enerji verir","d":"Sürterek verilen ısı bu eşiği aştırır ve kibrit yanar."}],"ans":"Yanma için gereken <b>Ea</b> verilene kadar başlamaz."}],"zor":[{"q":"Enerji–tepkime yolu grafiğinde aktivasyon enerjisi neresidir?","fig":"<svg viewBox='0 0 230 120'><rect x='0' y='0' width='230' height='120' fill='#f5f7fa'/><path d='M20 80 Q90 10 130 35 Q170 60 210 60' fill='none' stroke='#1a2b45' stroke-width='3'/><line x1='20' y1='80' x2='20' y2='80' stroke='#1a2b45'/><line x1='95' y1='80' x2='95' y2='22' stroke='#2b6be0' stroke-width='2' stroke-dasharray='4 3'/><text x='100' y='50' fill='#2b6be0' font-size='12'>Ea</text><text x='12' y='95' fill='#1a2b45' font-size='11'>girenler</text><text x='160' y='75' fill='#1a2b45' font-size='11'>ürünler</text></svg>","steps":[{"t":"Grafik","a":"tepe noktası","d":"Eğrinin en yüksek noktası aktifleşmiş komplekse karşılık gelir."},{"t":"Ea","a":"girenden tepeye fark","d":"Girenlerin enerjisinden tepe noktasına kadar olan enerji farkı <b>Ea</b>'dır."}],"ans":"Girenlerden <b>tepe noktasına</b> kadar olan enerji farkıdır."},{"q":"Aynı tepkimenin Ea değeri katalizörlü ve katalizörsüz halde nasıl karşılaştırılır?","steps":[{"t":"Katalizörsüz","a":"yüksek Ea","d":"Katalizör yokken tepkimenin aşması gereken eşik yüksektir."},{"t":"Katalizörlü","a":"düşük Ea","d":"Katalizör eşik enerjiyi düşürür, daha kolay bir yol açar."},{"t":"Sonuç","a":"hız ↑","d":"Düşen Ea sayesinde tepkime <b>hızlanır</b>; ürün ve girenlerin enerjisi değişmez."}],"ans":"Katalizör <b>Ea'yı düşürür</b>, tepkime hızlanır."},{"q":"Endotermik bir tepkimede aktivasyon enerjisi ile ileri ve geri yön ilişkisi nasıldır?","steps":[{"t":"Endotermik","a":"ürün enerjisi yüksek","d":"Endotermik tepkimede ürünlerin enerjisi girenlerden yüksektir."},{"t":"İleri yön","a":"Ea büyük","d":"İleri yön için aşılması gereken eşik görece yüksektir."},{"t":"Geri yön","a":"daha küçük Ea","d":"Geri yönün aktivasyon enerjisi ileri yönünkinden <b>küçüktür</b>."}],"ans":"İleri yön Ea'sı, geri yön Ea'sından <b>büyüktür</b>."},{"q":"Sıcaklığın artırılması neden aktivasyon enerjisini değiştirmediği hâlde tepkimeyi hızlandırır?","steps":[{"t":"Ea sabit","a":"değişmez","d":"Aktivasyon enerjisi tepkimenin kendine özgü değeridir; sıcaklıkla değişmez."},{"t":"Tanecik enerjisi","a":"artar","d":"Sıcaklık artınca taneciklerin ortalama enerjisi artar."},{"t":"Sonuç","a":"eşik aşan çok","d":"Daha çok tanecik <b>Ea'yı aşacak</b> enerjiye ulaşır, tepkime hızlanır."}],"ans":"Ea aynı kalır ama <b>eşiği aşan tanecik</b> sayısı artar."},{"q":"Aktifleşmiş kompleksin kararsız olması ne anlama gelir?","steps":[{"t":"En yüksek enerji","a":"tepe","d":"Aktifleşmiş kompleks enerjinin en yüksek olduğu noktadadır."},{"t":"Kararsız","a":"kısa ömürlü","d":"Bu yapı çok kararsız ve kısa ömürlüdür; tutulup ayrı bir madde olarak elde edilemez."},{"t":"Sonuç","a":"ya ürün ya giren","d":"Hızla ya ürünlere dönüşür ya da girenlere geri döner."}],"ans":"Çok <b>kararsız</b> ve kısa ömürlüdür; ürüne ya da girene döner."}]},"lise":{"kolay":[{"q":"Aktivasyon enerjisi (Ea) kavramını tanımlayın.","steps":[{"t":"Tanım","a":"eşik enerji","d":"Girenlerin aktifleşmiş kompleksi oluşturmak için sahip olması gereken en az enerjiye <b>aktivasyon enerjisi</b> denir."},{"t":"Anlamı","a":"hız belirler","d":"Ea ne kadar küçükse tepkime o kadar hızlı gerçekleşir."}],"ans":"Aktifleşmiş kompleksi oluşturmak için gereken <b>en az enerjidir</b>."},{"q":"Aktifleşmiş kompleks (geçiş hâli) nedir?","steps":[{"t":"Ara yapı","a":"kararsız","d":"Eski bağların kısmen koptuğu, yeni bağların kısmen oluştuğu yüksek enerjili kararsız yapıdır."},{"t":"Konumu","a":"enerji tepesi","d":"Enerji–tepkime yolu eğrisinin tepe noktasına karşılık gelir."}],"ans":"Tepkimenin tepe noktasındaki <b>kararsız ara yapıdır</b>."},{"q":"Aktivasyon enerjisinin büyüklüğü ile tepkime hızı arasındaki ilişki nedir?","steps":[{"t":"Düşük Ea","a":"hızlı","d":"Ea düşükse taneciklerin büyük kısmı eşiği aşar, tepkime hızlıdır."},{"t":"Yüksek Ea","a":"yavaş","d":"Ea yüksekse az tanecik eşiği aşar, tepkime yavaştır."}],"ans":"Ea küçüldükçe tepkime hızı <b>artar</b>."},{"q":"Katalizörün aktivasyon enerjisine etkisi nedir?","fig":"<svg viewBox='0 0 240 120'><rect x='0' y='0' width='240' height='120' fill='#f5f7fa'/><path d='M20 85 Q90 15 150 45 Q190 65 220 65' fill='none' stroke='#1a2b45' stroke-width='3'/><path d='M20 85 Q85 45 150 45 Q190 55 220 65' fill='none' stroke='#e0552b' stroke-width='3' stroke-dasharray='5 3'/><text x='95' y='30' fill='#1a2b45' font-size='11'>Ea</text><text x='95' y='62' fill='#e0552b' font-size='11'>Ea(kat.)</text></svg>","steps":[{"t":"Yeni yol","a":"düşük Ea","d":"Katalizör, daha düşük aktivasyon enerjili alternatif bir mekanizma sağlar."},{"t":"Sonuç","a":"hız ↑","d":"Ea düştüğü için hız artar; ΔH (girilen–ürün enerji farkı) değişmez."}],"ans":"Katalizör <b>Ea'yı düşürür</b>, ΔH'yi değiştirmez."},{"q":"Aktivasyon enerjisi, ekzotermik ve endotermik tepkimelerin enerji profilinde nasıl görünür?","fig":"<svg viewBox='0 0 240 120'><rect x='0' y='0' width='240' height='120' fill='#f5f7fa'/><path d='M15 80 Q60 20 100 45 Q130 65 130 95' fill='none' stroke='#1a2b45' stroke-width='3'/><text x='10' y='95' fill='#1a2b45' font-size='10'>ekzo.</text><path d='M150 95 Q190 25 215 45 Q230 55 235 50' fill='none' stroke='#e0552b' stroke-width='3'/><text x='150' y='110' fill='#e0552b' font-size='10'>endo.</text></svg>","steps":[{"t":"Ortak nokta","a":"tepe Ea","d":"Her ikisinde de girenlerden tepe noktasına kadarki fark Ea'dır."},{"t":"Fark","a":"ürün konumu","d":"Ekzotermikte ürün enerjisi girenden düşük, endotermikte yüksektir; Ea her ikisinde de pozitiftir."}],"ans":"Her ikisinde de Ea girenlerden <b>tepe noktasına</b> kadarki farktır."}],"zor":[{"q":"Bir ileri tepkimenin Ea değeri 80 kJ, ΔH değeri −30 kJ ise geri tepkimenin aktivasyon enerjisi kaç kJ'dür?","fig":"<svg viewBox='0 0 240 120'><rect x='0' y='0' width='240' height='120' fill='#f5f7fa'/><path d='M25 60 Q90 10 130 35 Q175 70 215 80' fill='none' stroke='#1a2b45' stroke-width='3'/><line x1='25' y1='60' x2='90' y2='60' stroke='#5b6b85' stroke-dasharray='3 3'/><line x1='130' y1='80' x2='215' y2='80' stroke='#5b6b85' stroke-dasharray='3 3'/><text x='95' y='30' fill='#2b6be0' font-size='10'>Ea ileri</text><text x='135' y='105' fill='#e0552b' font-size='10'>ΔH</text></svg>","steps":[{"t":"İlişki","a":"Ea(geri)=Ea(ileri)−ΔH","d":"Geri yön aktivasyon enerjisi, ileri yön Ea'sından ΔH çıkarılarak bulunur."},{"t":"Değerleri yerine koy","a":"80−(−30)","d":"Ea(geri) = 80 − (−30) = 80 + 30 kJ."},{"t":"Sonuç","a":"110 kJ","d":"Geri tepkimenin aktivasyon enerjisi <b>110 kJ</b>'dür."}],"ans":"Ea(geri) = <b>110 kJ</b>."},{"q":"Bir ileri tepkimenin Ea değeri 50 kJ, geri tepkimenin Ea değeri 70 kJ ise tepkime ekzotermik mi endotermik midir ve ΔH kaçtır?","steps":[{"t":"ΔH bağıntısı","a":"Ea(ileri)−Ea(geri)","d":"ΔH = Ea(ileri) − Ea(geri) bağıntısı kullanılır."},{"t":"Hesap","a":"50−70","d":"ΔH = 50 − 70 = −20 kJ."},{"t":"Yorum","a":"ekzotermik","d":"ΔH < 0 olduğundan tepkime <b>ekzotermiktir</b>."}],"ans":"ΔH = <b>−20 kJ</b>; tepkime <b>ekzotermiktir</b>."},{"q":"Katalizörün ΔH'yi değiştirmediği hâlde hem ileri hem geri tepkimeyi hızlandırması nasıl açıklanır?","steps":[{"t":"Ea düşer","a":"iki yön de","d":"Katalizör ileri yön Ea'sını da geri yön Ea'sını da aynı miktarda düşürür."},{"t":"ΔH","a":"değişmez","d":"Giren ve ürün enerji düzeyleri sabit kaldığından ΔH = Ea(ileri) − Ea(geri) değişmez."},{"t":"Sonuç","a":"ikisi de hızlanır","d":"İki yönün de eşiği düştüğü için hem ileri hem geri hız <b>artar</b>; denge daha hızlı kurulur."}],"ans":"Her iki yön Ea'sı eşit düştüğünden <b>ikisi de hızlanır</b>, ΔH sabit kalır."},{"q":"İki tepkimeden A'nın Ea'sı 40 kJ, B'nin Ea'sı 100 kJ ise aynı sıcaklıkta hangisinde eşiği aşan tanecik oranı daha büyüktür, neden?","steps":[{"t":"Eşik–oran ilişkisi","a":"düşük Ea → büyük oran","d":"Belirli bir sıcaklıkta Ea düştükçe enerjisi eşiği aşan tanecik oranı büyür."},{"t":"Karşılaştırma","a":"A < B","d":"A'nın Ea'sı (40 kJ) B'ninkinden (100 kJ) küçüktür."},{"t":"Sonuç","a":"A daha büyük","d":"Eşiği aşan tanecik oranı <b>A</b> tepkimesinde daha büyüktür; A daha hızlıdır."}],"ans":"<b>A</b> tepkimesinde; Ea'sı küçük olduğu için."},{"q":"Sıcaklık 10 °C arttığında çoğu tepkime hızının yaklaşık iki katına çıkmasının aktivasyon enerjisiyle ilişkisini açıklayın.","steps":[{"t":"Enerji dağılımı","a":"sağa kayar","d":"Sıcaklık artınca taneciklerin enerji dağılımı yüksek enerjilere doğru kayar."},{"t":"Ea'yı aşan oran","a":"belirgin artar","d":"Eşiği (Ea'yı) aşan taneciklerin oranı küçük sıcaklık artışıyla bile <b>belirgin</b> artar."},{"t":"Sonuç","a":"hız ~2 kat","d":"Bu nedenle etkin çarpışma sayısı çoğalır ve hız yaklaşık iki katına çıkabilir."}],"ans":"Sıcaklık <b>Ea'yı aşan tanecik oranını</b> belirgin artırdığından hız yaklaşık 2 katına çıkar."}]}},"bagEnerjisi":{"ilkokul":{"kolay":[{"q":"İki Lego parçasını birbirine takmak mı, ayırmak mı daha çok güç ister?","steps":[{"t":"Takma","a":"yerine oturur","d":"İki parça takılınca kendiliğinden sıkıca tutunur."},{"t":"Ayırma","a":"güç gerekir","d":"Onları ayırmak için çekmek, yani güç (enerji) harcamak gerekir."}],"ans":"Lego parçalarını ayırmak güç (enerji) ister; takmak ise kendiliğinden tutunur."},{"q":"Atomlar birbirine bağlanırken mi yoksa ayrılırken mi enerji açığa çıkar?","steps":[{"t":"Bağlanma","a":"enerji çıkar","d":"Atomlar birbirine bağlandığında enerji açığa çıkar."},{"t":"Ayrılma","a":"enerji ister","d":"Bağı koparıp ayrılmak için ise enerji vermek gerekir."}],"ans":"Atomlar bağlanırken enerji açığa çıkar; ayrılırken enerji gerekir."},{"q":"Mum yandığında etrafa ne yayar?","steps":[{"t":"Yanma","a":"ısı ve ışık","d":"Mum yanarken etrafa ısı ve ışık yayar."},{"t":"Enerji çıkar","a":"ekzotermik","d":"Yanma enerji açığa çıkaran bir olaydır, etrafı ısıtır."}],"ans":"Mum yandığında etrafa ısı ve ışık (enerji) yayar."},{"q":"Aşağıdaki gibi iki atomu birbirine bağlı tutan şeye ne denir?","fig":"<svg viewBox='0 0 320 150'><circle cx='110' cy='75' r='24' fill='#e0552b' stroke='#1a2b45'/><circle cx='210' cy='75' r='24' fill='#cfd8e8' stroke='#1a2b45'/><line x1='134' y1='75' x2='186' y2='75' stroke='#1a2b45' stroke-width='4'/><text x='160' y='130' font-size='12' text-anchor='middle' fill='#1a2b45'>iki atom arasi</text></svg>","steps":[{"t":"İki atom","a":"birleşik","d":"İki atom birbirine tutunmuş durumdadır."},{"t":"Tutan şey","a":"bağ","d":"Atomları bir arada tutan bu çekime bağ denir."}],"ans":"İki atomu birbirine tutan çekime bağ denir."},{"q":"Sıcak bir sobaya yaklaşınca ısınırız. Bu ısı nereden gelir?","steps":[{"t":"Yanma olur","a":"odun/kömür","d":"Sobada odun ya da kömür yanar."},{"t":"Enerji çıkar","a":"ısı","d":"Yanma sırasında enerji açığa çıkar, biz de bu ısıyı hissederiz."}],"ans":"Sobadaki ısı, yanma sırasında açığa çıkan enerjiden gelir."}],"zor":[{"q":"Bir kibrit yanarken neden ısı verir?","steps":[{"t":"Yanma","a":"yeni bağlar","d":"Kibrit yanarken maddeler havadaki oksijenle birleşir, yeni bağlar kurulur."},{"t":"Enerji","a":"açığa çıkar","d":"Yeni bağlar kurulurken enerji açığa çıktığı için kibrit ısı verir."}],"ans":"Kibrit yanarken yeni bağlar kurulduğu için enerji açığa çıkar ve ısı verir."},{"q":"Bir buz parçasını eritmek için neden ısı vermemiz gerekir?","steps":[{"t":"Tanecikler bağlı","a":"birbirini tutar","d":"Buzdaki su tanecikleri birbirine tutunmuş durumdadır."},{"t":"Ayırmak","a":"ısı gerekir","d":"Onları gevşetip ayırmak için dışarıdan ısı (enerji) vermemiz gerekir."}],"ans":"Buzdaki tanecikleri ayırmak için dışarıdan ısı vermemiz gerekir."},{"q":"Soğuk bir buz paketi (cold pack) açılınca neden soğur?","steps":[{"t":"Enerji çeker","a":"emer","d":"İçindeki madde çözünürken ortamdan enerji çeker."},{"t":"Soğuma","a":"ısı emilir","d":"Etraftan ısı emildiği için paket ve çevresi soğur."}],"ans":"Buz paketi çözünürken ortamdan ısı emdiği için soğur."},{"q":"Güçlü bağı koparmak mı, gevşek bağı koparmak mı daha çok enerji ister?","steps":[{"t":"Güçlü bağ","a":"sıkı tutar","d":"Güçlü bağ atomları daha sıkı tutar."},{"t":"Çok enerji","a":"zor kopar","d":"Bu yüzden güçlü bağı koparmak için daha çok enerji gerekir."}],"ans":"Güçlü bağı koparmak gevşek bağa göre daha çok enerji ister."},{"q":"Havai fişek patlarken ışık ve ses çıkarması neyi gösterir?","steps":[{"t":"Hızlı tepkime","a":"yanma","d":"Havai fişek içindeki maddeler çok hızlı yanar (tepkir)."},{"t":"Enerji","a":"açığa çıkar","d":"Bu tepkimede büyük enerji açığa çıkar; bu enerji ışık, ses ve ısı olur."}],"ans":"Havai fişeğin ışık ve sesi, tepkimede büyük enerjinin açığa çıktığını gösterir."}]},"ortaokul":{"kolay":[{"q":"Ekzotermik tepkime ne demektir?","steps":[{"t":"Tanım","a":"ısı verir","d":"Çevreye enerji (ısı) veren tepkimeye ekzotermik denir."},{"t":"Örnek","a":"yanma","d":"Yanma ve çoğu nötrleşme tepkimesi ekzotermiktir, ortamı ısıtır."}],"ans":"Ekzotermik tepkime çevreye ısı veren tepkimedir; yanma buna örnektir."},{"q":"Endotermik tepkime ne demektir?","steps":[{"t":"Tanım","a":"ısı alır","d":"Çevreden enerji (ısı) alan tepkimeye endotermik denir."},{"t":"Sonuç","a":"ortam soğur","d":"Ortamdan ısı çekildiği için çevre soğur."}],"ans":"Endotermik tepkime çevreden ısı alan tepkimedir; ortam soğur."},{"q":"Bağ kırmak için enerji mi gerekir, yoksa bağ kırmak enerji mi verir?","steps":[{"t":"Bağ kırma","a":"enerji gerekir","d":"Bir bağı koparmak için dışarıdan enerji vermek gerekir (endotermik adım)."},{"t":"Bağ oluşma","a":"enerji verir","d":"Bağ oluşurken ise enerji açığa çıkar (ekzotermik adım)."}],"ans":"Bağ kırmak enerji gerektirir; bağ oluşturmak ise enerji verir."},{"q":"Bir tepkimede ısı alışverişini gösteren şema aşağıdaki gibidir. Ekzotermik olanda enerji ne yönde gider?","fig":"<svg viewBox='0 0 320 150'><rect x='40' y='40' width='80' height='60' rx='6' fill='#cfd8e8' stroke='#1a2b45'/><text x='80' y='75' font-size='10' text-anchor='middle' fill='#1a2b45'>sistem</text><line x1='120' y1='70' x2='220' y2='70' stroke='#e0552b' stroke-width='3'/><polygon points='220,70 212,65 212,75' fill='#e0552b'/><text x='250' y='75' font-size='11' fill='#1a2b45'>cevre</text><text x='170' y='55' font-size='10' text-anchor='middle' fill='#1a2b45'>isi</text></svg>","steps":[{"t":"Ekzotermik","a":"sistemden çevreye","d":"Ekzotermik tepkimede enerji sistemden çevreye doğru gider."},{"t":"Sonuç","a":"çevre ısınır","d":"Çevreye ısı verildiği için ortam ısınır."}],"ans":"Ekzotermik tepkimede enerji sistemden çevreye gider, çevre ısınır."},{"q":"Yemek pişirmek için ocak yakmamız tepkimenin hangi türüne örnektir?","steps":[{"t":"Doğal gaz yanar","a":"yanma","d":"Ocakta doğal gaz oksijenle yanar."},{"t":"Isı verir","a":"ekzotermik","d":"Yanma ısı açığa çıkardığı için ekzotermik tepkimedir."}],"ans":"Ocakta gazın yanması ısı verdiği için ekzotermik tepkimeye örnektir."}],"zor":[{"q":"Bir tepkimede toplam 500 kJ bağ kırılıp 700 kJ bağ oluşuyorsa tepkime endotermik mi ekzotermik mi olur?","fig":"<svg viewBox='0 0 320 150'><line x1='40' y1='120' x2='290' y2='120' stroke='#1a2b45' stroke-width='2'/><rect x='70' y='70' width='40' height='50' fill='#5b6b85'/><text x='90' y='138' font-size='10' text-anchor='middle' fill='#1a2b45'>kirilan 500</text><rect x='200' y='40' width='40' height='80' fill='#e0552b'/><text x='220' y='138' font-size='10' text-anchor='middle' fill='#1a2b45'>olusan 700</text><text x='160' y='25' font-size='10' text-anchor='middle' fill='#1a2b45'>olusan>kirilan: ekzo</text></svg>","steps":[{"t":"Kural","a":"karşılaştır","d":"Oluşan bağ enerjisi kırılandan büyükse tepkime ekzotermiktir."},{"t":"Karşılaştırma","a":"700 > 500","d":"Oluşan 700 kJ, kırılan 500 kJ'den büyüktür; fazla enerji açığa çıkar."},{"t":"Sonuç","a":"ekzotermik","d":"Net 200 kJ enerji çevreye verilir, tepkime ekzotermiktir."}],"ans":"Oluşan (700 kJ) kırılandan (500 kJ) büyük olduğu için tepkime ekzotermiktir, 200 kJ açığa çıkar."},{"q":"Bir tepkimede 900 kJ bağ kırılıp 750 kJ bağ oluşuyorsa ısı alışverişi nasıl olur?","fig":"<svg viewBox='0 0 320 150'><line x1='40' y1='120' x2='290' y2='120' stroke='#1a2b45' stroke-width='2'/><rect x='70' y='35' width='40' height='85' fill='#5b6b85'/><text x='90' y='138' font-size='10' text-anchor='middle' fill='#1a2b45'>kirilan 900</text><rect x='200' y='55' width='40' height='65' fill='#e0552b'/><text x='220' y='138' font-size='10' text-anchor='middle' fill='#1a2b45'>olusan 750</text><text x='160' y='25' font-size='10' text-anchor='middle' fill='#1a2b45'>kirilan>olusan: endo</text></svg>","steps":[{"t":"Karşılaştırma","a":"900 > 750","d":"Kırılan bağ enerjisi (900 kJ) oluşandan (750 kJ) büyüktür."},{"t":"Net","a":"150 kJ emilir","d":"Eksik kalan 150 kJ dışarıdan emilir, tepkime endotermiktir."}],"ans":"Kırılan (900 kJ) oluşandan (750 kJ) büyük olduğu için tepkime endotermiktir, 150 kJ enerji emilir."},{"q":"Fotosentez endotermik, solunum ekzotermiktir. Bunu bağ enerjisiyle nasıl açıklarız?","steps":[{"t":"Fotosentez","a":"enerji depolar","d":"Fotosentezde güneş enerjisi kullanılarak yüksek enerjili bağlar (glikoz) kurulur, enerji depolanır."},{"t":"Solunum","a":"enerji açar","d":"Solunumda bu bağlar kırılıp daha kararlı bağlar oluşunca depolanan enerji açığa çıkar."}],"ans":"Fotosentez enerji depolayıp bağ kurduğu için endotermik, solunum bu enerjiyi bağ kırarak açtığı için ekzotermiktir."},{"q":"Yanma tepkimeleri neden hep ekzotermiktir; bağ enerjisiyle açıklayın.","steps":[{"t":"Bağlar kırılır","a":"enerji emilir","d":"Önce yakıt ve oksijendeki bağlar kırılır, bu enerji ister."},{"t":"Güçlü bağlar","a":"çok enerji çıkar","d":"Oluşan CO₂ ve H₂O bağları çok güçlü olduğundan kırılandan fazla enerji açığa çıkar."},{"t":"Net","a":"ekzotermik","d":"Açığa çıkan enerji emilenden fazla olduğu için yanma ekzotermiktir."}],"ans":"Yanmada oluşan CO₂ ve H₂O bağları kırılanlardan çok daha fazla enerji saldığı için tepkime hep ekzotermiktir."},{"q":"Bir kimyasal soğuk paket (cold pack) çözünürken neden soğur; bağ/etkileşim enerjisiyle açıklayın.","steps":[{"t":"Bağ kırma","a":"enerji emer","d":"Tuz çözünürken iyonlar arası bağları kırmak enerji gerektirir."},{"t":"Yeni etkileşim","a":"az enerji verir","d":"Oluşan iyon-su etkileşimleri daha az enerji saldığında net enerji emilir."},{"t":"Sonuç","a":"endotermik","d":"Sistem ortamdan ısı çektiği için paket soğur."}],"ans":"Kırılan bağlar oluşan etkileşimlerden fazla enerji gerektirdiği için çözünme endotermiktir ve paket soğur."}]},"lise":{"kolay":[{"q":"Bağ enerjisinden tepkime ısısı (ΔH) nasıl hesaplanır?","steps":[{"t":"Formül","a":"ΔH = Σkırılan − Σoluşan","d":"Tepkime ısısı, kırılan bağ enerjileri toplamından oluşan bağ enerjileri toplamı çıkarılarak bulunur."},{"t":"İşaret","a":"yorum","d":"ΔH negatifse ekzotermik, pozitifse endotermiktir."}],"ans":"ΔH = Σ(kırılan bağ enerjileri) − Σ(oluşan bağ enerjileri); negatifse ekzotermik, pozitifse endotermiktir."},{"q":"Bağ kırma adımı neden hep endotermiktir?","steps":[{"t":"Çekim yenilir","a":"enerji girer","d":"Atomları tutan çekimi yenmek için sisteme enerji vermek gerekir."},{"t":"İşaret","a":"pozitif","d":"Enerji girdiği için bağ kırma adımının enerjisi daima pozitif (endotermik) değerlidir."}],"ans":"Bağ kırmak atomlar arası çekimi yenmek için enerji gerektirdiğinden bu adım daima endotermiktir."},{"q":"Bağ oluşma adımı neden hep ekzotermiktir?","steps":[{"t":"Kararlılık","a":"enerji düşer","d":"Atomlar bağ kurunca sistemin enerjisi düşer, daha kararlı olur."},{"t":"İşaret","a":"negatif","d":"Fazla enerji dışarı salındığı için bağ oluşma adımı daima ekzotermiktir."}],"ans":"Bağ oluşurken sistem daha kararlı, düşük enerjili duruma geçip enerji saldığından bu adım daima ekzotermiktir."},{"q":"Bağ derecesi (tek, çift, üçlü) arttıkça bağ enerjisi nasıl değişir?","steps":[{"t":"Bağ derecesi","a":"artar","d":"Bağ derecesi arttıkça atomlar arası çekim güçlenir."},{"t":"Sıralama","a":"tek<çift<üçlü","d":"Bu yüzden bağ enerjisi tek < çift < üçlü sırasıyla artar."}],"ans":"Bağ derecesi arttıkça bağ enerjisi büyür: tek bağ < çift bağ < üçlü bağ."},{"q":"ΔH = +180 kJ/mol bulunan bir tepkime için ne söylenebilir?","steps":[{"t":"İşaret","a":"pozitif","d":"ΔH pozitif olduğundan sistem dışarıdan enerji alır."},{"t":"Yorum","a":"endotermik","d":"Kırılan bağlar oluşanlardan güçlüdür; tepkime endotermiktir ve 180 kJ ısı emer."}],"ans":"ΔH = +180 kJ/mol tepkimenin endotermik olduğunu ve 180 kJ ısı emdiğini gösterir."}],"zor":[{"q":"C₂H₄ + H₂ → C₂H₆ tepkimesinin ΔH'ını bağ enerjileriyle hesaplayın (C=C=614, C–C=348, C–H=413, H–H=436 kJ/mol).","fig":"<svg viewBox='0 0 320 150'><text x='20' y='60' font-size='13' fill='#1a2b45'>C₂H₄ + H₂</text><line x1='130' y1='55' x2='180' y2='55' stroke='#1a2b45' stroke-width='2'/><polygon points='180,55 172,51 172,59' fill='#1a2b45'/><text x='195' y='60' font-size='13' fill='#1a2b45'>C₂H₆</text><text x='160' y='115' font-size='11' text-anchor='middle' fill='#1a2b45'>ekzotermik katilma</text></svg>","steps":[{"t":"Kırılan","a":"1 C=C + 1 H–H","d":"Etende çift bağ açılır: 1×614 + 1×436 = 1050 kJ kırılan (C–H bağları korunur)."},{"t":"Oluşan","a":"1 C–C + 2 C–H","d":"Çift bağ tek bağa döner ve 2 yeni C–H kurulur: 1×348 + 2×413 = 348 + 826 = 1174 kJ oluşan."},{"t":"ΔH","a":"1050 − 1174 = −124","d":"ΔH = Σkırılan − Σoluşan = 1050 − 1174 = −124 kJ/mol."}],"ans":"ΔH = −124 kJ/mol; eten ile hidrojenin katılma tepkimesi ekzotermiktir."},{"q":"2HBr → H₂ + Br₂ tepkimesinin ΔH'ını hesaplayın (H–Br=366, H–H=436, Br–Br=193 kJ/mol).","fig":"<svg viewBox='0 0 320 150'><text x='20' y='60' font-size='13' fill='#1a2b45'>2HBr</text><line x1='90' y1='55' x2='140' y2='55' stroke='#1a2b45' stroke-width='2'/><polygon points='140,55 132,51 132,59' fill='#1a2b45'/><text x='155' y='60' font-size='13' fill='#1a2b45'>H₂ + Br₂</text><text x='160' y='115' font-size='11' text-anchor='middle' fill='#1a2b45'>endotermik ayrisma</text></svg>","steps":[{"t":"Kırılan","a":"2 H–Br","d":"2 mol H–Br bağı kırılır: 2×366 = 732 kJ."},{"t":"Oluşan","a":"H–H + Br–Br","d":"1 H–H ve 1 Br–Br oluşur: 436 + 193 = 629 kJ."},{"t":"ΔH","a":"732 − 629 = +103","d":"ΔH = 732 − 629 = +103 kJ/mol; pozitif olduğundan endotermik."}],"ans":"ΔH = +103 kJ/mol; HBr'nin ayrışması endotermik bir tepkimedir."},{"q":"C₂H₂ + 2H₂ → C₂H₆ tepkimesinin ΔH'ını bulun (C≡C=839, C–C=348, C–H=413, H–H=436 kJ/mol).","steps":[{"t":"Kırılan","a":"1 C≡C + 2 H–H","d":"Üçlü bağ ve 2 H–H kırılır: 1×839 + 2×436 = 839 + 872 = 1711 kJ (mevcut C–H'ler korunur)."},{"t":"Oluşan","a":"1 C–C + 4 C–H","d":"Üçlü bağ tek bağa döner, 4 yeni C–H kurulur: 1×348 + 4×413 = 348 + 1652 = 2000 kJ."},{"t":"ΔH","a":"1711 − 2000 = −289","d":"ΔH = 1711 − 2000 = −289 kJ/mol; güçlü ekzotermik."}],"ans":"ΔH = −289 kJ/mol; asetilenin hidrojenle doyurulması ekzotermiktir."},{"q":"H₂ + F₂ → 2HF tepkimesinin ΔH'ını hesaplayın (H–H=436, F–F=159, H–F=567 kJ/mol).","fig":"<svg viewBox='0 0 320 150'><text x='20' y='60' font-size='13' fill='#1a2b45'>H₂ + F₂</text><line x1='110' y1='55' x2='160' y2='55' stroke='#1a2b45' stroke-width='2'/><polygon points='160,55 152,51 152,59' fill='#1a2b45'/><text x='175' y='60' font-size='13' fill='#1a2b45'>2HF</text><text x='160' y='115' font-size='11' text-anchor='middle' fill='#1a2b45'>guclu ekzotermik</text></svg>","steps":[{"t":"Kırılan","a":"H–H + F–F","d":"1 H–H ve 1 F–F kırılır: 436 + 159 = 595 kJ."},{"t":"Oluşan","a":"2 H–F","d":"2 mol H–F bağı oluşur: 2×567 = 1134 kJ."},{"t":"ΔH","a":"595 − 1134 = −539","d":"ΔH = 595 − 1134 = −539 kJ/mol; çok güçlü ekzotermik (zayıf F–F ve güçlü H–F nedeniyle)."}],"ans":"ΔH = −539 kJ/mol; HF oluşumu zayıf F–F ve çok güçlü H–F bağı nedeniyle güçlü ekzotermiktir."},{"q":"Bağ enerjileriyle hesaplanan ΔH ile deneysel (kalorimetrik) ΔH arasında neden küçük farklar olur? Üç neden verin.","steps":[{"t":"Ortalama değerler","a":"yaklaşık","d":"Tablo bağ enerjileri çok molekülün ortalamasıdır, gerçek molekülde biraz farklıdır."},{"t":"Faz varsayımı","a":"gaz fazı","d":"Yöntem tüm türleri gaz kabul eder; sıvı/katı hal değişim enerjileri ihmal edilir."},{"t":"Rezonans/çevre","a":"ek etki","d":"Rezonans kararlılığı ve molekül içi etkileşimler tabloya tam yansımaz, küçük sapma oluşturur."}],"ans":"Tablo değerlerinin ortalama olması, gaz fazı varsayımı ve rezonans/çevre etkilerinin tam yansımaması nedeniyle hesaplanan ΔH deneysel değerden biraz sapar."}]}},"basincHacim":{"ilkokul":{"kolay":[{"q":"Bir kabın içindeki gazı sıkıştırıp küçültürsek tanecikler birbirine daha sık mı çarpar?","fig":"<svg viewBox='0 0 320 150'><rect x='30' y='30' width='110' height='90' fill='none' stroke='#1a2b45'/><circle cx='55' cy='55' r='6' fill='#2b6be0'/><circle cx='95' cy='70' r='6' fill='#2b6be0'/><circle cx='115' cy='100' r='6' fill='#2b6be0'/><circle cx='70' cy='100' r='6' fill='#2b6be0'/><text x='85' y='140' font-size='11' text-anchor='middle' fill='#1a2b45'>geniş kap</text><rect x='200' y='55' width='60' height='65' fill='none' stroke='#1a2b45'/><circle cx='215' cy='70' r='6' fill='#e0552b'/><circle cx='240' cy='75' r='6' fill='#e0552b'/><circle cx='225' cy='100' r='6' fill='#e0552b'/><circle cx='250' cy='105' r='6' fill='#e0552b'/><text x='230' y='140' font-size='11' text-anchor='middle' fill='#1a2b45'>sıkışık kap</text></svg>","steps":[{"t":"Küçük kap","a":"yakınlaşır","d":"Gaz küçük bir kaba sıkıştırılınca tanecikler birbirine yaklaşır."},{"t":"Çarpışma","a":"daha sık","d":"Yakınlaştıkları için tanecikler daha sık çarpışır."}],"ans":"Gaz sıkıştırılınca tanecikler yaklaşır ve birbirine daha sık çarpar."},{"q":"Şişirilmiş bir balonu sıkarsak içindeki hava taneciklerine ne olur?","steps":[{"t":"Sıkma","a":"hacim küçülür","d":"Balonu sıkınca içindeki havanın kapladığı yer (hacim) küçülür."},{"t":"Tanecikler","a":"sıkışır","d":"Aynı sayıda tanecik daha küçük yere sıkışır, birbirine yaklaşır."}],"ans":"Balonu sıkınca hava tanecikleri daha küçük bir yere sıkışıp birbirine yaklaşır."},{"q":"Gaz taneciklerini sıkıştırmak tepkimeyi hızlandırır mı?","steps":[{"t":"Sıkıştırma","a":"yakınlaşma","d":"Sıkıştırınca tanecikler birbirine yaklaşır."},{"t":"Sonuç","a":"hızlanır","d":"Daha sık çarpıştıkları için tepkime hızlanır."}],"ans":"Evet, gaz taneciklerini sıkıştırmak çarpışmayı artırdığı için tepkimeyi hızlandırır."},{"q":"Basınç, gaz taneciklerinin kabın duvarına yaptığı ne ile ilgilidir?","steps":[{"t":"Tanecik çarpması","a":"duvara vurma","d":"Gaz tanecikleri sürekli kabın duvarlarına çarpar."},{"t":"Basınç","a":"itme","d":"Bu çarpmaların oluşturduğu itmeye basınç denir."}],"ans":"Basınç, gaz taneciklerinin kabın duvarlarına çarpmasıyla oluşan itmedir."},{"q":"Aynı gazı büyük kaptan küçük kaba alırsak tanecikler daha mı kalabalık olur?","steps":[{"t":"Küçük kap","a":"az yer","d":"Küçük kapta tanecikler için daha az yer vardır."},{"t":"Kalabalık","a":"daha sık","d":"Aynı sayıda tanecik az yere sığınca daha kalabalık (sık) olur."}],"ans":"Gaz küçük kaba alınınca tanecikler aynı sayıda kalır ama daha kalabalık (sık) hale gelir."}],"zor":[{"q":"Bir gaz kabının hacmini yarıya indirirsek tanecik sıklığı ve tepkime hızı nasıl değişir?","steps":[{"t":"Hacim yarıya","a":"sıkışma","d":"Hacim küçülünce aynı tanecikler daha küçük yere sıkışır."},{"t":"Sıklık","a":"artar","d":"Birim hacimde tanecik çoğalır, çarpışma sıklaşır."},{"t":"Hız","a":"artar","d":"Çarpışmalar sıklaştığı için tepkime hızlanır."}],"ans":"Hacim yarıya inince tanecik sıklığı artar, çarpışmalar sıklaşır ve tepkime hızlanır."},{"q":"Neden basınç etkisi sadece gaz tepkimelerinde önemlidir, katı ve sıvılarda değil?","steps":[{"t":"Gaz","a":"kolay sıkışır","d":"Gaz tanecikleri arası boşluk çok olduğundan basınçla kolayca sıkışır."},{"t":"Katı/sıvı","a":"sıkışmaz","d":"Katı ve sıvılarda tanecikler zaten çok yakındır, basınçla neredeyse sıkışmaz."}],"ans":"Gazlar basınçla kolayca sıkışıp yoğunlaşabildiği için basınç etkisi gaz tepkimelerinde önemlidir; katı ve sıvılar sıkışmadığından etkilenmez."},{"q":"Bir gaz tepkimesinde basıncı artırmak için hacme ne yapmak gerekir?","fig":"<svg viewBox='0 0 320 150'><rect x='80' y='30' width='160' height='90' fill='none' stroke='#1a2b45'/><line x1='80' y1='55' x2='240' y2='55' stroke='#5b6b85' stroke-dasharray='4 4'/><polygon points='160,40 150,55 170,55' fill='#e0552b'/><text x='160' y='95' font-size='11' text-anchor='middle' fill='#1a2b45'>piston aşağı</text><text x='160' y='138' font-size='11' text-anchor='middle' fill='#1a2b45'>hacim azalır → basınç artar</text></svg>","steps":[{"t":"Hacim","a":"azaltılır","d":"Pistonu iterek gazın hacmi küçültülür."},{"t":"Basınç","a":"artar","d":"Hacim azalınca tanecikler sıkışır ve basınç artar."}],"ans":"Gazın hacmini azaltmak (sıkıştırmak) basıncı artırır."},{"q":"İki özdeş gaz kabından biri sıkıştırılmış, diğeri geniş. Hangisinde tepkime daha hızlıdır?","steps":[{"t":"Sıkışık kap","a":"sık tanecik","d":"Sıkıştırılmış kapta tanecikler daha sık ve yakındır."},{"t":"Sonuç","a":"sıkışıkta hızlı","d":"Daha sık çarpıştıkları için sıkıştırılmış kaptaki tepkime daha hızlıdır."}],"ans":"Sıkıştırılmış (yüksek basınçlı) kapta tanecikler daha sık olduğundan tepkime daha hızlı olur."},{"q":"Bir gazın bulunduğu kabın hacmini artırırsak (gevşetirsek) tepkime neden yavaşlar?","steps":[{"t":"Hacim artışı","a":"tanecikler dağılır","d":"Hacim büyüyünce aynı tanecikler daha geniş yere dağılır."},{"t":"Çarpışma azalır","a":"yavaşlar","d":"Tanecikler seyrekleştiği için çarpışmalar azalır ve tepkime yavaşlar."}],"ans":"Hacim artınca tanecikler daha geniş yere dağılıp seyrekleşir; çarpışmalar azaldığı için tepkime yavaşlar."}]},"ortaokul":{"kolay":[{"q":"Gaz tepkimelerinde basıncın tepkime hızına etkisini açıklayınız.","steps":[{"t":"Basınç artışı","a":"hacim azalır","d":"Basınç artırılınca gazın hacmi küçülür ve tanecikler sıkışır."},{"t":"Çarpışma","a":"sıklaşır","d":"Birim hacimde tanecik çoğaldığından çarpışma sıklaşır, hız artar."}],"ans":"Basınç artınca gaz hacmi azalır, tanecikler sıkışır, çarpışmalar sıklaşır ve tepkime hızı artar."},{"q":"Basınç ile hacim arasındaki ilişki nasıldır (sabit sıcaklıkta)?","steps":[{"t":"Ters orantı","a":"biri artarsa diğeri azalır","d":"Sabit sıcaklıkta gazın basıncı artarsa hacmi azalır, hacmi artarsa basıncı azalır."},{"t":"Sonuç","a":"ters orantı","d":"Yani basınç ve hacim birbiriyle ters orantılıdır."}],"ans":"Sabit sıcaklıkta gazın basıncı ile hacmi ters orantılıdır; biri artarken diğeri azalır."},{"q":"Basınç artışı taneciklerin birim hacimdeki sayısını (derişimini) nasıl değiştirir?","fig":"<svg viewBox='0 0 320 150'><rect x='30' y='35' width='100' height='85' fill='none' stroke='#1a2b45'/><circle cx='50' cy='55' r='5' fill='#2b6be0'/><circle cx='90' cy='60' r='5' fill='#2b6be0'/><circle cx='70' cy='95' r='5' fill='#2b6be0'/><circle cx='110' cy='100' r='5' fill='#2b6be0'/><text x='80' y='138' font-size='10' text-anchor='middle' fill='#1a2b45'>düşük basınç</text><rect x='210' y='55' width='55' height='65' fill='none' stroke='#1a2b45'/><circle cx='222' cy='70' r='5' fill='#e0552b'/><circle cx='250' cy='72' r='5' fill='#e0552b'/><circle cx='230' cy='100' r='5' fill='#e0552b'/><circle cx='255' cy='105' r='5' fill='#e0552b'/><text x='237' y='138' font-size='10' text-anchor='middle' fill='#1a2b45'>yüksek basınç</text></svg>","steps":[{"t":"Basınç artar","a":"hacim küçülür","d":"Basınç artınca tanecikler daha küçük hacme sıkışır."},{"t":"Derişim","a":"artar","d":"Aynı tanecik küçük hacimde toplandığından birim hacimdeki tanecik (derişim) artar."}],"ans":"Basınç artınca hacim küçülür ve birim hacimdeki tanecik sayısı, yani derişim artar."},{"q":"Hangi tür tepkimelerin hızı basınç değişiminden etkilenir?","steps":[{"t":"Gaz tepkimeleri","a":"etkilenir","d":"En az bir gaz tepkeni içeren tepkimelerin hızı basınçtan etkilenir."},{"t":"Katı/sıvı","a":"etkilenmez","d":"Sadece katı ya da sıvı içeren tepkimeler basınçtan neredeyse etkilenmez."}],"ans":"Yalnızca gaz tepkenli tepkimelerin hızı basınç değişiminden belirgin biçimde etkilenir."},{"q":"Basıncı düşürmek (hacmi artırmak) gaz tepkimesinin hızını nasıl etkiler?","steps":[{"t":"Basınç düşer","a":"hacim büyür","d":"Basınç azalınca gaz genleşir, hacmi büyür."},{"t":"Çarpışma","a":"azalır","d":"Tanecikler daha geniş yere dağılıp seyreldiği için çarpışmalar azalır, hız düşer."}],"ans":"Basıncı düşürmek hacmi artırır, tanecikleri seyreltir; çarpışmalar azaldığından tepkime hızı düşer."}],"zor":[{"q":"N₂(g) + 3H₂(g) → 2NH₃(g) tepkimesinde basıncı artırmak hızı neden artırır?","fig":"<svg viewBox='0 0 320 130'><rect x='100' y='25' width='120' height='80' fill='none' stroke='#1a2b45'/><circle cx='120' cy='45' r='6' fill='#5b6b85'/><circle cx='150' cy='50' r='6' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='180' cy='48' r='6' fill='#5b6b85'/><circle cx='130' cy='80' r='6' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='165' cy='85' r='6' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='200' cy='75' r='6' fill='#5b6b85'/><text x='160' y='123' font-size='11' text-anchor='middle' fill='#1a2b45'>basınç ↑ ⇒ tanecikler sıkışır</text></svg>","steps":[{"t":"Tepkime","a":"N₂ + 3H₂ → 2NH₃","d":"Azot ve hidrojen gazları birleşip amonyak gazını verir."},{"t":"Basınç artışı","a":"hacim azalır","d":"Basınç artınca gaz hacmi küçülür, N₂ ve H₂ tanecikleri birim hacimde sıklaşır."},{"t":"Sonuç","a":"hız artar","d":"Tanecikler sıklaştığından çarpışma sıklığı artar ve tepkime hızlanır."}],"ans":"Basınç artınca gaz hacmi küçülür, N₂ ve H₂ tanecikleri birim hacimde sıklaşır; çarpışmalar arttığından tepkime hızı artar."},{"q":"Basınç artışının tepkime hızına etkisi, derişim artışıyla nasıl aynı mantığa dayanır?","steps":[{"t":"Basınç → hacim","a":"hacim azalır","d":"Gazda basınç artırmak hacmi küçültür."},{"t":"Hacim → derişim","a":"derişim artar","d":"Hacim küçülünce birim hacimdeki tanecik, yani derişim artar."},{"t":"Ortak sonuç","a":"çarpışma artar","d":"Hem basınç hem derişim artışı sonuçta birim hacimdeki taneciği artırarak çarpışmayı sıklaştırır."}],"ans":"Basınç artışı gazda hacmi küçülterek derişimi artırır; sonuçta her ikisi de birim hacimdeki tanecik sayısını artırıp çarpışmaları sıklaştırdığından aynı mantıkla hızı yükseltir."},{"q":"Sadece katı ve sıvı içeren bir tepkimede basınç artışı hızı neden neredeyse etkilemez?","steps":[{"t":"Katı/sıvı","a":"sıkışmaz","d":"Katı ve sıvılarda tanecikler zaten çok yakın olduğundan basınçla hacimleri neredeyse değişmez."},{"t":"Derişim","a":"sabit kalır","d":"Hacim değişmediği için birim hacimdeki tanecik sayısı (derişim) de değişmez."},{"t":"Sonuç","a":"hız değişmez","d":"Çarpışma sıklığı değişmediğinden basınç artışı hızı etkilemez."}],"ans":"Katı ve sıvılar sıkışmadığından basınç artsa da hacimleri ve derişimleri değişmez; çarpışma sıklığı sabit kaldığı için tepkime hızı etkilenmez."},{"q":"Sabit sıcaklıkta hacmi yarıya indirilen bir gaz tepkimesinde tanecik derişimi nasıl değişir?","steps":[{"t":"Hacim","a":"V → V/2","d":"Hacim yarıya indirilir, gazdaki tanecik sayısı (mol) sabit kalır."},{"t":"Derişim","a":"iki katına","d":"Derişim mol/hacim olduğundan hacim yarıya inince derişim iki katına çıkar."},{"t":"Hız","a":"artar","d":"Birim hacimdeki tanecik iki katına çıktığından çarpışmalar sıklaşır, hız artar."}],"ans":"Hacim yarıya indirilince tanecik sayısı sabit kaldığından derişim iki katına çıkar; çarpışmalar sıklaştığı için tepkime hızı artar."},{"q":"Bir kaba tepkimeye girmeyen (asal) gaz eklenip basınç artırılırsa gaz tepkimesinin hızı neden değişmez?","steps":[{"t":"Asal gaz","a":"tepkimeye girmez","d":"Eklenen asal gaz tepken değildir, tepkimeye katılmaz."},{"t":"Hacim sabit","a":"derişim sabit","d":"Kabın hacmi sabit kaldığından tepken gazların birim hacimdeki sayısı (derişimi) değişmez."},{"t":"Sonuç","a":"hız değişmez","d":"Toplam basınç artsa da tepken derişimleri sabit kaldığından çarpışma sıklığı, yani hız değişmez."}],"ans":"Sabit hacimde asal gaz eklemek toplam basıncı artırsa da tepken gazların derişimini değiştirmediğinden çarpışma sıklığı sabit kalır ve tepkime hızı değişmez."}]},"lise":{"kolay":[{"q":"Gaz tepkimelerinde basınç artışının hızı artırmasını çarpışma kuramıyla açıklayınız.","steps":[{"t":"Basınç → derişim","a":"hacim azalır","d":"Sabit sıcaklıkta basınç artışı gaz hacmini küçültür, böylece gaz taneciklerinin molar derişimi (mol/L) artar."},{"t":"Çarpışma sıklığı","a":"artar","d":"Birim hacimde tanecik sayısı arttığından birim zamandaki çarpışma sayısı çoğalır."},{"t":"Sonuç","a":"hız artar","d":"Etkin çarpışma sayısı arttığından tepkime hızı yükselir."}],"ans":"Basınç artışı gaz hacmini küçültüp molar derişimi artırır; çarpışma kuramına göre çarpışma sıklığı artar ve etkin çarpışmalar çoğaldığından tepkime hızı yükselir."},{"q":"Sabit sıcaklıkta gaz için basınç ve hacim ilişkisini (Boyle) ve hıza yansımasını açıklayınız.","steps":[{"t":"Boyle yasası","a":"P·V = sabit","d":"Sabit sıcaklık ve mol sayısında basınç ile hacim ters orantılıdır (P·V sabit)."},{"t":"Hıza etkisi","a":"derişim üzerinden","d":"Basınç artınca hacim azalır, derişim (mol/V) artar; çarpışmalar sıklaştığı için hız artar."}],"ans":"Boyle yasasına göre sabit sıcaklıkta P·V sabittir; basınç artınca hacim küçülür, derişim ve çarpışma sıklığı artar, dolayısıyla gaz tepkimesinin hızı yükselir."},{"q":"Basınç etkisinin yalnızca gaz fazındaki tepkenler için belirgin olmasının nedeni nedir?","steps":[{"t":"Gazlar sıkışabilir","a":"hacim değişir","d":"Gaz tanecikleri arası boşluk büyük olduğundan basınçla hacimleri belirgin değişir, derişimleri değişir."},{"t":"Yoğun fazlar","a":"sıkışmaz","d":"Katı ve sıvılar pratikte sıkışmaz; basınçla hacim ve derişimleri değişmez, hız etkilenmez."}],"ans":"Gazlar sıkışabildiği için basınç hacmi ve derişimi değiştirip hızı etkiler; katı ve sıvılar pratikte sıkışmadığından basınç değişimi hızlarını belirgin etkilemez."},{"q":"Sabit hacimde asal gaz eklemek tepken gazların derişimini neden değiştirmez?","fig":"<svg viewBox='0 0 320 130'><rect x='90' y='25' width='140' height='80' fill='none' stroke='#1a2b45'/><circle cx='115' cy='50' r='6' fill='#e0552b'/><circle cx='150' cy='55' r='6' fill='#e0552b'/><circle cx='130' cy='85' r='6' fill='#e0552b'/><circle cx='185' cy='50' r='6' fill='#9ed9a8' stroke='#1a2b45'/><circle cx='205' cy='80' r='6' fill='#9ed9a8' stroke='#1a2b45'/><text x='160' y='123' font-size='10' text-anchor='middle' fill='#1a2b45'>asal gaz (yeşil) eklendi, V sabit</text></svg>","steps":[{"t":"Sabit hacim","a":"V değişmez","d":"Kabın hacmi sabit tutulduğundan tepken gazların kapladığı toplam hacim değişmez."},{"t":"Tepken derişimi","a":"sabit","d":"Tepken mol sayısı ve hacim sabit kaldığından derişimleri (mol/V) değişmez; toplam basınç artsa da hız sabit kalır."}],"ans":"Sabit hacimde asal gaz eklemek toplam basıncı artırır ama tepken gazların mol sayısı ve hacmi değişmediğinden derişimleri sabit kalır; bu yüzden çarpışma sıklığı ve hız değişmez."},{"q":"Hacmi sabit tutup basıncı artırmak için tepken gaz eklenirse hız neden artar?","steps":[{"t":"Tepken eklenir","a":"mol artar","d":"Sabit hacimde tepken gaz eklenince o gazın mol sayısı artar."},{"t":"Derişim ve hız","a":"artar","d":"Hacim sabit olduğundan tepken derişimi (mol/V) artar, çarpışmalar sıklaşır ve hız artar."}],"ans":"Sabit hacimde tepken gaz eklemek o gazın derişimini artırır; çarpışmalar sıklaştığı için tepkime hızı artar (asal gaz eklemekten farklı olarak)."}],"zor":[{"q":"2NO(g) + O₂(g) → 2NO₂(g) tepkimesinde toplam basınç iki katına çıkarılırsa (hacim yarıya) başlangıç hızı nasıl değişir? Hız = k·[NO]²·[O₂] kabul ediniz.","steps":[{"t":"Hacim yarıya","a":"derişimler 2 kat","d":"Hacim yarıya indiğinde tüm gaz tepkenlerin derişimi iki katına çıkar: [NO] → 2[NO], [O₂] → 2[O₂]."},{"t":"Hız denklemi","a":"k·(2[NO])²·(2[O₂])","d":"Yeni hız = k·(2[NO])²·(2[O₂]) = k·4[NO]²·2[O₂] = 8·k[NO]²[O₂]."},{"t":"Sonuç","a":"8 kat","d":"Yani başlangıç hızı 8 katına çıkar."}],"ans":"Hacim yarıya indiğinde [NO] ve [O₂] iki katına çıkar; hız = k·(2[NO])²·(2[O₂]) = 8·k[NO]²[O₂] olur, yani başlangıç hızı 8 katına çıkar."},{"q":"Toplam basıncı artırmanın iki farklı yolu (hacmi azaltmak ve sabit hacimde tepken eklemek) hıza neden farklı yansır?","steps":[{"t":"Hacmi azaltmak","a":"tüm derişimler artar","d":"Hacim küçültülünce kaptaki tüm gaz tepkenlerin derişimi birlikte artar, hız belirgin artar."},{"t":"Sabit hacimde asal gaz","a":"derişim sabit","d":"Asal gaz eklemek toplam basıncı artırır ama tepken derişimlerini değiştirmez, hız değişmez."},{"t":"Sonuç","a":"belirleyici derişim","d":"Hızı belirleyen toplam basınç değil, tepkenlerin derişimidir; bu yüzden iki yol farklı sonuç verir."}],"ans":"Hacmi azaltmak tüm tepken derişimlerini artırıp hızı yükseltir; sabit hacimde asal gaz eklemek ise tepken derişimini değiştirmediğinden hızı etkilemez. Hızı belirleyen toplam basınç değil tepken derişimidir."},{"q":"Hacmi üç katına çıkarılan bir gaz tepkimesinde hız = k·[A]² ise hız kaçta birine düşer?","fig":"<svg viewBox='0 0 320 130'><text x='160' y='35' font-size='13' text-anchor='middle' fill='#1a2b45'>V → 3V  ⇒  [A] → [A]/3</text><text x='160' y='70' font-size='13' text-anchor='middle' fill='#1a2b45'>hız = k·[A]²</text><text x='160' y='105' font-size='14' text-anchor='middle' fill='#1a2b45'>(1/3)² = 1/9 kat</text></svg>","steps":[{"t":"Hacim 3 kat","a":"derişim 1/3","d":"Hacim üç katına çıkınca tanecik sayısı sabit kaldığından [A] derişimi üçte birine düşer."},{"t":"Hız denklemi","a":"(1/3)²","d":"Hız [A]'ya göre ikinci dereceden olduğundan hız (1/3)² = 1/9 oranında değişir."}],"ans":"Hacim üç katına çıkınca [A] derişimi 1/3'üne düşer; hız [A]² ile orantılı olduğundan hız (1/3)² = 1/9 katına, yani dokuzda birine iner."},{"q":"Mol sayısı tepken tarafında daha fazla olan gaz tepkimelerinde basınç artışı dengeyi ürün yönüne kaydırırken, hıza etkisi nasıldır?","steps":[{"t":"Denge (Le Chatelier)","a":"az mollü yön","d":"Basınç artışı dengeyi gaz mol sayısının az olduğu yöne kaydırır; tepken tarafı çok mollüyse denge ürünlere kayar."},{"t":"Hıza etki","a":"hem ileri hem geri artar","d":"Basınç artışı tüm gaz derişimlerini artırdığından hem ileri hem geri tepkime hızı artar; tepkime daha çabuk dengeye ulaşır."},{"t":"Ayrım","a":"konum vs hız","d":"Denge konumu mol farkına göre kayarken, hız etkisi derişim artışıyla her iki yönde de hızlanmadır."}],"ans":"Basınç artışı dengeyi gaz molü az olan yöne kaydırır (denge konumu), aynı zamanda tüm gaz derişimlerini artırdığından hem ileri hem geri tepkime hızlanır ve sistem dengeye daha çabuk ulaşır."},{"q":"PV = nRT eşitliğinden yola çıkarak basınç artışının gaz derişimini nasıl artırdığını gösteriniz.","steps":[{"t":"İdeal gaz","a":"PV = nRT","d":"İdeal gaz denkleminde n/V terimi molar derişimi (C) verir."},{"t":"Derişim ifadesi","a":"C = n/V = P/(RT)","d":"Denklem düzenlenirse n/V = P/(RT) olur; sabit sıcaklıkta derişim basınçla doğru orantılıdır."},{"t":"Sonuç","a":"P artar → C artar","d":"Sabit T'de basınç artınca molar derişim artar, çarpışma sıklığı ve hız yükselir."}],"ans":"PV = nRT'den C = n/V = P/(RT) elde edilir; sabit sıcaklıkta molar derişim basınçla doğru orantılı olduğundan basınç artışı derişimi, dolayısıyla çarpışma sıklığını ve tepkime hızını artırır."}]}},"bayatlamaHiz":{"ilkokul":{"kolay":[{"q":"Sütü neden buzdolabında saklarız?","steps":[{"t":"Soğuk yavaşlatır","a":"buzdolabı","d":"Buzdolabı soğuk olduğu için sütün bozulmasını yavaşlatır."},{"t":"Daha uzun durur","a":"taze kalır","d":"Bu sayede süt daha uzun süre taze ve içilebilir kalır."}],"ans":"Buzdolabı soğuk olduğu için sütün bozulmasını yavaşlatır, süt daha uzun taze kalır."},{"q":"Ekmek açık havada mı yoksa poşet içinde mi daha çabuk bayatlar?","steps":[{"t":"Açık hava","a":"hızlı bayatlar","d":"Açıkta duran ekmek havayla temas eder ve daha çabuk bayatlar."},{"t":"Poşet içinde","a":"yavaş bayatlar","d":"Kapalı poşet havayı engeller, ekmek daha yavaş bayatlar."}],"ans":"Açık havada duran ekmek daha çabuk bayatlar; poşette daha yavaş bayatlar."},{"q":"Yazın sıcakta bırakılan dondurma neden hemen erir ve bozulur?","steps":[{"t":"Sıcaklık yüksek","a":"hızlanır","d":"Hava sıcak olunca her şey daha hızlı değişir, dondurma çabuk erir."},{"t":"Bozulma","a":"çabuk bozulur","d":"Eriyen ve sıcakta kalan dondurma çabucak bozulur."}],"ans":"Sıcak hava değişimi hızlandırdığı için dondurma hemen erir ve bozulur."},{"q":"Meyveleri taze tutmak için ne yapmamız iyi olur?","fig":"<svg viewBox='0 0 320 160'><rect x='40' y='30' width='100' height='100' rx='8' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='90' cy='80' r='16' fill='#e0552b' stroke='#1a2b45'/><text x='90' y='148' font-size='11' text-anchor='middle' fill='#1a2b45'>buzdolabi</text><rect x='190' y='30' width='100' height='100' rx='8' fill='#f5d7c0' stroke='#1a2b45'/><circle cx='240' cy='80' r='16' fill='#e0552b' stroke='#1a2b45'/><text x='240' y='148' font-size='11' text-anchor='middle' fill='#1a2b45'>sicak masa</text></svg>","steps":[{"t":"Soğukta sakla","a":"buzdolabı","d":"Meyveleri buzdolabında soğukta saklamak iyi olur."},{"t":"Yavaş bozulur","a":"taze kalır","d":"Soğuk bozulmayı yavaşlattığı için meyveler daha uzun taze kalır."}],"ans":"Meyveleri buzdolabında saklamak iyidir; soğuk bozulmayı yavaşlatır."},{"q":"Aynı elmadan biri masada, biri buzdolabında. Hangisi daha çabuk çürür?","steps":[{"t":"Masadaki","a":"sıcak","d":"Masadaki elma daha ılık ortamda durur."},{"t":"Sonuç","a":"çabuk çürür","d":"Sıcak yer bozulmayı hızlandırdığından masadaki elma daha çabuk çürür."}],"ans":"Masadaki (daha sıcak) elma buzdolabındakinden daha çabuk çürür."}],"zor":[{"q":"Annemiz yemeği neden hemen buzdolabına koyar, masada bırakmaz?","steps":[{"t":"Masada bekleme","a":"hızlı bozulur","d":"Ilık masada bekleyen yemek daha hızlı bozulur."},{"t":"Buzdolabı","a":"yavaşlatır","d":"Soğuk buzdolabı bozulmayı yavaşlattığı için yemek daha uzun süre dayanır."}],"ans":"Soğuk buzdolabı bozulmayı yavaşlattığı için yemek masada bırakılmaz, dolaba konur."},{"q":"Derin dondurucudaki et neden aylarca dayanırken buzdolabındaki birkaç günde bozulur?","steps":[{"t":"Çok soğuk","a":"dondurucu","d":"Derin dondurucu buzdolabından çok daha soğuktur."},{"t":"Daha yavaş","a":"uzun dayanır","d":"Daha soğuk ortam bozulmayı çok daha fazla yavaşlattığı için et aylarca dayanır."}],"ans":"Derin dondurucu çok daha soğuk olduğundan bozulmayı daha çok yavaşlatır, et aylarca dayanır."},{"q":"Bir bardak süt kışın balkonda, yazın aynı balkonda bırakılıyor. Hangisi daha çabuk bozulur?","steps":[{"t":"Sıcaklık farkı","a":"yaz sıcak","d":"Yazın balkon çok daha sıcaktır, kışın ise soğuktur."},{"t":"Sonuç","a":"yaz hızlı","d":"Sıcak ortam bozulmayı hızlandırdığından yazın bırakılan süt daha çabuk bozulur."}],"ans":"Yazın sıcak balkonda bırakılan süt, kışın soğukta bırakılandan daha çabuk bozulur."},{"q":"Konserve ve reçel neden uzun süre bozulmadan durur?","steps":[{"t":"Kapalı kavanoz","a":"hava giremez","d":"Konserve ve reçel ağzı kapalı kavanozda saklanır, hava giremez."},{"t":"Yavaş bozulma","a":"uzun dayanır","d":"Hava ve mikroplar giremediği için bozulma çok yavaşlar, uzun süre dayanır."}],"ans":"Ağzı kapalı kavanozda hava giremediği için bozulma yavaşlar, konserve ve reçel uzun dayanır."},{"q":"Piknikte yiyecekleri buzlukta (soğutucu çantada) taşımamız neden mantıklıdır?","steps":[{"t":"Sıcak hava","a":"bozar","d":"Piknikte hava sıcaktır, yiyecekler çabuk bozulabilir."},{"t":"Soğutucu çanta","a":"yavaşlatır","d":"Buzluk içini soğuk tutar, soğuk bozulmayı yavaşlatır."}],"ans":"Buzluk içini soğuk tuttuğu için bozulmayı yavaşlatır, yiyecekler piknikte daha uzun dayanır."}]},"ortaokul":{"kolay":[{"q":"Sıcaklık arttıkça gıdaların bozulma (tepkime) hızı nasıl değişir?","steps":[{"t":"Kural","a":"hız artar","d":"Sıcaklık arttıkça taneciklerin hareketi hızlanır, bozulma tepkimeleri hızlanır."},{"t":"Sonuç","a":"çabuk bozulur","d":"Bu yüzden sıcakta gıdalar daha çabuk bozulur, bayatlar."}],"ans":"Sıcaklık arttıkça bozulma hızı artar; gıdalar sıcakta daha çabuk bozulur."},{"q":"Buzdolabı yiyecekleri nasıl daha uzun süre korur?","steps":[{"t":"Düşük sıcaklık","a":"yavaşlatır","d":"Buzdolabı sıcaklığı düşürür, böylece bozulma tepkimeleri yavaşlar."},{"t":"Mikroplar","a":"yavaş ürer","d":"Soğukta mikroorganizmalar da yavaş çoğaldığı için gıda uzun korunur."}],"ans":"Buzdolabı sıcaklığı düşürerek bozulma tepkimelerini ve mikrop üremesini yavaşlatır."},{"q":"Açık havada bekleyen yiyecek neden buzdolabındakinden hızlı bozulur?","steps":[{"t":"Oda sıcaklığı","a":"daha sıcak","d":"Açık hava (oda) sıcaklığı buzdolabından yüksektir."},{"t":"Hız","a":"daha hızlı","d":"Yüksek sıcaklıkta bozulma tepkimeleri daha hızlı olur."}],"ans":"Açık havadaki sıcaklık daha yüksek olduğu için bozulma tepkimesi hızlanır."},{"q":"Gıda saklamada hangi yöntemler bozulmayı yavaşlatır?","fig":"<svg viewBox='0 0 320 150'><rect x='20' y='40' width='80' height='70' rx='6' fill='#cfd8e8' stroke='#1a2b45'/><text x='60' y='128' font-size='10' text-anchor='middle' fill='#1a2b45'>soğutma</text><rect x='120' y='40' width='80' height='70' rx='6' fill='#cfd8e8' stroke='#1a2b45'/><text x='160' y='128' font-size='10' text-anchor='middle' fill='#1a2b45'>kurutma</text><rect x='220' y='40' width='80' height='70' rx='6' fill='#cfd8e8' stroke='#1a2b45'/><text x='260' y='128' font-size='10' text-anchor='middle' fill='#1a2b45'>tuzlama</text></svg>","steps":[{"t":"Yöntemler","a":"soğutma, kurutma, tuzlama","d":"Soğutma, kurutma, tuzlama, salamura ve konserve bozulmayı yavaşlatır."},{"t":"Ortak amaç","a":"tepkimeyi yavaşlatma","d":"Hepsi sıcaklığı, suyu veya havayı azaltarak bozulma hızını düşürür."}],"ans":"Soğutma, kurutma, tuzlama ve konserve gibi yöntemler bozulma hızını düşürerek gıdayı korur."},{"q":"Donmuş gıda neden çok uzun süre dayanır?","steps":[{"t":"Çok düşük sıcaklık","a":"donma","d":"Donmada sıcaklık çok düşüktür, tanecik hareketi neredeyse durur."},{"t":"Bozulma","a":"çok yavaş","d":"Bu yüzden bozulma tepkimeleri çok yavaşlar, gıda aylarca dayanır."}],"ans":"Çok düşük sıcaklıkta bozulma tepkimeleri çok yavaşladığı için donmuş gıda uzun dayanır."}],"zor":[{"q":"Sıcaklığın artması bozulma tepkimesini neden hızlandırır? Tanecik düzeyinde açıkla.","fig":"<svg viewBox='0 0 320 150'><text x='75' y='25' font-size='10' text-anchor='middle' fill='#1a2b45'>soguk: yavas</text><circle cx='50' cy='70' r='8' fill='#2b6be0'/><circle cx='90' cy='90' r='8' fill='#2b6be0'/><circle cx='70' cy='110' r='8' fill='#2b6be0'/><text x='245' y='25' font-size='10' text-anchor='middle' fill='#1a2b45'>sicak: hizli</text><circle cx='210' cy='60' r='8' fill='#e0552b'/><circle cx='260' cy='80' r='8' fill='#e0552b'/><circle cx='230' cy='110' r='8' fill='#e0552b'/><line x1='210' y1='60' x2='240' y2='95' stroke='#1a2b45'/><line x1='260' y1='80' x2='232' y2='105' stroke='#1a2b45'/></svg>","steps":[{"t":"Tanecik hareketi","a":"hızlanır","d":"Sıcaklık artınca tanecikler daha hızlı hareket eder, daha sık çarpışır."},{"t":"Etkili çarpışma","a":"artar","d":"Daha hızlı ve enerjik çarpışmalar bozulma tepkimesini hızlandırır."}],"ans":"Sıcaklık taneciklerin hızını ve çarpışma sıklığını artırdığı için bozulma tepkimesi hızlanır."},{"q":"Bir yiyecek oda sıcaklığında 2 günde, buzdolabında 10 günde bozuluyorsa bu fark neyi gösterir?","fig":"<svg viewBox='0 0 320 150'><text x='160' y='25' font-size='10' text-anchor='middle' fill='#1a2b45'>bozulma suresi (gun)</text><rect x='60' y='85' width='40' height='30' fill='#e0552b'/><text x='80' y='135' font-size='10' text-anchor='middle' fill='#1a2b45'>oda: 2</text><rect x='200' y='35' width='40' height='80' fill='#2b6be0'/><text x='220' y='135' font-size='10' text-anchor='middle' fill='#1a2b45'>dolap: 10</text></svg>","steps":[{"t":"Karşılaştırma","a":"5 kat","d":"Buzdolabında bozulma süresi 5 kat uzamıştır."},{"t":"Yorum","a":"hız düşmüş","d":"Düşük sıcaklık bozulma hızını yaklaşık 5 kat azaltmıştır."}],"ans":"Soğuk ortam bozulma süresini 5 kat uzatmış, yani bozulma hızını yaklaşık 5 kat azaltmıştır."},{"q":"Pastörizasyonda süt neden kısa süre ısıtılıp sonra hızla soğutulur?","steps":[{"t":"Isıtma","a":"mikrop öldürür","d":"Kısa süreli ısıtma sütteki zararlı mikroorganizmaları öldürür."},{"t":"Hızlı soğutma","a":"yavaş bozulur","d":"Sonra hızla soğutmak kalan bozulmayı yavaşlatır, süt uzun dayanır."}],"ans":"Isıtma mikropları öldürür, ardından hızlı soğutma bozulma hızını düşürdüğü için süt uzun dayanır."},{"q":"Kurutulmuş meyve (kuru kayısı, kuru üzüm) neden taze hâline göre çok daha uzun dayanır?","steps":[{"t":"Su azaltma","a":"kurutma","d":"Kurutmada meyvedeki su uzaklaştırılır."},{"t":"Bozulma","a":"yavaşlar","d":"Su olmadan mikroplar üreyemez ve bozulma tepkimeleri çok yavaşlar."}],"ans":"Kurutma suyu uzaklaştırdığı için mikrop üremesi ve bozulma yavaşlar, kuru meyve uzun dayanır."},{"q":"Vakumlu (havasız) paketleme bozulmayı nasıl yavaşlatır?","fig":"<svg viewBox='0 0 320 150'><rect x='40' y='40' width='90' height='70' rx='6' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='60' cy='60' r='4' fill='#5b6b85'/><circle cx='100' cy='80' r='4' fill='#5b6b85'/><circle cx='80' cy='95' r='4' fill='#5b6b85'/><text x='85' y='128' font-size='10' text-anchor='middle' fill='#1a2b45'>havali</text><rect x='190' y='55' width='90' height='40' rx='6' fill='#cfd8e8' stroke='#1a2b45'/><text x='235' y='128' font-size='10' text-anchor='middle' fill='#1a2b45'>vakum (O₂ yok)</text></svg>","steps":[{"t":"Hava çekilir","a":"oksijen yok","d":"Vakumlamada paketteki hava, özellikle oksijen alınır."},{"t":"Yavaşlama","a":"yükseltgenme azalır","d":"Oksijen olmayınca yükseltgenme (acılaşma) ve oksijen seven mikroplar azalır, bozulma yavaşlar."}],"ans":"Vakum oksijeni uzaklaştırdığı için yükseltgenme ve mikrop üremesi azalır, bozulma yavaşlar."}]},"lise":{"kolay":[{"q":"Tepkime hızını etkileyen başlıca faktörler nelerdir?","steps":[{"t":"Faktörler","a":"sıcaklık, derişim, yüzey, katalizör","d":"Sıcaklık, derişim, temas yüzeyi, katalizör ve ortam (su, oksijen) tepkime hızını etkiler."},{"t":"Gıda örneği","a":"bozulma","d":"Gıda bozulması da bir tepkimedir; aynı faktörler hızını belirler."}],"ans":"Tepkime hızını sıcaklık, derişim, temas yüzeyi ve katalizör etkiler; gıda bozulması da buna uyar."},{"q":"Sıcaklığın tepkime hızına etkisi neden bu kadar belirgindir?","steps":[{"t":"Aktivasyon enerjisi","a":"eşik","d":"Tepkimenin olması için taneciklerin aktivasyon enerjisini aşması gerekir."},{"t":"Sıcaklık","a":"enerjili tanecik artar","d":"Sıcaklık artınca eşiği aşacak enerjili tanecik sayısı hızla artar."}],"ans":"Sıcaklık arttıkça aktivasyon enerjisini aşan tanecik oranı hızla arttığı için tepkime belirgin hızlanır."},{"q":"Bir kuralla, sıcaklık 10 °C arttığında tepkime hızı kabaca nasıl değişir?","steps":[{"t":"Yaklaşık kural","a":"2 kat","d":"Birçok tepkimede sıcaklık 10 °C artınca hız kabaca 2 katına çıkar."},{"t":"Yorum","a":"hızlı bozulma","d":"Bu yüzden ılık ortam bozulmayı belirgin hızlandırır."}],"ans":"Genel bir yaklaşımla sıcaklık 10 °C artınca tepkime hızı kabaca iki katına çıkar."},{"q":"Buzdolabı sıcaklığı (4 °C) ile oda sıcaklığı (24 °C) arasında bozulma hızı kabaca kaç kat değişir?","fig":"<svg viewBox='0 0 320 150'><line x1='40' y1='115' x2='290' y2='115' stroke='#1a2b45' stroke-width='2'/><rect x='70' y='95' width='30' height='20' fill='#2b6be0'/><text x='85' y='135' font-size='10' text-anchor='middle' fill='#1a2b45'>4°C ×1</text><rect x='210' y='35' width='30' height='80' fill='#e0552b'/><text x='225' y='135' font-size='10' text-anchor='middle' fill='#1a2b45'>24°C ×4</text><text x='160' y='25' font-size='10' text-anchor='middle' fill='#1a2b45'>bozulma hizi</text></svg>","steps":[{"t":"Fark","a":"20 °C","d":"İki sıcaklık arasındaki fark 24 − 4 = 20 °C'dir."},{"t":"Yaklaşım","a":"2² = 4 kat","d":"Her 10 °C için 2 kat alınırsa 20 °C için 2×2 = 4 kat hız değişir."}],"ans":"Yaklaşık 20 °C fark için bozulma hızı kabaca 4 kat değişir; oda sıcaklığında çok daha hızlı bozulur."},{"q":"Oksijenin gıda bozulmasındaki (acılaşma) rolü nedir?","steps":[{"t":"Yükseltgenme","a":"O₂ tepkir","d":"Yağlar oksijenle tepkiyerek yükseltgenir ve acılaşır."},{"t":"Engelleme","a":"vakum/antioksidan","d":"Oksijeni azaltmak (vakum) veya antioksidan eklemek bu tepkimeyi yavaşlatır."}],"ans":"Oksijen yağların yükseltgenmesini (acılaşma) sağlar; vakum ve antioksidanlar bu bozulmayı yavaşlatır."}],"zor":[{"q":"Bir gıda 25 °C'de 4 günde bozuluyor. Her 10 °C düşüşte hız yarıya iniyorsa 5 °C'de kaç günde bozulur?","fig":"<svg viewBox='0 0 320 150'><line x1='40' y1='120' x2='290' y2='120' stroke='#1a2b45' stroke-width='2'/><line x1='40' y1='120' x2='40' y2='20' stroke='#1a2b45' stroke-width='2'/><text x='60' y='135' font-size='10' fill='#1a2b45'>5°C</text><text x='250' y='135' font-size='10' fill='#1a2b45'>25°C</text><circle cx='70' cy='100' r='5' fill='#2b6be0'/><circle cx='260' cy='40' r='5' fill='#e0552b'/><text x='160' y='18' font-size='10' text-anchor='middle' fill='#1a2b45'>hiz: sicaklikla artar</text></svg>","steps":[{"t":"Sıcaklık farkı","a":"20 °C","d":"25 − 5 = 20 °C düşüş, yani iki kez 10 °C düşüş vardır."},{"t":"Hız çarpanı","a":"1/4","d":"Her 10 °C'de hız yarıya inerse 20 °C'de hız (1/2)×(1/2) = 1/4 olur."},{"t":"Süre","a":"4×4 = 16 gün","d":"Hız 1/4'e düşünce bozulma süresi 4 katına çıkar: 4×4 = 16 gün."}],"ans":"5 °C'de gıda yaklaşık 16 günde bozulur (hız 1/4'e iner, süre 4 katına çıkar)."},{"q":"Oda sıcaklığında 1 günde bozulan et −18 °C'de aylarca dayanıyor. Bu büyük farkı kinetik olarak açıklayın.","steps":[{"t":"Büyük sıcaklık düşüşü","a":"çok az enerjili tanecik","d":"−18 °C'de eşik enerjisini aşan tanecik sayısı çok azdır."},{"t":"Hız sabiti","a":"çok küçük","d":"Hız sabiti üstel olarak çok küçüldüğünden enzim ve mikrop tepkimeleri neredeyse durur."},{"t":"Sonuç","a":"aylarca","d":"Bu yüzden bozulma çok yavaşlar ve et aylarca dayanır."}],"ans":"Çok düşük sıcaklık eşiği aşan tanecik oranını üstel olarak azaltıp hız sabitini çok küçülttüğü için bozulma neredeyse durur ve et aylarca dayanır."},{"q":"Aktivasyon enerjisi büyük olan bir bozulma tepkimesi, sıcaklık değişimine neden daha duyarlıdır?","steps":[{"t":"Üstel bağ","a":"e^(−Ea/RT)","d":"Hız sabiti, aktivasyon enerjisi ile e^(−Ea/RT) çarpanına bağlıdır."},{"t":"Büyük Ea","a":"keskin değişim","d":"Ea büyükse sıcaklıktaki küçük değişim bu çarpanı çok değiştirir."},{"t":"Sonuç","a":"duyarlı","d":"Bu yüzden büyük Ea'lı tepkimenin hızı sıcaklığa daha duyarlıdır."}],"ans":"Hız sabiti e^(−Ea/RT) ile orantılı olduğundan büyük aktivasyon enerjili tepkimeler sıcaklık değişimine daha duyarlıdır."},{"q":"Soğutma bozulmayı yavaşlatır ama tepkimenin dengesini (ürün miktarını) değiştirir mi? Açıklayın.","steps":[{"t":"Hız vs denge","a":"farklı","d":"Sıcaklık hem hızı hem dengeyi etkiler ama bunlar farklı kavramlardır."},{"t":"Hız","a":"yavaşlar","d":"Soğutma bozulma hızını (ne kadar çabuk) belirgin düşürür."},{"t":"Pratik sonuç","a":"süre uzar","d":"Gıda saklamada amaç hızı düşürmektir; bozulma yine olur ama çok yavaş gerçekleşir."}],"ans":"Soğutma asıl olarak bozulma hızını düşürür; bozulma tümden durmaz, sadece çok yavaşladığı için gıda uzun süre korunur."},{"q":"Bir konserve neden hem ısıl işlem hem de hava boşaltma ile korunur; iki yöntemin tepkime hızına etkisini birlikte değerlendirin.","steps":[{"t":"Isıl işlem","a":"mikrop öldürür","d":"Yüksek sıcaklıkta sterilizasyon mevcut mikropları ve sporları öldürür."},{"t":"Hava boşaltma","a":"oksijen yok","d":"Havası alınınca oksijenli bozulma (yükseltgenme) ve oksijen seven mikrop üremesi durur."},{"t":"Birlikte","a":"çok düşük hız","d":"İki etki birleşince bozulma tepkimelerinin hızı neredeyse sıfıra iner, konserve yıllarca dayanır."}],"ans":"Isıl işlem mikropları öldürür, hava boşaltma oksijenli bozulmayı durdurur; birlikte bozulma hızını neredeyse sıfıra indirip konserveyi yıllarca korur."}]}},"carpismaTeorisi":{"ilkokul":{"kolay":[{"q":"İki oyuncak araba çarpışmazsa birbirini değiştirebilir mi?","steps":[{"t":"Değmek gerekir","a":"çarpışma","d":"İki şeyin birbirini etkilemesi için önce birbirine değmesi, yani <b>çarpışması</b> gerekir."},{"t":"Tepkimede de öyle","a":"tanecikler","d":"Maddeler de ancak küçük tanecikleri birbirine çarptığında değişip yeni madde oluşturur."}],"ans":"Hayır; tanecikler önce birbirine <b>çarpmalıdır</b>."},{"q":"Bir tepkimenin olması için maddelerin küçük taneciklerinin ne yapması gerekir?","fig":"<svg viewBox='0 0 220 90'><rect x='0' y='0' width='220' height='90' fill='#f5f7fa'/><circle cx='60' cy='45' r='15' fill='#2b6be0'/><circle cx='150' cy='45' r='15' fill='#e0552b'/><path d='M80 45 L110 45' stroke='#1a2b45' stroke-width='3'/><path d='M104 39 L112 45 L104 51' fill='none' stroke='#1a2b45' stroke-width='3'/><path d='M130 45 L100 45' stroke='#1a2b45' stroke-width='3'/><path d='M106 39 L98 45 L106 51' fill='none' stroke='#1a2b45' stroke-width='3'/></svg>","steps":[{"t":"Küçük tanecikler","a":"hareketli","d":"Her madde sürekli hareket eden çok küçük taneciklerden oluşur."},{"t":"Buluşma","a":"çarpışır","d":"Bu tanecikler birbirine <b>çarptığında</b> tepkime başlayabilir."}],"ans":"Taneciklerin birbirine <b>çarpması</b> gerekir."},{"q":"Bilye dolu iki kutuyu salladığımızda bilyeler birbirine çarpar. Bu, tepkimedeki neye benzer?","steps":[{"t":"Sallamak","a":"hareket","d":"Sallayınca bilyeler hareket eder ve birbirine çarpar."},{"t":"Benzetme","a":"taneciklerin çarpışması","d":"Maddedeki tanecikler de hareket edip <b>çarpışır</b>, tıpkı bilyeler gibi."}],"ans":"Taneciklerin <b>çarpışmasına</b> benzer."},{"q":"Her çarpışma yeni bir madde oluşturur mu?","steps":[{"t":"Çarpışma çok","a":"hepsi olmaz","d":"Tanecikler çok kez çarpışır ama hepsi yeni madde oluşturmaz."},{"t":"Bazıları işe yarar","a":"sadece bazıları","d":"Sadece <b>bazı</b> çarpışmalar tepkimeyle sonuçlanır."}],"ans":"Hayır; sadece <b>bazı</b> çarpışmalar işe yarar."},{"q":"Hareket etmeyen, hiç titremeyen tanecikler birbirine çarpabilir mi?","steps":[{"t":"Hareket şart","a":"çarpmak için","d":"Bir şeyin başka şeye çarpması için <b>hareket etmesi</b> gerekir."},{"t":"Durgunsa","a":"çarpışmaz","d":"Hiç hareket etmeyen tanecikler birbirine çarpamaz, tepkime olmaz."}],"ans":"Hayır; çarpışmak için <b>hareket</b> gerekir."}],"zor":[{"q":"İki yumuşak top yavaşça birbirine değse yapışmaz ama hızla çarparsa yapışabilir. Bu, taneciklerde neyi anlatır?","steps":[{"t":"Yavaş dokunuş","a":"yetersiz","d":"Yavaş ve nazik dokunuş çoğu zaman bir değişiklik yaratmaz."},{"t":"Hızlı çarpışma","a":"güçlü","d":"Hızlı, güçlü çarpışma ise topların yapışmasına yol açabilir."},{"t":"Taneciklerde","a":"güçlü çarpışma","d":"Tanecikler de ancak yeterince <b>güçlü</b> çarpıştığında yeni madde oluşturur."}],"ans":"Tepkime için çarpışmanın <b>güçlü</b> olması gerekir."},{"q":"İki anahtarı kilide rastgele dokundurmak yerine doğru yönde sokmak gerekir. Bu durum çarpışmada neye benzer?","fig":"<svg viewBox='0 0 220 90'><rect x='0' y='0' width='220' height='90' fill='#f5f7fa'/><circle cx='40' cy='45' r='14' fill='#2b6be0'/><circle cx='100' cy='45' r='14' fill='#e0552b'/><path d='M58 45 L84 45' stroke='#1a2b45' stroke-width='3'/><path d='M78 39 L86 45 L78 51' fill='none' stroke='#1a2b45' stroke-width='3'/><text x='150' y='40' fill='#1a2b45' font-size='12'>uygun</text><text x='150' y='56' fill='#1a2b45' font-size='12'>yön</text></svg>","steps":[{"t":"Anahtar yönü","a":"doğru olmalı","d":"Anahtar ancak doğru yönde girerse kilidi açar."},{"t":"Tanecik çarpışması","a":"uygun yön","d":"Tanecikler de <b>uygun yönden</b> çarpışırsa tepkime olur."},{"t":"Sonuç","a":"yön önemli","d":"Yanlış yönden çarparlarsa tepkime gerçekleşmez."}],"ans":"Çarpışmanın <b>uygun yönden</b> olması gerekir."},{"q":"Bir tepkimede tanecikler hem yeterince hızlı hem de doğru yönden çarparsa ne olur?","steps":[{"t":"Hızlı çarpışma","a":"yeterli güç","d":"Yeterince hızlı çarpışma tepkimeyi başlatacak gücü sağlar."},{"t":"Doğru yön","a":"uygun yönelim","d":"Doğru yönden çarpışma da taneciklerin doğru yerden birleşmesini sağlar."},{"t":"İkisi birden","a":"yeni madde","d":"Bu iki şart birlikte sağlanırsa <b>yeni madde</b> oluşur."}],"ans":"İkisi birden olunca <b>yeni madde</b> oluşur."},{"q":"Çok kalabalık bir odada insanlar birbirine sık çarpar. Tanecik sayısı çok olunca tepkime hızı için ne söylenir?","steps":[{"t":"Kalabalık oda","a":"sık çarpışma","d":"Ortamda ne kadar çok kişi varsa o kadar sık çarpışma olur."},{"t":"Tanecikte","a":"daha çok çarpışma","d":"Tanecik sayısı arttıkça çarpışma sayısı da <b>artar</b>."},{"t":"Sonuç","a":"daha hızlı","d":"Daha çok çarpışma genelde tepkimeyi daha <b>hızlı</b> yapar."}],"ans":"Tanecik çoksa çarpışma artar, tepkime <b>hızlanır</b>."},{"q":"Bir çarpışmanın işe yaraması için neden hem hız hem de yön gerekir?","steps":[{"t":"Sadece hız","a":"yetmez","d":"Hızlı ama yanlış yönden çarpan tanecikler birleşemez."},{"t":"Sadece yön","a":"yetmez","d":"Doğru yönden ama çok yavaş çarpan tanecikler de tepkime yapamaz."},{"t":"İkisi gerekli","a":"hız + yön","d":"İşe yarayan çarpışma için <b>hem yeterli hız hem uygun yön</b> birlikte gerekir."}],"ans":"Hem <b>yeterli hız</b> hem <b>uygun yön</b> gerekir."}]},"ortaokul":{"kolay":[{"q":"Çarpışma teorisine göre bir kimyasal tepkimenin gerçekleşmesi için ilk şart nedir?","steps":[{"t":"Tepkime şartı","a":"çarpışma","d":"Tepkimeye girecek tanecikler önce birbirleriyle <b>çarpışmalıdır</b>."},{"t":"Neden","a":"temas","d":"Çarpışma olmadan tanecikler etkileşip yeni bağ kuramaz."}],"ans":"Taneciklerin birbiriyle <b>çarpışması</b> gerekir."},{"q":"Her tanecik çarpışması bir tepkimeyle sonuçlanır mı? Açıklayın.","steps":[{"t":"Çarpışma sayısı","a":"çok fazla","d":"Bir ortamda saniyede sayısız çarpışma olur."},{"t":"Sonuç","a":"hepsi değil","d":"Bunların yalnızca <b>etkin</b> olanları tepkimeyle sonuçlanır."}],"ans":"Hayır; sadece <b>etkin çarpışmalar</b> tepkime yapar."},{"q":"Tepkime ile sonuçlanan çarpışmaya ne ad verilir?","steps":[{"t":"İşe yarayan çarpışma","a":"etkin","d":"Tepkime oluşturan çarpışmalara <b>etkin çarpışma</b> denir."},{"t":"Diğerleri","a":"etkisiz","d":"Tepkimeye yol açmayan çarpışmalar etkisizdir."}],"ans":"Buna <b>etkin çarpışma</b> denir."},{"q":"Tanecik sayısı (derişim) artınca çarpışma sayısı nasıl değişir?","steps":[{"t":"Daha çok tanecik","a":"daha sık temas","d":"Birim hacimde tanecik çoğalınca taneciklerin birbirini bulma olasılığı artar."},{"t":"Sonuç","a":"çarpışma artar","d":"Bu nedenle çarpışma sayısı <b>artar</b> ve tepkime hızlanır."}],"ans":"Çarpışma sayısı <b>artar</b>."},{"q":"Katı bir maddeyi toz hâline getirmek tepkime hızını neden artırır?","fig":"<svg viewBox='0 0 220 90'><rect x='0' y='0' width='220' height='90' fill='#f5f7fa'/><rect x='25' y='30' width='40' height='40' fill='#5b6b85' stroke='#1a2b45'/><text x='30' y='85' fill='#1a2b45' font-size='10'>blok</text><rect x='140' y='35' width='10' height='10' fill='#5b6b85'/><rect x='155' y='50' width='10' height='10' fill='#5b6b85'/><rect x='170' y='32' width='10' height='10' fill='#5b6b85'/><rect x='150' y='30' width='10' height='10' fill='#5b6b85'/><rect x='168' y='52' width='10' height='10' fill='#5b6b85'/><text x='140' y='85' fill='#1a2b45' font-size='10'>toz</text></svg>","steps":[{"t":"Toz hâli","a":"daha çok yüzey","d":"Toz hâlinde maddenin <b>temas yüzeyi</b> çok artar."},{"t":"Çarpışma","a":"daha çok","d":"Daha geniş yüzeyde daha çok çarpışma olur, tepkime hızlanır."}],"ans":"Temas yüzeyi artar, <b>çarpışma</b> çoğalır."}],"zor":[{"q":"Etkin çarpışma için gereken iki temel koşul nedir?","steps":[{"t":"Birinci koşul","a":"yeterli enerji","d":"Çarpışan tanecikler eski bağları kıracak <b>yeterli enerjiye</b> sahip olmalıdır."},{"t":"İkinci koşul","a":"uygun yönelim","d":"Tanecikler tepkimeye uygun <b>doğru yönden</b> çarpışmalıdır."},{"t":"İkisi birden","a":"etkin","d":"Her iki koşul sağlanınca çarpışma etkin olur."}],"ans":"<b>Yeterli enerji</b> ve <b>uygun yönelim</b>."},{"q":"İki tanecik yüksek enerjiyle ama yanlış yönden çarpışırsa ne olur?","fig":"<svg viewBox='0 0 230 90'><rect x='0' y='0' width='230' height='90' fill='#f5f7fa'/><circle cx='40' cy='30' r='13' fill='#2b6be0'/><circle cx='70' cy='60' r='13' fill='#e0552b'/><path d='M52 38 L62 52' stroke='#1a2b45' stroke-width='3'/><text x='110' y='40' fill='#1a2b45' font-size='12'>yanlış</text><text x='110' y='58' fill='#1a2b45' font-size='12'>yön → etkisiz</text></svg>","steps":[{"t":"Enerji yeterli","a":"var","d":"Çarpışmada bağları kıracak enerji bulunsa bile tek başına yetmez."},{"t":"Yön yanlış","a":"etkisiz","d":"Yönelim uygun değilse tanecikler doğru biçimde birleşemez."},{"t":"Sonuç","a":"tepkime yok","d":"Bu çarpışma <b>etkisizdir</b>, tepkime gerçekleşmez."}],"ans":"Çarpışma <b>etkisiz</b> olur, tepkime olmaz."},{"q":"Sıcaklık artınca etkin çarpışma sayısı neden artar?","steps":[{"t":"Sıcaklık","a":"daha hızlı tanecik","d":"Sıcaklık artınca tanecikler daha hızlı hareket eder."},{"t":"Etki","a":"hem sık hem enerjik","d":"Çarpışmalar hem daha <b>sık</b> hem daha <b>yüksek enerjili</b> olur."},{"t":"Sonuç","a":"etkin çarpışma artar","d":"Bu yüzden etkin çarpışma sayısı artar, tepkime hızlanır."}],"ans":"Çarpışmalar sıklaşır ve enerjilenir, <b>etkin çarpışma artar</b>."},{"q":"Katalizör eklemek etkin çarpışmaları nasıl etkiler?","steps":[{"t":"Katalizör","a":"yeni yol","d":"Katalizör, tepkimeye daha kolay bir yol açar."},{"t":"Eşik enerji","a":"düşer","d":"Gereken eşik enerji azalınca daha çok tanecik bu eşiği aşabilir."},{"t":"Sonuç","a":"etkin çarpışma artar","d":"Böylece <b>etkin çarpışma oranı</b> artar ve tepkime hızlanır."}],"ans":"Eşik enerjiyi düşürür, <b>etkin çarpışmaları artırır</b>."},{"q":"Çarpışma sayısı çok arttığı hâlde tepkime hızının az değişmesinin nedeni ne olabilir?","steps":[{"t":"Çok çarpışma","a":"ama çoğu etkisiz","d":"Çarpışmaların büyük kısmı yeterli enerji ya da uygun yönelimden yoksundur."},{"t":"Etkin oran","a":"düşük","d":"Yalnızca etkin çarpışmalar tepkimeye katkı verir."},{"t":"Sonuç","a":"az artış","d":"Etkin çarpışma oranı düşükse hız az değişir."}],"ans":"Çarpışmaların çoğu <b>etkisiz</b> olduğu için."}]},"lise":{"kolay":[{"q":"Çarpışma teorisinin temel varsayımı nedir?","steps":[{"t":"Temel ilke","a":"çarpışma şart","d":"Tepkimeye giren tanecikler ürün oluşturmak için birbiriyle <b>çarpışmalıdır</b>."},{"t":"Etkin çarpışma","a":"enerji + yön","d":"Çarpışmanın tepkimeyle sonuçlanması için yeterli enerji ve uygun yönelim gerekir."}],"ans":"Tanecikler <b>etkin çarpışma</b> yapmalıdır."},{"q":"Etkin çarpışma ile etkisiz çarpışma arasındaki fark nedir?","steps":[{"t":"Etkin çarpışma","a":"tepkime olur","d":"Yeterli enerji ve uygun yönelimle gerçekleşir, ürün oluşur."},{"t":"Etkisiz çarpışma","a":"tepkime olmaz","d":"Enerji yetersiz veya yönelim uygunsuzdur; tanecikler değişmeden ayrılır."}],"ans":"Etkin çarpışma <b>ürün oluşturur</b>, etkisiz oluşturmaz."},{"q":"Derişim artışı tepkime hızını çarpışma teorisiyle nasıl açıklanır?","fig":"<svg viewBox='0 0 220 90'><rect x='0' y='0' width='220' height='90' fill='#f5f7fa'/><circle cx='30' cy='30' r='7' fill='#2b6be0'/><circle cx='60' cy='60' r='7' fill='#e0552b'/><circle cx='150' cy='25' r='7' fill='#2b6be0'/><circle cx='170' cy='45' r='7' fill='#e0552b'/><circle cx='150' cy='65' r='7' fill='#2b6be0'/><circle cx='185' cy='65' r='7' fill='#e0552b'/><text x='20' y='80' fill='#1a2b45' font-size='11'>seyrek</text><text x='150' y='82' fill='#1a2b45' font-size='11'>derişik</text></svg>","steps":[{"t":"Derişim ↑","a":"birim hacimde tanecik ↑","d":"Derişim artınca birim hacimdeki tanecik sayısı artar."},{"t":"Çarpışma sıklığı","a":"artar","d":"Tanecikler daha sık çarpışır, etkin çarpışma sayısı da artar."}],"ans":"Çarpışma sıklığı artar, hız <b>yükselir</b>."},{"q":"Gaz tepkimelerinde basıncın artırılması hızı neden etkiler?","steps":[{"t":"Basınç ↑","a":"hacim ↓","d":"Sabit sıcaklıkta basınç artınca gazın hacmi azalır."},{"t":"Derişim ↑","a":"çarpışma ↑","d":"Birim hacimdeki tanecik artar, çarpışma sıklığı yükselir, hız artar."}],"ans":"Derişim artar, <b>çarpışma sıklığı</b> yükselir."},{"q":"Temas yüzeyinin tepkime hızına etkisi çarpışma teorisiyle nasıl açıklanır?","steps":[{"t":"Yüzey ↑","a":"daha çok temas noktası","d":"Katı parçalanıp toz yapılınca yüzey alanı çok artar."},{"t":"Çarpışma","a":"artar","d":"Daha fazla tanecik temas eder, çarpışma ve hız artar."}],"ans":"Temas yüzeyi artınca <b>çarpışma</b> ve hız artar."}],"zor":[{"q":"Çarpışma teorisinde 'yönelim faktörü' (sterik faktör) neyi ifade eder?","steps":[{"t":"Yönelim faktörü","a":"olasılık","d":"Bir çarpışmanın geometrik olarak <b>uygun yönden</b> olma olasılığını ifade eder."},{"t":"Etki","a":"hızı düşürür","d":"Karmaşık moleküllerde uygun yönelim olasılığı düşük olduğundan hesaplanan hız azalır."},{"t":"Sonuç","a":"yön kritik","d":"Yeterli enerji olsa bile uygun yönelim sağlanmazsa çarpışma etkisiz kalır."}],"ans":"Çarpışmanın <b>uygun yönden</b> olma olasılığını ifade eder."},{"q":"N₂ + 3H₂ ⇌ 2NH₃ tepkimesinde H₂ derişimi iki katına çıkarılırsa çarpışma sayısı niceliksel olarak nasıl değişir, açıklayın.","fig":"<svg viewBox='0 0 240 90'><rect x='0' y='0' width='240' height='90' fill='#f5f7fa'/><circle cx='40' cy='45' r='14' fill='#5b6b85'/><text x='34' y='49' fill='#f5f7fa' font-size='12'>N₂</text><circle cx='110' cy='30' r='9' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='120' cy='55' r='9' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='95' cy='60' r='9' fill='#cfd8e8' stroke='#1a2b45'/><text x='150' y='35' fill='#1a2b45' font-size='11'>H₂ 2 katı</text><text x='150' y='55' fill='#1a2b45' font-size='11'>→ çarpışma ↑</text></svg>","steps":[{"t":"Çarpışma–derişim","a":"doğru orantı","d":"Çarpışma sayısı, çarpışan taneciklerin derişimleriyle doğru orantılıdır."},{"t":"H₂ iki katı","a":"N₂–H₂ çarpışması","d":"H₂ derişimi 2 katına çıkınca N₂ ile H₂ arasındaki çarpışma sayısı yaklaşık <b>2 katına</b> çıkar."},{"t":"Yorum","a":"hız ↑","d":"Daha çok çarpışma daha çok etkin çarpışma demektir; ileri tepkime hızı artar."}],"ans":"N₂–H₂ çarpışma sayısı yaklaşık <b>2 katına</b> çıkar."},{"q":"Bir tepkimede çarpışma sıklığı çok yüksek olduğu hâlde hız düşükse bunun çarpışma teorisine göre iki olası nedeni nedir?","steps":[{"t":"Birinci neden","a":"yüksek Ea","d":"Aktivasyon enerjisi yüksekse çarpışmaların çok azı yeterli enerjiye sahiptir."},{"t":"İkinci neden","a":"katı yönelim şartı","d":"Uygun yönelim olasılığı (sterik faktör) düşükse etkin çarpışma oranı azalır."},{"t":"Sonuç","a":"etkin oran düşük","d":"İki durumda da toplam çarpışma yüksek olsa bile <b>etkin çarpışma</b> oranı düşüktür."}],"ans":"Yüksek <b>Ea</b> ve/veya düşük <b>yönelim olasılığı</b>."},{"q":"İki farklı tepkimede çarpışma sıklığı eşit, ancak Ea değerleri farklıysa hangisi daha hızlıdır ve neden?","steps":[{"t":"Çarpışma eşit","a":"fark Ea'da","d":"Çarpışma sıklığı aynı olduğundan farkı belirleyen aktivasyon enerjisidir."},{"t":"Düşük Ea","a":"daha çok etkin çarpışma","d":"Ea düşük olan tepkimede taneciklerin daha büyük oranı eşiği aşar."},{"t":"Sonuç","a":"düşük Ea hızlı","d":"<b>Düşük Ea'lı</b> tepkime daha hızlıdır."}],"ans":"<b>Düşük Ea'lı</b> tepkime daha hızlıdır."},{"q":"Sıcaklık artışının tepkime hızını çoğunlukla çarpışma sıklığından çok aktivasyon enerjisini aşan tanecik oranını artırarak hızlandırdığı söylenir. Bunu açıklayın.","steps":[{"t":"Sıcaklık–çarpışma","a":"az artış","d":"Sıcaklık arttığında çarpışma sıklığı görece az (küçük oranda) artar."},{"t":"Sıcaklık–enerji dağılımı","a":"büyük etki","d":"Sıcaklık artışı, enerjisi Ea'yı aşan tanecik oranını <b>belirgin</b> ölçüde artırır."},{"t":"Sonuç","a":"etkin çarpışma fırlar","d":"Bu nedenle hızdaki büyük artış, esas olarak etkin çarpışma oranının yükselmesinden gelir."}],"ans":"Asıl etki, <b>Ea'yı aşan tanecik oranının</b> artmasıdır."}]}},"degisimHizi":{"ilkokul":{"kolay":[{"q":"Bir kâğıdı kibritle yakmak ile demir bir çivinin paslanması; hangisi daha hızlı gerçekleşir?","fig":"<svg viewBox='0 0 320 150'><text x='80' y='25' font-size='11' text-anchor='middle' fill='#1a2b45'>kâğıt yanması</text><circle cx='80' cy='75' r='22' fill='#e0552b' stroke='#1a2b45'/><text x='80' y='115' font-size='10' text-anchor='middle' fill='#1a2b45'>çok hızlı</text><text x='240' y='25' font-size='11' text-anchor='middle' fill='#1a2b45'>çivi paslanması</text><circle cx='240' cy='75' r='22' fill='#5b6b85' stroke='#1a2b45'/><text x='240' y='115' font-size='10' text-anchor='middle' fill='#1a2b45'>çok yavaş</text></svg>","steps":[{"t":"Kâğıt yanması","a":"saniyeler","d":"Kâğıt kibritle birkaç saniye içinde yanıp biter."},{"t":"Paslanma","a":"günler-aylar","d":"Demir çivinin paslanması günler hatta aylar sürer."}],"ans":"Kâğıdın yanması çok hızlı, çivinin paslanması ise çok yavaş gerçekleşir."},{"q":"Bir havai fişeğin patlaması neden hızlı bir değişimdir?","fig":"<svg viewBox='0 0 320 150'><circle cx='160' cy='75' r='10' fill='#e0552b'/><line x1='160' y1='75' x2='160' y2='30' stroke='#e0552b'/><line x1='160' y1='75' x2='160' y2='120' stroke='#e0552b'/><line x1='160' y1='75' x2='115' y2='75' stroke='#e0552b'/><line x1='160' y1='75' x2='205' y2='75' stroke='#e0552b'/><line x1='160' y1='75' x2='128' y2='43' stroke='#e0552b'/><line x1='160' y1='75' x2='192' y2='43' stroke='#e0552b'/><line x1='160' y1='75' x2='128' y2='107' stroke='#e0552b'/><line x1='160' y1='75' x2='192' y2='107' stroke='#e0552b'/><text x='160' y='142' font-size='11' text-anchor='middle' fill='#1a2b45'>anlık patlama</text></svg>","steps":[{"t":"Ne oluyor","a":"anlık patlama","d":"Havai fişek tutuşunca bir anda patlar, ışık ve ses çıkarır."},{"t":"Süre","a":"çok kısa","d":"Bütün bu olay saniyeden bile kısa sürdüğü için çok hızlı bir değişimdir."}],"ans":"Havai fişeğin patlaması bir anda olup bittiği için çok hızlı bir değişimdir."},{"q":"Bir muzun çürüyüp kararması hızlı mı yavaş mı bir değişimdir?","fig":"<svg viewBox='0 0 320 150'><path d='M60 60 Q100 100 140 60' fill='none' stroke='#1a2b45'/><text x='100' y='115' font-size='10' text-anchor='middle' fill='#1a2b45'>taze</text><text x='160' y='80' font-size='14' text-anchor='middle' fill='#1a2b45'>→</text><path d='M190 60 Q230 100 270 60' fill='none' stroke='#5b6b85' stroke-width='3'/><text x='230' y='115' font-size='10' text-anchor='middle' fill='#1a2b45'>günler sonra kararmış</text></svg>","steps":[{"t":"Ne oluyor","a":"yavaş kararma","d":"Muz birkaç gün içinde yavaş yavaş kararır ve yumuşar."},{"t":"Süre","a":"günler","d":"Bu değişim günler sürdüğü için yavaş bir değişimdir."}],"ans":"Muzun çürümesi günler sürdüğü için yavaş bir değişimdir."},{"q":"Aşağıdakilerden hangisi hızlı bir değişimdir: bir kibritin yanması mı yoksa bir kayanın aşınması mı?","steps":[{"t":"Kibrit","a":"hemen yanar","d":"Kibrit çakar çakmaz birkaç saniyede alev alır."},{"t":"Kaya aşınması","a":"yıllarca","d":"Kayaların su ve rüzgârla aşınması yıllar, hatta çok uzun zaman alır."}],"ans":"Kibritin yanması hızlı, kayanın aşınması ise çok yavaş bir değişimdir."},{"q":"Soba ya da ocakta odunun yanması neden hızlı bir değişime örnektir?","steps":[{"t":"Ne görüyoruz","a":"alev ve ısı","d":"Odun tutuşunca kısa sürede alevlenir, ısı ve ışık verir."},{"t":"Süre","a":"kısa","d":"Yanma kısa sürede gerçekleştiği için hızlı bir değişimdir."}],"ans":"Odunun yanması kısa sürede ısı ve ışık vererek gerçekleştiği için hızlı bir değişimdir."}],"zor":[{"q":"Annemiz yiyecekleri neden buzdolabına koyar; bu, değişimin hızıyla nasıl ilişkilidir?","steps":[{"t":"Soğuk ortam","a":"yavaşlatır","d":"Buzdolabı soğuktur ve soğuk, yiyeceklerin bozulmasını yavaşlatır."},{"t":"Sonuç","a":"geç bozulur","d":"Böylece çürüme (bozulma) değişimi yavaşlar ve yiyecekler daha uzun süre dayanır."}],"ans":"Buzdolabının soğukluğu bozulma değişimini yavaşlattığı için yiyecekler daha geç bozulur."},{"q":"Bir bardak ekmek dilimi açık havada birkaç günde küflenirken, mum bir kibritle hemen yanar. Bu iki olayı hızlarına göre nasıl sıralarız?","steps":[{"t":"Mumun yanması","a":"hızlı","d":"Mum kibritle değdiği anda yanmaya başlar; bu hızlı bir değişimdir."},{"t":"Ekmeğin küflenmesi","a":"yavaş","d":"Ekmeğin küflenmesi günler sürer; bu yavaş bir değişimdir."}],"ans":"Mumun yanması hızlı, ekmeğin küflenmesi yavaş bir değişimdir."},{"q":"İki dilim elmadan birini buzdolabına, diğerini masaya koyarsak hangisi daha çabuk kararır; neden?","steps":[{"t":"Masadaki elma","a":"daha çabuk","d":"Masadaki elma daha sıcak bir ortamdadır; sıcaklık değişimi hızlandırır, bu yüzden daha çabuk kararır."},{"t":"Buzdolabındaki elma","a":"daha yavaş","d":"Buzdolabındaki elma soğukta olduğu için kararması yavaşlar."}],"ans":"Masadaki elma daha çabuk kararır, çünkü ortam sıcak olduğunda değişim hızlanır."},{"q":"Patlama ile paslanma; ikisi de kimyasal değişim olduğu hâlde neden biri çok hızlı, diğeri çok yavaştır?","steps":[{"t":"Patlama","a":"anlık","d":"Patlamada maddeler bir anda hızla tepkimeye girer, çok kısa sürede biter."},{"t":"Paslanma","a":"uzun süre","d":"Paslanmada demir çok yavaş tepkimeye girer, bu yüzden günlerce, aylarca sürer."}],"ans":"İkisi de kimyasal değişimdir; patlamada maddeler bir anda tepkir, paslanmada ise çok yavaş tepkidiği için süre uzar."},{"q":"Bir kibriti çakıp odunu tutuşturmaya çalışırken kalın bir kütüğü yakmak neden ince çıralardan daha uzun sürer?","steps":[{"t":"İnce çıra","a":"hemen tutuşur","d":"İnce çıralar ince olduğu için kibritle hemen alev alır."},{"t":"Kalın kütük","a":"geç tutuşur","d":"Kalın kütüğün tutuşması daha zordur ve daha uzun sürer; yanma değişimi daha yavaş başlar."}],"ans":"İnce çıralar hemen tutuşurken kalın kütük geç tutuşur; parçanın büyüklüğü yanma hızını etkiler."}]},"ortaokul":{"kolay":[{"q":"Kimyasal değişimlerin hepsi aynı hızda mı gerçekleşir? Örnek veriniz.","steps":[{"t":"Hız çeşitliliği","a":"farklı hızlar","d":"Kimyasal değişimler çok farklı hızlarda olabilir; bazıları çok hızlı, bazıları çok yavaştır."},{"t":"Örnekler","a":"patlama-paslanma","d":"Patlama ve yanma çok hızlı, paslanma ve çürüme ise çok yavaş gerçekleşen değişimlerdir."}],"ans":"Hayır; kimyasal değişimler farklı hızlardadır: patlama ve yanma hızlı, paslanma ve çürüme yavaştır."},{"q":"Hızlı ve yavaş kimyasal değişimlere ikişer örnek veriniz.","steps":[{"t":"Hızlı değişimler","a":"yanma, patlama","d":"Yanma ve patlama saniyeler içinde tamamlanan hızlı değişimlerdir."},{"t":"Yavaş değişimler","a":"paslanma, çürüme","d":"Demirin paslanması ve besinlerin çürümesi günler, aylar süren yavaş değişimlerdir."}],"ans":"Hızlı: yanma ve patlama; yavaş: paslanma ve çürüme."},{"q":"Sıcaklık artışı bir kimyasal değişimin hızını genellikle nasıl etkiler?","fig":"<svg viewBox='0 0 320 150'><text x='80' y='25' font-size='11' text-anchor='middle' fill='#1a2b45'>soğuk</text><circle cx='65' cy='70' r='6' fill='#2b6be0'/><circle cx='95' cy='80' r='6' fill='#2b6be0'/><circle cx='80' cy='55' r='6' fill='#2b6be0'/><text x='80' y='115' font-size='10' text-anchor='middle' fill='#1a2b45'>yavaş çarpışma</text><text x='240' y='25' font-size='11' text-anchor='middle' fill='#1a2b45'>sıcak</text><circle cx='220' cy='65' r='6' fill='#e0552b'/><circle cx='255' cy='78' r='6' fill='#e0552b'/><circle cx='240' cy='52' r='6' fill='#e0552b'/><line x1='220' y1='65' x2='255' y2='78' stroke='#e0552b'/><text x='240' y='115' font-size='10' text-anchor='middle' fill='#1a2b45'>sık çarpışma</text></svg>","steps":[{"t":"Sıcaklık","a":"hızlandırır","d":"Sıcaklık arttığında tanecikler daha hızlı hareket eder ve daha sık çarpışır."},{"t":"Sonuç","a":"daha hızlı tepkime","d":"Bu yüzden çoğu kimyasal değişim sıcaklık artınca daha hızlı gerçekleşir."}],"ans":"Sıcaklık artışı genellikle kimyasal değişimi hızlandırır."},{"q":"Yiyecekleri buzdolabında saklamak çürüme hızını neden azaltır?","steps":[{"t":"Soğukluk","a":"hızı düşürür","d":"Düşük sıcaklık, çürümeye neden olan kimyasal değişimleri yavaşlatır."},{"t":"Sonuç","a":"geç bozulur","d":"Bu yüzden buzdolabındaki yiyecekler oda sıcaklığındakilere göre daha geç bozulur."}],"ans":"Buzdolabı düşük sıcaklığıyla çürüme hızını düşürdüğü için yiyecekler daha geç bozulur."},{"q":"Bir kömür tozunun aynı kütledeki bir kömür parçasından daha hızlı yanmasının nedeni nedir?","fig":"<svg viewBox='0 0 320 150'><text x='80' y='25' font-size='11' text-anchor='middle' fill='#1a2b45'>tek parça</text><rect x='55' y='45' width='50' height='50' fill='#334155' stroke='#1a2b45'/><text x='80' y='115' font-size='10' text-anchor='middle' fill='#1a2b45'>az yüzey</text><text x='240' y='25' font-size='11' text-anchor='middle' fill='#1a2b45'>toz</text><circle cx='215' cy='55' r='6' fill='#334155'/><circle cx='235' cy='62' r='6' fill='#334155'/><circle cx='255' cy='53' r='6' fill='#334155'/><circle cx='222' cy='78' r='6' fill='#334155'/><circle cx='245' cy='82' r='6' fill='#334155'/><circle cx='262' cy='75' r='6' fill='#334155'/><text x='240' y='115' font-size='10' text-anchor='middle' fill='#1a2b45'>geniş yüzey</text></svg>","steps":[{"t":"Yüzey alanı","a":"toz daha geniş","d":"Toz hâlinde kömürün havayla temas eden yüzeyi, tek parçaya göre çok daha geniştir."},{"t":"Sonuç","a":"hızlı yanma","d":"Temas yüzeyi arttıkça oksijenle daha çok yer çarpışır ve yanma hızlanır."}],"ans":"Toz hâlindeki kömürün yüzey alanı daha geniş olduğu için oksijenle daha çok temas eder ve daha hızlı yanar."}],"zor":[{"q":"Tepkime hızını etkileyen başlıca etmenler nelerdir?","steps":[{"t":"Etmenler","a":"sıcaklık, yüzey, derişim, katalizör","d":"Sıcaklık, temas yüzeyinin büyüklüğü, maddelerin derişimi (yoğunluğu) ve katalizör varlığı tepkime hızını etkiler."},{"t":"Genel kural","a":"çarpışma sıklığı","d":"Bu etmenlerin çoğu, tanecikler arası çarpışma sıklığını ve şiddetini değiştirerek hızı etkiler."}],"ans":"Sıcaklık, temas yüzeyi, derişim ve katalizör tepkime hızını etkileyen başlıca etmenlerdir."},{"q":"Katalizör nedir ve bir tepkimenin hızını nasıl değiştirir?","steps":[{"t":"Tanım","a":"hızlandırıcı madde","d":"Katalizör, bir tepkimeyi hızlandıran ama tepkime sonunda kendisi değişmeden kalan maddedir."},{"t":"Etki","a":"kolay yol açar","d":"Katalizör, tepkimenin daha kolay (daha az enerji isteyen) bir yoldan ilerlemesini sağlayarak hızı artırır; harcanmaz."}],"ans":"Katalizör, kendisi tükenmeden tepkimeye daha kolay bir yol sunarak tepkime hızını artıran maddedir."},{"q":"Aynı demir parçası tuzlu, nemli havada neden temiz, kuru havaya göre daha hızlı paslanır?","steps":[{"t":"Nem ve tuz","a":"hızlandırır","d":"Su ve tuz, demir ile oksijen arasındaki tepkimeyi kolaylaştırır."},{"t":"Sonuç","a":"hızlı paslanma","d":"Bu nedenle nemli ve tuzlu ortamdaki demir, kuru havadakine göre çok daha hızlı paslanır."}],"ans":"Nem ve tuz tepkimeyi kolaylaştırdığı için demir nemli-tuzlu havada kuru havaya göre daha hızlı paslanır."},{"q":"Bir efervesan (kabaran) tableti soğuk su yerine ılık suda atınca neden daha hızlı çözünüp köpürür?","steps":[{"t":"Sıcaklık etkisi","a":"hızlandırır","d":"Ilık suda tanecikler daha hızlı hareket eder ve tablet ile su daha sık etkileşir."},{"t":"Sonuç","a":"hızlı tepkime","d":"Bu nedenle tablet ılık suda daha hızlı çözünür ve gaz çıkışı (köpürme) daha hızlı olur."}],"ans":"Ilık su sıcaklığı artırıp tanecik hareketini hızlandırdığı için tablet daha hızlı çözünüp köpürür."},{"q":"Patlamanın çok hızlı, demirin paslanmasının çok yavaş bir kimyasal değişim olmasını tanecik düzeyinde açıklayınız.","steps":[{"t":"Patlama","a":"ani çarpışma","d":"Patlayıcıda tanecikler bir kıvılcımla aniden ve çok sayıda tepkir, kısa sürede büyük enerji açığa çıkar."},{"t":"Paslanma","a":"yavaş çarpışma","d":"Paslanmada demir, havadaki oksijen ve nemle çok seyrek ve yavaş tepkir, bu yüzden değişim aylar sürer."}],"ans":"Patlamada tanecikler bir anda yoğun biçimde tepkir, paslanmada ise çok yavaş ve seyrek tepkir; bu yüzden hızları çok farklıdır."}]},"lise":{"kolay":[{"q":"Tepkime hızı nasıl tanımlanır ve kimyasal değişimler neden çok farklı hızlarda gerçekleşir?","steps":[{"t":"Tanım","a":"birim zamanda değişim","d":"Tepkime hızı, birim zamanda harcanan tepken ya da oluşan ürün miktarı olarak tanımlanır."},{"t":"Hız farkı nedeni","a":"çarpışma ve enerji","d":"Tepkimeler, taneciklerin etkin çarpışma sıklığına ve aşılması gereken enerji engeline bağlı olarak çok farklı hızlarda yürür; bu yüzden patlama hızlı, paslanma yavaştır."}],"ans":"Tepkime hızı birim zamandaki madde değişimidir; etkin çarpışma sıklığı ve enerji engeli farklı olduğundan tepkimeler çok farklı hızlarda gerçekleşir."},{"q":"Tepkime hızını etkileyen etmenleri ve her birinin etki mekanizmasını kısaca açıklayınız.","steps":[{"t":"Etmenler","a":"sıcaklık, derişim, yüzey, katalizör","d":"Sıcaklık, derişim, temas yüzeyi ve katalizör tepkime hızını etkileyen başlıca etmenlerdir."},{"t":"Mekanizma","a":"çarpışma kuramı","d":"Bunların çoğu etkin çarpışma sayısını artırır; katalizör ise aktivasyon enerjisini düşürerek hızlandırır."}],"ans":"Sıcaklık, derişim, temas yüzeyi ve katalizör; çoğu etkin çarpışmayı artırarak, katalizör ise aktivasyon enerjisini düşürerek hızı etkiler."},{"q":"Çarpışma kuramına göre bir tepkimenin gerçekleşmesi için hangi koşullar sağlanmalıdır?","steps":[{"t":"Çarpışma","a":"tanecikler çarpışmalı","d":"Tepkimenin olabilmesi için tepken tanecikleri birbiriyle çarpışmalıdır."},{"t":"Etkin çarpışma","a":"yeterli enerji ve uygun yönelim","d":"Çarpışmanın ürün vermesi için tanecikler hem yeterli enerjiye (aktivasyon enerjisi) sahip olmalı hem de uygun konumda çarpışmalıdır."}],"ans":"Çarpışma kuramına göre tanecikler yeterli enerjiyle (aktivasyon enerjisi) ve uygun yönelimle çarpıştığında tepkime gerçekleşir."},{"q":"Sıcaklık artışı tepkime hızını neden belirgin biçimde artırır?","steps":[{"t":"Tanecik enerjisi","a":"artar","d":"Sıcaklık artınca taneciklerin ortalama kinetik enerjisi ve hareket hızı artar."},{"t":"Etkin çarpışma","a":"daha çok","d":"Hem çarpışmalar sıklaşır hem de aktivasyon enerjisini aşabilen tanecik oranı artar; böylece etkin çarpışma sayısı belirgin biçimde yükselir."}],"ans":"Sıcaklık artışı taneciklerin enerjisini ve çarpışma sıklığını artırarak aktivasyon enerjisini aşan etkin çarpışma sayısını yükseltir, bu da hızı artırır."},{"q":"Aktivasyon enerjisi nedir ve tepkime hızıyla ilişkisi nasıldır?","fig":"<svg viewBox='0 0 320 150'><line x1='30' y1='120' x2='300' y2='120' stroke='#1a2b45'/><line x1='30' y1='120' x2='30' y2='25' stroke='#1a2b45'/><path d='M50 100 Q120 100 150 40 Q180 100 270 100' fill='none' stroke='#e0552b' stroke-width='2'/><line x1='150' y1='40' x2='150' y2='100' stroke='#2b6be0'/><text x='185' y='70' font-size='10' fill='#2b6be0'>Eₐ</text><text x='160' y='140' font-size='10' text-anchor='middle' fill='#1a2b45'>tepkime ilerleyişi</text></svg>","steps":[{"t":"Tanım","a":"enerji engeli","d":"Aktivasyon enerjisi, tepkimenin başlaması için tepken taneciklerinin aşması gereken en düşük enerji engelidir."},{"t":"İlişki","a":"yüksek engel = yavaş","d":"Aktivasyon enerjisi yüksekse engeli aşabilen tanecik az olur ve tepkime yavaş; düşükse tepkime hızlı gerçekleşir."}],"ans":"Aktivasyon enerjisi tepkimenin başlaması için aşılması gereken enerji engelidir; engel yüksek oldukça tepkime yavaşlar, düşük oldukça hızlanır."}],"zor":[{"q":"Katalizör bir tepkimenin hızını artırırken denge konumunu değiştirmez; bunu aktivasyon enerjisi kavramıyla açıklayınız.","steps":[{"t":"Katalizör etkisi","a":"Ea düşürür","d":"Katalizör, hem ileri hem geri tepkime için daha düşük aktivasyon enerjili alternatif bir yol sunar."},{"t":"Denge değişmez","a":"iki yön de hızlanır","d":"İleri ve geri tepkime aynı oranda hızlandığından denge daha çabuk kurulur ama tepken-ürün oranı (denge konumu) değişmez."}],"ans":"Katalizör ileri ve geri tepkimenin aktivasyon enerjisini eşit oranda düşürür; bu yüzden denge daha hızlı kurulur ama denge konumu değişmez."},{"q":"Bir gaz tepkimesinde basıncın artırılması tepkime hızını neden etkiler ve bu hangi etmenle aynı sonucu verir?","steps":[{"t":"Basınç etkisi","a":"hacim azalır","d":"Sabit sıcaklıkta basınç artırılınca gazın hacmi küçülür ve tanecikler birim hacimde sıkışır."},{"t":"Sonuç","a":"derişim artışı gibi","d":"Birim hacimdeki tanecik sayısı arttığından çarpışma sıklaşır; bu, derişim artışıyla aynı etkiyi yaparak hızı artırır."}],"ans":"Basınç artışı gaz taneciklerini birim hacimde yoğunlaştırarak çarpışmayı sıklaştırır; bu, derişimi artırmakla aynı sonucu verir ve hızı artırır."},{"q":"Maksimum yüzey alanı ilkesiyle, endüstride bazı katı tepkenlerin neden toz hâline getirildiğini açıklayınız.","steps":[{"t":"Yüzey-hız ilişkisi","a":"geniş yüzey hızlı","d":"Katı bir tepkende tepkime yalnızca yüzeyde gerçekleşir; yüzey arttıkça temas eden tanecik sayısı artar."},{"t":"Tozlaştırma","a":"yüzeyi büyütür","d":"Katıyı toz hâline getirmek toplam yüzey alanını çok artırır, böylece tepkime hızlanır; bu yüzden endüstride katılar sıklıkla öğütülür."}],"ans":"Toz hâline getirmek katının yüzey alanını büyütüp temas eden tanecik sayısını artırdığından tepkimeyi hızlandırır; bu nedenle endüstride katılar öğütülür."},{"q":"Vücudumuzdaki tepkimelerin ılık vücut sıcaklığında çok hızlı yürüyebilmesi enzimlerle nasıl açıklanır?","steps":[{"t":"Sorun","a":"düşük sıcaklık yetersiz","d":"Vücut sıcaklığı (yaklaşık 37 °C) pek çok tepkimeyi kendiliğinden hızlandırmaya yetmez."},{"t":"Enzim çözümü","a":"biyolojik katalizör","d":"Enzimler biyolojik katalizör olarak aktivasyon enerjisini büyük ölçüde düşürür, böylece tepkimeler ılık vücut sıcaklığında bile çok hızlı gerçekleşir."}],"ans":"Enzimler biyolojik katalizör olarak aktivasyon enerjisini düşürdüğü için vücut tepkimeleri ılık vücut sıcaklığında bile çok hızlı yürür."},{"q":"İki özdeş demir parçasından biri kuru havada, diğeri tuzlu deniz havasında bırakılıyor. Hız farkını derişim ve elektrolit kavramıyla açıklayınız.","steps":[{"t":"Kuru hava","a":"yavaş paslanma","d":"Kuru havada su ve iyon az olduğundan demir-oksijen tepkimesi çok yavaş ilerler."},{"t":"Tuzlu nemli hava","a":"hızlı paslanma","d":"Tuzlu nem, çözünmüş iyonlarla (elektrolit) elektron aktarımını kolaylaştırır; bu, paslanma tepkimesinin hızını belirgin biçimde artırır."}],"ans":"Tuzlu nemli havadaki çözünmüş iyonlar elektrolit olarak elektron aktarımını kolaylaştırdığından paslanma kuru havaya göre çok daha hızlı gerçekleşir."}]}},"derisimEtki":{"ilkokul":{"kolay":[{"q":"Bir tepkimede tanecik sayısı artarsa tepkime daha hızlı mı yoksa daha yavaş mı olur?","steps":[{"t":"Tanecikler çarpışır","a":"çok tanecik","d":"Tepkimenin olması için taneciklerin birbirine çarpması gerekir."},{"t":"Çok tanecik çok çarpışma","a":"daha hızlı","d":"Tanecik sayısı artınca çarpışmalar sıklaşır ve tepkime hızlanır."}],"ans":"Tanecik sayısı artınca çarpışmalar sıklaşır ve tepkime daha hızlı olur."},{"q":"Şekerin tatlı suda mı yoksa az şekerli suda mı daha çok şeker taneciği vardır?","steps":[{"t":"Tatlı su","a":"çok şeker","d":"Tatlı suda birim hacimde daha çok şeker taneciği bulunur."},{"t":"Az şekerli su","a":"az şeker","d":"Az şekerli suda ise birim hacimde daha az şeker taneciği vardır."}],"ans":"Tatlı (çok şekerli) suda birim hacimde daha çok şeker taneciği bulunur."},{"q":"Bir kabı çok kalabalık atom dolduğunda atomlar birbirine daha sık mı çarpar?","fig":"<svg viewBox='0 0 320 150'><rect x='30' y='30' width='110' height='90' fill='none' stroke='#1a2b45'/><circle cx='55' cy='55' r='7' fill='#2b6be0'/><circle cx='80' cy='70' r='7' fill='#2b6be0'/><circle cx='110' cy='50' r='7' fill='#2b6be0'/><circle cx='95' cy='100' r='7' fill='#2b6be0'/><text x='85' y='140' font-size='11' text-anchor='middle' fill='#1a2b45'>az tanecik</text><rect x='180' y='30' width='110' height='90' fill='none' stroke='#1a2b45'/><circle cx='200' cy='50' r='7' fill='#e0552b'/><circle cx='225' cy='65' r='7' fill='#e0552b'/><circle cx='255' cy='48' r='7' fill='#e0552b'/><circle cx='275' cy='75' r='7' fill='#e0552b'/><circle cx='210' cy='95' r='7' fill='#e0552b'/><circle cx='245' cy='100' r='7' fill='#e0552b'/><circle cx='270' cy='110' r='7' fill='#e0552b'/><text x='235' y='140' font-size='11' text-anchor='middle' fill='#1a2b45'>çok tanecik</text></svg>","steps":[{"t":"Kalabalık kap","a":"çok atom","d":"Kapta çok atom varsa atomlar birbirine daha yakındır."},{"t":"Sık çarpışma","a":"daha sık","d":"Birbirine yakın olduklarından daha sık çarpışırlar."}],"ans":"Kap kalabalıklaştıkça atomlar daha sık çarpışır."},{"q":"Tepkimenin hızlı olması için taneciklerin ne yapması gerekir?","steps":[{"t":"Çarpışma","a":"çarpışmalı","d":"Tepkimenin olması için taneciklerin birbirine çarpması gerekir."},{"t":"Sık çarpışma","a":"hız artar","d":"Tanecikler ne kadar sık çarpışırsa tepkime o kadar hızlı olur."}],"ans":"Taneciklerin sık sık çarpışması tepkimeyi hızlandırır."},{"q":"Bir bardak suya bol tuz, başka bardağa az tuz attık. Hangisinde tuz taneciği daha sıktır?","steps":[{"t":"Bol tuz","a":"sık tanecik","d":"Bol tuz atılan bardakta tuz tanecikleri daha sıktır."},{"t":"Az tuz","a":"seyrek tanecik","d":"Az tuz atılan bardakta ise tanecikler daha seyrektir."}],"ans":"Bol tuz atılan bardakta tuz tanecikleri daha sık (yoğun) bulunur."}],"zor":[{"q":"Aynı kapta daha çok gaz taneciği olursa tepkime hızı nasıl değişir, neden?","steps":[{"t":"Çok tanecik","a":"sık çarpışma","d":"Kapta gaz taneciği çoğalınca tanecikler birbirine daha sık çarpar."},{"t":"Hız","a":"artar","d":"Çarpışmalar sıklaştığı için tepkime hızı artar."}],"ans":"Gaz taneciği çoğalınca çarpışmalar sıklaşır, bu yüzden tepkime hızı artar."},{"q":"Derişik (koyu) bir çözeltide tepkime, seyreltik (sulandırılmış) çözeltiye göre neden daha hızlıdır?","steps":[{"t":"Derişik","a":"çok tanecik","d":"Derişik çözeltide birim hacimde tepkimeye girecek tanecik daha çoktur."},{"t":"Çarpışma","a":"sıklaşır","d":"Tanecik çok olunca çarpışmalar sıklaşır ve hız artar."}],"ans":"Derişik çözeltide tanecik daha çok olduğundan çarpışmalar sıklaşır ve tepkime daha hızlı olur."},{"q":"Bir suyu sulandırınca (su ekleyince) içindeki tuz taneciklerinin sıklığına ne olur?","steps":[{"t":"Su eklenir","a":"hacim artar","d":"Su eklenince çözeltinin hacmi büyür ama tuz miktarı aynı kalır."},{"t":"Sıklık","a":"azalır","d":"Aynı tuz daha büyük hacme dağıldığından tanecik sıklığı azalır."}],"ans":"Sulandırınca aynı tuz daha büyük hacme yayıldığı için tanecik sıklığı azalır."},{"q":"İki tepkimeden birinde tanecikler sık, diğerinde seyrek. Hangisi önce biter?","fig":"<svg viewBox='0 0 320 150'><rect x='30' y='30' width='110' height='90' fill='none' stroke='#1a2b45'/><circle cx='55' cy='55' r='7' fill='#e0552b'/><circle cx='80' cy='65' r='7' fill='#e0552b'/><circle cx='110' cy='50' r='7' fill='#e0552b'/><circle cx='65' cy='95' r='7' fill='#e0552b'/><circle cx='100' cy='100' r='7' fill='#e0552b'/><circle cx='120' cy='90' r='7' fill='#e0552b'/><text x='85' y='140' font-size='11' text-anchor='middle' fill='#1a2b45'>sık</text><rect x='180' y='30' width='110' height='90' fill='none' stroke='#1a2b45'/><circle cx='210' cy='55' r='7' fill='#2b6be0'/><circle cx='260' cy='95' r='7' fill='#2b6be0'/><text x='235' y='140' font-size='11' text-anchor='middle' fill='#1a2b45'>seyrek</text></svg>","steps":[{"t":"Sık tanecik","a":"çok çarpışma","d":"Tanecikler sık olduğunda çarpışmalar çok ve hızlıdır."},{"t":"Sonuç","a":"sık olan biter","d":"Bu yüzden tanecikleri sık olan tepkime daha önce biter."}],"ans":"Tanecikleri sık olan tepkime daha hızlı olduğundan önce biter."},{"q":"Limon suyunu (asidi) suyla karıştırıp sulandırırsak metalle tepkimesi neden yavaşlar?","steps":[{"t":"Sulandırma","a":"asit seyrekleşir","d":"Su eklenince asit tanecikleri daha geniş hacme dağılır, seyrekleşir."},{"t":"Çarpışma azalır","a":"yavaşlar","d":"Asit tanecikleri seyrekleşince metalle çarpışmalar azalır ve tepkime yavaşlar."}],"ans":"Sulandırınca asit tanecikleri seyrekleştiği için metalle çarpışma azalır ve tepkime yavaşlar."}]},"ortaokul":{"kolay":[{"q":"Derişim (yoğunluk) nedir ve tepkime hızını nasıl etkiler?","steps":[{"t":"Derişim","a":"birim hacimde tanecik","d":"Derişim, belirli bir hacimde bulunan tepken tanecik miktarını gösterir."},{"t":"Etki","a":"artınca hız artar","d":"Derişim artınca birim hacimde tanecik çoğalır, çarpışma sıklaşır, tepkime hızlanır."}],"ans":"Derişim birim hacimdeki tanecik miktarıdır; arttığında çarpışma sıklaştığı için tepkime hızı artar."},{"q":"Birim hacimde tanecik sayısı arttığında çarpışma sıklığına ne olur?","steps":[{"t":"Tanecik artışı","a":"daha kalabalık","d":"Birim hacimde tanecik çoğalınca ortam daha kalabalık olur."},{"t":"Çarpışma","a":"sıklaşır","d":"Tanecikler birbirine daha sık rastlar, çarpışma sıklığı artar."}],"ans":"Birim hacimde tanecik sayısı artınca çarpışma sıklığı artar."},{"q":"Çinko metalinin derişik asitle mi yoksa seyreltik asitle mi tepkimesi daha hızlıdır?","fig":"<svg viewBox='0 0 320 160'><rect x='40' y='40' width='90' height='100' fill='#cfe3ff' stroke='#1a2b45'/><rect x='75' y='95' width='20' height='40' fill='#5b6b85' stroke='#1a2b45'/><circle cx='60' cy='60' r='5' fill='#e0552b'/><circle cx='100' cy='65' r='5' fill='#e0552b'/><circle cx='80' cy='80' r='5' fill='#e0552b'/><circle cx='110' cy='85' r='5' fill='#e0552b'/><text x='85' y='155' font-size='11' text-anchor='middle' fill='#1a2b45'>derişik</text><rect x='190' y='40' width='90' height='100' fill='#eef4ff' stroke='#1a2b45'/><rect x='225' y='95' width='20' height='40' fill='#5b6b85' stroke='#1a2b45'/><circle cx='210' cy='65' r='5' fill='#2b6be0'/><circle cx='260' cy='80' r='5' fill='#2b6be0'/><text x='235' y='155' font-size='11' text-anchor='middle' fill='#1a2b45'>seyreltik</text></svg>","steps":[{"t":"Derişik asit","a":"çok H⁺","d":"Derişik asitte birim hacimde daha çok asit (H⁺) taneciği bulunur."},{"t":"Hız","a":"derişikte hızlı","d":"Çok tanecik metalle daha sık çarpışır, bu yüzden derişik asitle tepkime daha hızlıdır."}],"ans":"Derişik asitte tanecik daha çok olduğundan çinko ile tepkime daha hızlı olur."},{"q":"Gaz tepkimelerinde derişimi artırmanın bir yolu nedir?","steps":[{"t":"Gaz derişimi","a":"hacme bağlı","d":"Sabit gaz miktarı daha küçük hacme sıkıştırılırsa birim hacimdeki tanecik artar."},{"t":"Sonuç","a":"derişim artar","d":"Böylece gazın derişimi (yoğunluğu) artmış olur."}],"ans":"Gazı daha küçük hacme sıkıştırmak birim hacimdeki tanecik sayısını, yani derişimi artırır."},{"q":"Bir tepkime ilerledikçe tepkenlerin derişimi neden azalır ve hız nasıl değişir?","steps":[{"t":"Tepkenler tükenir","a":"derişim azalır","d":"Tepkenler ürüne dönüştükçe ortamda kalan tepken taneciği azalır."},{"t":"Hız","a":"yavaşlar","d":"Tanecik azaldıkça çarpışmalar seyrekleşir ve tepkime yavaşlar."}],"ans":"Tepkenler tükendikçe derişim azalır, çarpışmalar seyrekleşir ve tepkime giderek yavaşlar."}],"zor":[{"q":"Mermer (CaCO₃) ile hidroklorik asit tepkimesinde asit derişimi iki katına çıkarsa başlangıç hızı nasıl etkilenir?","steps":[{"t":"Tepkime","a":"CaCO₃ + 2HCl → CaCl₂ + H₂O + CO₂","d":"Mermer asitle tepkimeye girip CO₂ gazı açığa çıkarır."},{"t":"Derişim etkisi","a":"H⁺ çoğalır","d":"Asit derişimi artınca birim hacimde H⁺ taneciği çoğalır, mermer yüzeyiyle çarpışma sıklaşır."},{"t":"Sonuç","a":"hız artar","d":"Çarpışma sıklaştığı için tepkimenin başlangıç hızı belirgin biçimde artar."}],"ans":"Asit derişimi artınca birim hacimdeki H⁺ taneciği çoğalır, mermerle çarpışmalar sıklaşır ve başlangıç hızı artar."},{"q":"Tepkime hızı zamanla neden azalır? Derişim açısından açıklayınız.","steps":[{"t":"Başlangıç","a":"derişim yüksek","d":"Tepkimenin başında tepken derişimi en yüksektir, çarpışma en sıktır, hız en büyüktür."},{"t":"İlerleme","a":"derişim düşer","d":"Tepkenler tükendikçe derişimleri azalır, çarpışma sıklığı düşer."},{"t":"Sonuç","a":"hız azalır","d":"Bu yüzden çoğu tepkimenin hızı zaman geçtikçe giderek azalır."}],"ans":"Tepkenler harcandıkça derişimleri düştüğü için çarpışmalar seyrekleşir ve tepkime hızı zamanla azalır."},{"q":"Tepkime kabına su eklenirse (seyreltme) çözünmüş tepkenlerin tepkime hızı nasıl değişir?","steps":[{"t":"Su ekleme","a":"hacim artar","d":"Su eklenince çözeltinin hacmi büyür ama tepken mol miktarı sabit kalır."},{"t":"Derişim","a":"azalır","d":"Aynı tepken daha büyük hacme dağıldığı için derişim (mol/L) düşer."},{"t":"Hız","a":"azalır","d":"Birim hacimdeki tanecik azaldığından çarpışmalar seyrekleşir, hız düşer."}],"ans":"Su eklenince hacim büyür, tepken derişimi düşer; çarpışmalar seyrekleştiği için tepkime hızı azalır."},{"q":"N₂ + 3H₂ → 2NH₃ tepkimesinde H₂ derişimini artırmak hızı neden artırır?","fig":"<svg viewBox='0 0 320 150'><circle cx='70' cy='60' r='10' fill='#5b6b85'/><circle cx='90' cy='60' r='10' fill='#5b6b85'/><text x='80' y='95' font-size='11' text-anchor='middle' fill='#1a2b45'>N₂</text><text x='130' y='65' font-size='16' text-anchor='middle' fill='#1a2b45'>+</text><circle cx='170' cy='45' r='7' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='190' cy='45' r='7' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='170' cy='70' r='7' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='190' cy='70' r='7' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='180' cy='90' r='7' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='200' cy='90' r='7' fill='#cfd8e8' stroke='#1a2b45'/><text x='185' y='120' font-size='11' text-anchor='middle' fill='#1a2b45'>3H₂</text><text x='250' y='65' font-size='14' text-anchor='middle' fill='#1a2b45'>→ 2NH₃</text></svg>","steps":[{"t":"Tepkime","a":"N₂ + 3H₂ → 2NH₃","d":"Azot ve hidrojen gazları birleşip amonyak oluşturur."},{"t":"Derişim artışı","a":"H₂ çoğalır","d":"H₂ derişimi artınca birim hacimde H₂ taneciği çoğalır, N₂ ile çarpışma sıklaşır."},{"t":"Sonuç","a":"hız artar","d":"Etkin çarpışma sayısı arttığı için tepkime hızı artar."}],"ans":"H₂ derişimi artınca birim hacimde H₂ taneciği çoğalır, N₂ ile çarpışmalar sıklaşır ve tepkime hızı artar."},{"q":"Aynı kütlede tuz, bir kez 1 litre suda bir kez 4 litre suda çözülürse hangisinde tepkime daha hızlı olur?","steps":[{"t":"Aynı mol","a":"farklı hacim","d":"İki durumda da tuz miktarı (mol) aynı ama çözüldüğü hacim farklıdır."},{"t":"Derişim","a":"1 L'de yüksek","d":"Aynı mol daha küçük hacme (1 L) dağılınca derişim daha yüksek olur."},{"t":"Hız","a":"1 L'de hızlı","d":"Daha derişik çözeltide çarpışma sık olduğundan tepkime daha hızlıdır."}],"ans":"Aynı tuz 1 litre suda çözüldüğünde derişim daha yüksek olur; çarpışmalar sık olduğundan tepkime 4 litredekine göre daha hızlı gerçekleşir."}]},"lise":{"kolay":[{"q":"Derişimin tepkime hızına etkisini çarpışma kuramıyla açıklayınız.","steps":[{"t":"Çarpışma kuramı","a":"hız ∝ çarpışma","d":"Tepkime, tanecikler uygun yönelim ve yeterli enerjiyle çarpıştığında gerçekleşir; hız çarpışma sayısıyla orantılıdır."},{"t":"Derişim etkisi","a":"birim hacimde tanecik","d":"Derişim artınca birim hacimdeki tanecik sayısı artar, birim zamandaki çarpışma sayısı çoğalır."},{"t":"Sonuç","a":"hız artar","d":"Çarpışma sıklığı arttığı için etkin çarpışma sayısı da artar ve tepkime hızı yükselir."}],"ans":"Çarpışma kuramına göre derişim artınca birim hacimdeki tanecik sayısı, dolayısıyla çarpışma sıklığı artar; etkin çarpışmalar çoğaldığından tepkime hızı yükselir."},{"q":"Hız denklemi hız = k·[A]·[B] olan bir tepkimede [A] iki katına çıkarsa hız nasıl değişir?","steps":[{"t":"Hız denklemi","a":"hız = k[A][B]","d":"Hız, [A] derişimiyle birinci dereceden doğru orantılıdır."},{"t":"Değişim","a":"[A] → 2[A]","d":"[A] iki katına çıkıp [B] sabit kalırsa hız da 2 katına çıkar."}],"ans":"Hız [A] ile birinci dereceden orantılı olduğundan [A] iki katına çıkınca hız da 2 katına çıkar."},{"q":"Tepkime başlangıcında hız neden en yüksektir?","steps":[{"t":"Başlangıç derişimi","a":"en yüksek","d":"Tepkimenin başında tepken derişimleri en büyüktür."},{"t":"Çarpışma","a":"en sık","d":"Yüksek derişim en sık çarpışmayı, dolayısıyla en yüksek anlık hızı verir."}],"ans":"Başlangıçta tepken derişimleri en yüksek olduğu için çarpışma sıklığı ve dolayısıyla tepkime hızı en büyüktür."},{"q":"Seyreltme bir çözeltideki tepkimenin hızını neden düşürür?","steps":[{"t":"Seyreltme","a":"hacim artar","d":"Çözücü eklenince hacim artar, tepken mol miktarı değişmez."},{"t":"Derişim","a":"mol/L azalır","d":"Aynı mol daha büyük hacme yayıldığından molar derişim düşer."},{"t":"Hız","a":"azalır","d":"Hız denklemine göre derişim düşünce hız da azalır."}],"ans":"Seyreltme hacmi artırıp molar derişimi düşürdüğünden, hız derişimle orantılı olduğu için tepkime hızı azalır."},{"q":"Hız = k·[NO]²·[O₂] denkleminde [NO] üç katına çıkarsa hız kaç kat olur?","fig":"<svg viewBox='0 0 320 120'><text x='160' y='45' font-size='15' text-anchor='middle' fill='#1a2b45'>hız = k·[NO]²·[O₂]</text><text x='160' y='80' font-size='13' text-anchor='middle' fill='#1a2b45'>[NO] → 3[NO]  ⇒  3² = 9 kat</text></svg>","steps":[{"t":"Derece","a":"[NO]²","d":"Hız, [NO] derişimine göre ikinci derecedendir."},{"t":"Değişim","a":"3² = 9","d":"[NO] üç katına çıkınca etki kare olduğundan hız 3² = 9 katına çıkar."}],"ans":"Hız [NO] derişimine göre ikinci dereceden olduğundan [NO] üç katına çıkınca hız 3² = 9 katına çıkar."}],"zor":[{"q":"Hız = k·[A]·[B]² olan bir tepkimede [A] iki katına, [B] üç katına çıkarsa hız kaç katına çıkar?","steps":[{"t":"Hız denklemi","a":"hız = k[A][B]²","d":"Hız, [A]'ya birinci, [B]'ye ikinci dereceden bağlıdır."},{"t":"A etkisi","a":"2¹ = 2","d":"[A] iki katına çıkınca bu çarpan 2 olur."},{"t":"B etkisi ve sonuç","a":"3² = 9, toplam 18","d":"[B] üç katına çıkınca 3² = 9 olur; ikisi çarpılır: 2 × 9 = 18 kat."}],"ans":"[A]'nın etkisi 2¹ = 2, [B]'nin etkisi 3² = 9'dur; hız 2 × 9 = 18 katına çıkar."},{"q":"Bir tepkimenin derişim-zaman grafiğinde eğimin giderek azalması neyi gösterir?","steps":[{"t":"Eğim","a":"anlık hız","d":"Derişim-zaman grafiğinde eğrinin eğimi o andaki tepkime hızını verir."},{"t":"Azalan eğim","a":"hız düşüyor","d":"Eğimin giderek azalması anlık hızın azaldığını gösterir."},{"t":"Neden","a":"derişim düşüyor","d":"Tepkenler tükendikçe derişim düştüğü için çarpışma sıklığı ve hız azalır."}],"ans":"Eğrinin eğimi anlık hızdır; eğimin azalması tepken derişimi düştükçe çarpışma sıklığının ve hızın azaldığını gösterir."},{"q":"Tepkime derecesi (mertebesi) ile katsayı (denklem katsayısı) neden her zaman aynı olmayabilir?","steps":[{"t":"Katsayı","a":"denklemden","d":"Denklem katsayısı, denkleştirilmiş tepkimedeki mol oranını verir."},{"t":"Derece","a":"deneysel","d":"Tepkime derecesi ise yalnızca deneyle bulunur, mekanizmanın yavaş (hız belirleyen) basamağına bağlıdır."},{"t":"Sonuç","a":"aynı olmayabilir","d":"Tepkime tek basamaklı (temel) değilse derece, denklem katsayısından farklı çıkabilir."}],"ans":"Katsayı denklemden gelir; tepkime derecesi ise deneyseldir ve hız belirleyen basamağa bağlıdır, bu yüzden çok basamaklı tepkimelerde ikisi farklı olabilir."},{"q":"İki deneyde [A] sabit tutulup [B] iki katına çıkarıldığında hız dört katına çıkıyorsa B'ye göre derece kaçtır?","fig":"<svg viewBox='0 0 320 130'><text x='160' y='35' font-size='13' text-anchor='middle' fill='#1a2b45'>[B]: x → 2x</text><text x='160' y='65' font-size='13' text-anchor='middle' fill='#1a2b45'>hız: v → 4v</text><text x='160' y='100' font-size='14' text-anchor='middle' fill='#1a2b45'>2ⁿ = 4 ⇒ n = 2</text></svg>","steps":[{"t":"Oran","a":"2 kat → 4 kat","d":"[B] 2 katına çıkınca hız 4 katına çıkıyor."},{"t":"Derece","a":"2ⁿ = 4","d":"2ⁿ = 4 eşitliğinden n = 2 bulunur."}],"ans":"[B] 2 katına çıkınca hız 4 (2²) katına çıktığı için tepkime B'ye göre ikinci derecedendir (n = 2)."},{"q":"Sıfırıncı dereceden bir tepkimede (hız = k) derişim artışı hızı neden etkilemez?","steps":[{"t":"Sıfırıncı derece","a":"hız = k","d":"Sıfırıncı dereceden tepkimede hız derişimden bağımsızdır, yalnızca k sabitine bağlıdır."},{"t":"Neden","a":"yüzey/katalizör doygun","d":"Genelde tepkime sınırlı bir yüzey ya da katalizörle yürür; bu bölgeler doyduğu için derişimi artırmak hızı değiştirmez."},{"t":"Sonuç","a":"sabit hız","d":"Derişim artsa da hız sabit kalır, çünkü hızı belirleyen etken tepken derişimi değildir."}],"ans":"Sıfırıncı dereceden tepkimede hız = k olup derişimden bağımsızdır; hız genelde doymuş bir yüzey ya da katalizörle sınırlandığından derişim artışı hızı etkilemez."}]}},"katalizor":{"ilkokul":{"kolay":[{"q":"Bazı maddeler bir işi daha çabuk bitirmemize yardım eder. Tepkimeyi hızlandıran bu yardımcıya ne denir?","steps":[{"t":"Yardımcı madde","a":"hızlandırır","d":"Bir tepkimenin daha çabuk olmasını sağlayan yardımcı maddeler vardır."},{"t":"Adı","a":"katalizör","d":"Tepkimeyi hızlandıran bu yardımcı maddeye katalizör denir."}],"ans":"Tepkimeyi hızlandıran yardımcı maddeye katalizör denir."},{"q":"Katalizör tepkimeyi hızlandırır ama kendisine ne olur?","steps":[{"t":"İş biter","a":"hâlâ orada","d":"Tepkime bittiğinde katalizör hâlâ vardır, yok olmaz."},{"t":"Tükenmez","a":"aynı kalır","d":"Bir köprü gibi sadece yardım eder, kendisi tükenmez."}],"ans":"Katalizör tepkime sonunda tükenmez, hemen hemen aynı kalır."},{"q":"Bir kaydıraktan inerken yol kısa olunca aşağı daha çabuk inersin. Katalizör de tepkimeye nasıl yardım eder?","fig":"<svg viewBox='0 0 320 150'><path d='M40 30 Q90 30 120 130' fill='none' stroke='#5b6b85' stroke-width='3'/><path d='M180 70 Q210 70 250 130' fill='none' stroke='#2b6be0' stroke-width='3'/><circle cx='45' cy='30' r='8' fill='#e0552b'/><circle cx='185' cy='70' r='8' fill='#e0552b'/><text x='80' y='25' font-size='10' fill='#5b6b85'>uzun yol</text><text x='210' y='65' font-size='10' fill='#2b6be0'>kısa yol</text></svg>","steps":[{"t":"Kısa yol","a":"daha kolay","d":"Katalizör tepkimeye daha kolay, kısa bir yol açar."},{"t":"Çabuk biter","a":"hızlanır","d":"Bu kolay yol sayesinde tepkime daha çabuk olur."}],"ans":"Katalizör daha kolay bir yol açtığı için tepkime daha çabuk gerçekleşir."},{"q":"Vücudumuzda yediğimiz besinleri parçalamaya yardım eden doğal yardımcılara ne denir?","steps":[{"t":"Vücutta yardımcı","a":"enzim","d":"Vücudumuzda besinleri parçalamaya yardım eden yardımcılara enzim denir."},{"t":"Görevi","a":"hızlandırır","d":"Enzimler de bir tür katalizördür, işleri hızlandırır."}],"ans":"Vücudumuzdaki bu doğal yardımcılara enzim denir; onlar da işleri hızlandırır."},{"q":"Bir madde tepkimeyi yavaşlatıyorsa, bu katalizörün tersi olan maddeye ne denir?","steps":[{"t":"Yavaşlatan","a":"engel olur","d":"Bazı maddeler tepkimeyi hızlandırmak yerine yavaşlatır."},{"t":"Adı","a":"inhibitör","d":"Tepkimeyi yavaşlatan bu maddeye inhibitör denir, katalizörün tersidir."}],"ans":"Tepkimeyi yavaşlatan maddeye inhibitör denir; bu katalizörün tersidir."}],"zor":[{"q":"Katalizör eklediğimizde tepkime hızlanır. Peki katalizör tepkimeden sonra azalır mı?","steps":[{"t":"Yalnız yardım","a":"kullanılmaz","d":"Katalizör tepkimenin malzemesi gibi harcanmaz, sadece yardım eder."},{"t":"Sonuç","a":"azalmaz","d":"Tepkime bitince katalizörün miktarı neredeyse hiç azalmaz."}],"ans":"Hayır, katalizör tepkime boyunca harcanmadığı için sonunda miktarı azalmaz."},{"q":"Aynı katalizörü bir tepkimede tekrar tekrar kullanabilir miyiz?","steps":[{"t":"Tükenmez","a":"aynı kalır","d":"Katalizör her seferinde tükenmediği için kaybolmaz."},{"t":"Tekrar kullanım","a":"evet","d":"Aynı katalizör tekrar tekrar kullanılabilir, çünkü her işten sonra hâlâ ortadadır."}],"ans":"Evet, katalizör tükenmediği için aynı tepkimede tekrar tekrar kullanılabilir."},{"q":"Çamaşır tozlarının içine konan enzimler kirleri çıkarmaya nasıl yardım eder?","steps":[{"t":"Enzim katalizör","a":"hızlandırır","d":"Enzimler bir tür katalizördür ve kir lekelerinin çözülmesini hızlandırır."},{"t":"Sonuç","a":"daha temiz","d":"Böylece lekeler daha çabuk çözülür ve çamaşır daha kolay temizlenir."}],"ans":"Çamaşır tozundaki enzimler katalizör gibi davranıp leke çözülmesini hızlandırır, böylece kir daha kolay çıkar."},{"q":"Katalizör tepkimeyi hızlandırır ama tepkimede açığa çıkan ısıyı ya da sonucu değiştirir mi?","steps":[{"t":"Sadece hız","a":"hızı artırır","d":"Katalizör yalnızca tepkimenin daha çabuk olmasını sağlar."},{"t":"Sonuç aynı","a":"değişmez","d":"Tepkimenin sonunda elde edilen ürün ve açığa çıkan ısı aynı kalır."}],"ans":"Katalizör sadece hızı artırır; tepkimenin ürününü veya açığa çıkan ısıyı değiştirmez."},{"q":"Bir oyunda hem gidiş hem dönüş yolunu kısaltırsan ikisi de hızlanır. Katalizör tepkimenin sadece ileri yönünü mü hızlandırır?","steps":[{"t":"İki yön","a":"ileri ve geri","d":"Bazı tepkimeler hem ileri hem geri gidebilir."},{"t":"Eşit yardım","a":"ikisini de","d":"Katalizör hem ileri hem geri yönü hızlandırır, sadece birini değil."}],"ans":"Hayır, katalizör tepkimenin hem ileri hem geri yönünü birlikte hızlandırır."}]},"ortaokul":{"kolay":[{"q":"Katalizör bir tepkimenin hızını nasıl etkiler?","steps":[{"t":"Hız değişimi","a":"artar","d":"Katalizör eklenince tepkimenin gerçekleşme hızı artar."},{"t":"Kendisi","a":"tükenmez","d":"Katalizör bu sırada harcanmaz, tepkime sonunda geri kazanılır."}],"ans":"Katalizör tepkime hızını artırır ve kendisi tükenmeden tepkime sonunda geri kazanılır."},{"q":"Bir tepkimenin başlaması için aşılması gereken enerji engeline ne ad verilir?","steps":[{"t":"Enerji engeli","a":"eşik enerji","d":"Tepkimenin başlaması için tanecikler en az belli bir enerjiye ulaşmalıdır."},{"t":"Adı","a":"aktivasyon enerjisi","d":"Bu en düşük enerji engeline aktivasyon enerjisi denir."}],"ans":"Tepkimenin başlaması için aşılması gereken bu enerji engeline aktivasyon enerjisi denir."},{"q":"Katalizör aktivasyon enerjisini nasıl etkiler?","fig":"<svg viewBox='0 0 320 175'><line x1='30' y1='150' x2='300' y2='150' stroke='#1a2b45'/><line x1='30' y1='150' x2='30' y2='20' stroke='#1a2b45'/><path d='M50 130 Q120 30 190 110' fill='none' stroke='#5b6b85' stroke-width='2'/><path d='M50 130 Q120 70 190 110' fill='none' stroke='#2b6be0' stroke-width='2' stroke-dasharray='4 3'/><text x='120' y='25' font-size='10' fill='#5b6b85'>katalizörsüz</text><text x='130' y='62' font-size='10' fill='#2b6be0'>katalizörlü</text><text x='200' y='115' font-size='10' fill='#1a2b45'>ürün</text></svg>","steps":[{"t":"Engeli düşürür","a":"alternatif yol","d":"Katalizör tepkimeye daha düşük enerji gerektiren yeni (alternatif) bir yol sağlar."},{"t":"Sonuç","a":"hız artar","d":"Aktivasyon enerjisi düştüğü için daha çok tanecik engeli aşar ve hız artar."}],"ans":"Katalizör daha düşük enerjili alternatif bir yol sunarak aktivasyon enerjisini düşürür, böylece hızı artırır."},{"q":"Canlıların vücudundaki biyolojik katalizörlere ne ad verilir?","steps":[{"t":"Biyolojik yardımcı","a":"enzim","d":"Canlı hücrelerdeki tepkimeleri hızlandıran protein yapılı katalizörler vardır."},{"t":"Adı","a":"enzim","d":"Bu biyolojik katalizörlere enzim denir; örneğin tükürükteki amilaz nişastayı parçalar."}],"ans":"Canlılardaki biyolojik katalizörlere enzim denir."},{"q":"İnhibitör bir tepkimeye nasıl etki eder?","steps":[{"t":"Etki yönü","a":"yavaşlatır","d":"İnhibitör, katalizörün tersine tepkimenin hızını azaltır."},{"t":"Kullanım","a":"engelleyici","d":"İstenmeyen tepkimeleri yavaşlatmak için inhibitör kullanılır."}],"ans":"İnhibitör tepkimeyi yavaşlatır; bu yönüyle katalizörün tersidir."}],"zor":[{"q":"Katalizör tepkimenin denge konumunu (ürün miktarını) değiştirir mi?","steps":[{"t":"İleri ve geri","a":"eşit hızlanır","d":"Katalizör hem ileri hem geri tepkimeyi aynı oranda hızlandırır."},{"t":"Denge aynı","a":"daha erken ulaşılır","d":"İki yön eşit hızlandığı için denge konumu değişmez; sadece dengeye daha çabuk ulaşılır."}],"ans":"Hayır, katalizör ileri ve geri tepkimeyi eşit hızlandırdığından denge konumunu değiştirmez, yalnızca dengeye daha çabuk ulaştırır."},{"q":"Katalizör tepkimenin verdiği ya da aldığı ısı miktarını (ΔH) değiştirir mi?","steps":[{"t":"Yol değişir","a":"enerji aynı","d":"Katalizör sadece tepkimenin izlediği yolu değiştirir, başlangıç ve bitiş enerjilerini değiştirmez."},{"t":"ΔH sabit","a":"değişmez","d":"Tepkimenin açığa çıkardığı veya aldığı net ısı (ΔH) aynı kalır."}],"ans":"Hayır, katalizör tepkimenin net ısısını (ΔH) değiştirmez; yalnızca aktivasyon enerjisini düşürür."},{"q":"Bir katalizör tepkimeye katılır gibi görünür ama sonunda neden geri kazanılır?","steps":[{"t":"Ara basamak","a":"geçici birleşme","d":"Katalizör tepkimenin ara basamağında tepkenlerle geçici olarak birleşir."},{"t":"Yeniden serbest","a":"geri çıkar","d":"Tepkime tamamlanınca katalizör bağlandığı yerden ayrılıp serbest kalır, böylece net olarak tükenmez."}],"ans":"Katalizör ara basamakta geçici olarak birleşip sonunda yeniden serbest kaldığı için net olarak tükenmez ve geri kazanılır."},{"q":"Homojen ve heterojen katalizör arasındaki fark nedir?","steps":[{"t":"Homojen","a":"aynı fazda","d":"Homojen katalizör, tepkenlerle aynı fazdadır (örneğin ikisi de çözeltide)."},{"t":"Heterojen","a":"farklı fazda","d":"Heterojen katalizör farklı fazdadır; örneğin katı katalizör yüzeyinde gaz tepkimesi gerçekleşir."}],"ans":"Homojen katalizör tepkenlerle aynı fazda, heterojen katalizör ise farklı fazda (örneğin katı yüzey) bulunur."},{"q":"Enzimlerin belirli bir tepkimeye özgü çalışması neyle açıklanır?","fig":"<svg viewBox='0 0 320 165'><path d='M40 110 Q40 50 110 50 L150 50 Q150 70 130 80 Q150 90 150 110 Z' fill='#9ed9a8' stroke='#1a2b45'/><rect x='128' y='72' width='18' height='16' fill='#e0552b' stroke='#1a2b45'/><text x='80' y='95' font-size='10' fill='#1a2b45'>enzim</text><text x='175' y='84' font-size='10' fill='#1a2b45'>substrat</text></svg>","steps":[{"t":"Aktif bölge","a":"özel şekil","d":"Her enzimin substrata uyan özel bir aktif bölgesi (cebi) vardır."},{"t":"Anahtar-kilit","a":"seçici","d":"Anahtar-kilit uyumu gibi, yalnızca uygun substrat bağlanabildiğinden enzim seçicidir."}],"ans":"Enzimin aktif bölgesinin substrata anahtar-kilit gibi uyması, onu belirli bir tepkimeye özgü ve seçici kılar."}]},"lise":{"kolay":[{"q":"Katalizörün tepkime hızını artırma mekanizması nedir?","fig":"<svg viewBox='0 0 320 165'><line x1='30' y1='140' x2='300' y2='140' stroke='#1a2b45'/><line x1='30' y1='140' x2='30' y2='20' stroke='#1a2b45'/><path d='M45 110 Q110 25 175 95 L290 95' fill='none' stroke='#5b6b85' stroke-width='2'/><path d='M45 110 Q90 78 120 82 Q150 86 175 95' fill='none' stroke='#2b6be0' stroke-width='2' stroke-dasharray='4 3'/><text x='110' y='22' font-size='9' fill='#5b6b85'>Ea büyük</text><text x='90' y='72' font-size='9' fill='#2b6be0'>Ea küçük</text><text x='250' y='90' font-size='9' fill='#1a2b45'>ürünler</text></svg>","steps":[{"t":"Alternatif yol","a":"farklı mekanizma","d":"Katalizör, tepkimenin daha düşük aktivasyon enerjili alternatif bir mekanizma izlemesini sağlar."},{"t":"Etkin çarpışma","a":"daha fazla tanecik","d":"Aktivasyon enerjisi düştüğünden, eşik enerjiyi aşıp etkin çarpışma yapan tanecik sayısı artar ve hız büyür."}],"ans":"Katalizör daha düşük aktivasyon enerjili alternatif bir yol sunar; böylece etkin çarpışma yapan tanecik oranı artar ve tepkime hızı yükselir."},{"q":"Katalizör tepkimenin entalpi değişimini (ΔH) neden değiştirmez?","fig":"<svg viewBox='0 0 320 180'><line x1='30' y1='160' x2='300' y2='160' stroke='#1a2b45'/><line x1='30' y1='160' x2='30' y2='20' stroke='#1a2b45'/><path d='M45 120 Q110 30 175 100 L290 100' fill='none' stroke='#5b6b85' stroke-width='2'/><path d='M45 120 Q110 65 175 100' fill='none' stroke='#2b6be0' stroke-width='2' stroke-dasharray='4 3'/><line x1='45' y1='120' x2='45' y2='160' stroke='#1a2b45' stroke-dasharray='2 2'/><text x='48' y='115' font-size='9' fill='#1a2b45'>tepkenler</text><text x='250' y='95' font-size='9' fill='#1a2b45'>ürünler</text><text x='110' y='25' font-size='9' fill='#5b6b85'>Ea (katalizörsüz)</text></svg>","steps":[{"t":"Başlangıç-bitiş","a":"sabit","d":"ΔH yalnızca tepkenlerin ve ürünlerin enerji düzeyine bağlıdır; bu düzeyler katalizörden etkilenmez."},{"t":"Sadece tepe","a":"Ea düşer","d":"Katalizör yalnızca enerji engelinin (Ea) yüksekliğini düşürür, başlangıç ve bitiş enerjilerini değiştirmez."}],"ans":"ΔH tepkenler ve ürünlerin enerji farkına bağlıdır; katalizör yalnızca aktivasyon enerjisini düşürdüğünden ΔH değişmez."},{"q":"Bir katalizör dengeye nasıl etki eder?","steps":[{"t":"İki yönü hızlandırır","a":"ileri = geri","d":"Katalizör ileri ve geri tepkimenin hız sabitlerini aynı oranda büyütür."},{"t":"Denge sabiti","a":"K değişmez","d":"İki yön eşit etkilendiğinden denge sabiti (K) ve ürün miktarı değişmez; yalnızca dengeye ulaşma süresi kısalır."}],"ans":"Katalizör ileri ve geri tepkimeyi eşit hızlandırdığından denge sabitini ve denge konumunu değiştirmez, yalnızca dengeye daha kısa sürede ulaşılmasını sağlar."},{"q":"İnhibitör ile katalizör arasındaki temel fark nedir?","steps":[{"t":"Katalizör","a":"hızlandırır","d":"Katalizör aktivasyon enerjisini düşürerek tepkime hızını artırır."},{"t":"İnhibitör","a":"yavaşlatır","d":"İnhibitör ise tepkime hızını azaltır; örneğin enzimlerin aktif bölgesini bloke ederek (enzim inhibitörü) çalışmayı engelleyebilir."}],"ans":"Katalizör tepkimeyi hızlandırırken inhibitör yavaşlatır; ikisi de hız üzerinde etkilidir ama zıt yönde çalışır."},{"q":"Heterojen katalizde katı katalizör yüzeyinin önemi nedir?","steps":[{"t":"Yüzeyde tutunma","a":"adsorpsiyon","d":"Gaz tepkenler katı katalizör yüzeyine tutunur (adsorpsiyon), böylece tanecikler uygun konuma gelir."},{"t":"Bağ zayıflar","a":"hız artar","d":"Yüzeyde tepkenlerin bağları zayıflar, aktivasyon enerjisi düşer ve tepkime yüzeyde hızla gerçekleşir."}],"ans":"Heterojen katalizde tepkenler katı yüzeye tutunarak bağları zayıflar ve aktivasyon enerjisi düşer; bu nedenle yüzey alanı arttıkça katalitik etki güçlenir."}],"zor":[{"q":"Bir katalizör tepkimeye katılmasına rağmen tepkime denkleminde neden yer almaz?","steps":[{"t":"Ara basamak","a":"oluşup tüketilir","d":"Katalizör ilk basamakta tepkenlerle birleşip ara tür oluşturur, sonraki basamakta yeniden açığa çıkar."},{"t":"Net denklem","a":"sadeleşir","d":"Basamaklar toplanıp net denklem yazıldığında katalizör hem girende hem üründe yer aldığından sadeleşir; bu yüzden net denklemde görünmez."}],"ans":"Katalizör ara basamaklarda oluşup yeniden tüketildiğinden, basamaklar toplanınca sadeleşir ve net tepkime denkleminde yer almaz."},{"q":"Katalizör Maxwell-Boltzmann enerji dağılımı açısından hızı nasıl artırır?","fig":"<svg viewBox='0 0 320 175'><line x1='30' y1='150' x2='300' y2='150' stroke='#1a2b45'/><line x1='30' y1='150' x2='30' y2='20' stroke='#1a2b45'/><path d='M30 150 Q90 30 150 70 Q220 120 295 145' fill='none' stroke='#1a2b45' stroke-width='2'/><line x1='150' y1='30' x2='150' y2='150' stroke='#5b6b85' stroke-dasharray='3 3'/><line x1='210' y1='30' x2='210' y2='150' stroke='#2b6be0' stroke-dasharray='3 3'/><text x='128' y='25' font-size='9' fill='#5b6b85'>Ea(kat.)</text><text x='200' y='25' font-size='9' fill='#2b6be0'>Ea</text></svg>","steps":[{"t":"Eşik düşer","a":"Ea azalır","d":"Katalizör aktivasyon enerjisini düşürdüğünden eşik değer dağılım eğrisinde sola kayar."},{"t":"Daha geniş alan","a":"daha çok tanecik aşar","d":"Eşik solda olduğundan eğrinin altında eşiği aşan bölge (etkin tanecik sayısı) büyür; sıcaklık değişmeden hız artar."}],"ans":"Katalizör aktivasyon enerjisini düşürerek Maxwell-Boltzmann eğrisinde eşiği sola kaydırır; böylece sıcaklık sabitken eşik enerjiyi aşan tanecik oranı artar ve hız büyür."},{"q":"Ara ürün ile katalizör, bir tepkime mekanizmasında nasıl ayırt edilir?","steps":[{"t":"Katalizör","a":"önce girer sonra çıkar","d":"Katalizör ilk basamakta tepken olarak girer, sonraki basamakta ürün olarak geri çıkar; net denklemde yer almaz."},{"t":"Ara ürün","a":"önce oluşur sonra tükenir","d":"Ara ürün ise bir basamakta ürün olarak oluşur, sonraki basamakta tepken olarak tükenir; net denklemde görünmez ama tersi sırayla."}],"ans":"Katalizör mekanizmaya önce girip sonra geri çıkar; ara ürün ise önce oluşup sonra tükenir. İkisi de net denklemde görünmez ama katalizör başta, ara ürün sonra ortaya çıkar."},{"q":"Enzim katalizinde sıcaklık arttıkça hız neden bir noktadan sonra düşer?","steps":[{"t":"Optimum sıcaklık","a":"hız artar","d":"Belirli bir sıcaklığa kadar artan sıcaklıkla tanecik enerjisi ve hız artar (optimum sıcaklık)."},{"t":"Denatürasyon","a":"aktif bölge bozulur","d":"Optimumu aşan sıcaklıkta enzimin protein yapısı bozulur (denatürasyon); aktif bölge şeklini kaybeder ve katalitik etki düşer."}],"ans":"Enzimde sıcaklık optimuma kadar hızı artırır; aşılınca protein yapı denatüre olup aktif bölge bozulduğundan katalitik etki ve hız düşer."},{"q":"Bir tepkimede katalizör hem ileri hem geri hız sabitini eşit oranda artırırsa, denge sabiti K neden sabit kalır?","steps":[{"t":"K tanımı","a":"K = k_ileri / k_geri","d":"Denge sabiti, ileri ve geri hız sabitlerinin oranına eşittir (K = k_ileri / k_geri)."},{"t":"Oran korunur","a":"aynı kat ile çarpılır","d":"Katalizör iki sabiti de aynı kat ile çarptığından oran değişmez; bu yüzden K aynı kalır."}],"ans":"K = k_ileri / k_geri olduğundan, katalizör her iki hız sabitini de aynı oranda artırınca oran (dolayısıyla K) değişmez; denge konumu korunur."}]}},"kutleKorunumu":{"ilkokul":{"kolay":[{"q":"Kapağı sıkıca kapalı bir kapta bir mum yanarsa, yanmadan önce ve sonra kabın toplam ağırlığı değişir mi?","fig":"<svg viewBox='0 0 320 150'><rect x='40' y='40' width='80' height='70' fill='none' stroke='#1a2b45'/><circle cx='80' cy='80' r='10' fill='#e0552b'/><text x='80' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>önce</text><text x='160' y='80' font-size='16' text-anchor='middle' fill='#1a2b45'>=</text><rect x='200' y='40' width='80' height='70' fill='none' stroke='#1a2b45'/><circle cx='240' cy='80' r='10' fill='#5b6b85'/><text x='240' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>sonra</text></svg>","steps":[{"t":"Kapalı kap","a":"hiçbir şey çıkmaz","d":"Kap sıkıca kapalı olduğu için içeriden dışarı hiçbir madde kaçamaz."},{"t":"Sonuç","a":"ağırlık aynı","d":"Madde dışarı çıkmadığı için kabın toplam ağırlığı yanmadan önce ve sonra aynı kalır."}],"ans":"Kapalı kapta madde dışarı çıkamadığı için toplam ağırlık değişmez, aynı kalır."},{"q":"Bir buz parçası kapalı bir kapta eriyip su olunca ağırlığı değişir mi?","steps":[{"t":"Ne değişir","a":"sadece hâl","d":"Buz erirken sadece katıdan sıvıya döner, yani hâl değiştirir."},{"t":"Ağırlık","a":"aynı kalır","d":"Madde miktarı değişmediği için suyun ağırlığı buzun ağırlığıyla aynıdır."}],"ans":"Buz eriyip su olsa da madde kaybolmadığı için ağırlığı değişmez."},{"q":"10 gram tuzu bir bardak suda eritirsek karışımın toplam ağırlığı kaç gram artar?","steps":[{"t":"Tuz kaybolmaz","a":"görünmez ama orada","d":"Tuz suda çözününce gözden kaybolur ama yok olmaz, suyun içinde dağılır."},{"t":"Ağırlık","a":"10 gram artar","d":"Tuz hâlâ orada olduğu için karışımın ağırlığı tam 10 gram artar."}],"ans":"Tuz yok olmadığı için karışımın ağırlığı tam 10 gram artar."},{"q":"Lavoisier adlı bilim insanı kapalı kapta yaptığı deneylerde neyi keşfetmiştir?","steps":[{"t":"Deney","a":"kapalı kapta tartma","d":"Lavoisier maddeleri kapalı kapta tepkimeye sokup önce ve sonra tartmıştır."},{"t":"Keşif","a":"ağırlık aynı","d":"Tepkimeden önceki ve sonraki toplam ağırlığın aynı kaldığını görmüştür."}],"ans":"Lavoisier, kapalı kapta tepkimeden önce ve sonra toplam ağırlığın değişmediğini keşfetmiştir."},{"q":"Bir kâğıdı yakınca geriye az bir kül kalıyor; kâğıdın 'eksilen' kısmı nereye gitti?","steps":[{"t":"Yanma","a":"gaz çıkar","d":"Kâğıt yanarken havaya gözle görülmeyen gazlar ve duman çıkar."},{"t":"Madde kaybolmaz","a":"havaya karıştı","d":"Eksik görünen madde yok olmadı, gaz olarak havaya karıştığı için kül hafif kaldı."}],"ans":"Kâğıdın eksilen kısmı yok olmadı; yanarken gaz olarak havaya karıştığı için geriye az kül kaldı."}],"zor":[{"q":"Açık bir kapta mum yakınca kabın ağırlığı azalıyor gibi görünüyor; bu kütlenin korunumuna aykırı mıdır?","steps":[{"t":"Görünen","a":"hafifleme","d":"Açık kapta mum yanınca kalanlar tartıldığında ağırlık azalmış gibi görünür."},{"t":"Gerçek","a":"gaz kaçtı","d":"Aslında madde yok olmadı; oluşan gazlar açık kaptan havaya kaçtığı için ölçüm eksik çıktı. Çıkan gazlar da hesaba katılırsa kütle korunur."}],"ans":"Hayır aykırı değildir; açık kapta oluşan gazlar havaya kaçtığı için eksik görünür, gazlar da sayılırsa kütle korunur."},{"q":"5 gram demir tozu ile 3 gram kükürt tozu kapalı kapta birleşip yeni bir madde oluşturursa, oluşan maddenin kütlesi kaç gram olur?","fig":"<svg viewBox='0 0 320 150'><rect x='30' y='55' width='55' height='40' fill='#5b6b85' stroke='#1a2b45'/><text x='57' y='115' font-size='11' text-anchor='middle' fill='#1a2b45'>5 g</text><text x='100' y='80' font-size='16' text-anchor='middle' fill='#1a2b45'>+</text><rect x='120' y='55' width='45' height='40' fill='#e0552b' stroke='#1a2b45'/><text x='142' y='115' font-size='11' text-anchor='middle' fill='#1a2b45'>3 g</text><text x='185' y='80' font-size='16' text-anchor='middle' fill='#1a2b45'>→</text><rect x='210' y='55' width='75' height='40' fill='#33415588' stroke='#1a2b45'/><text x='247' y='115' font-size='11' text-anchor='middle' fill='#1a2b45'>8 g</text></svg>","steps":[{"t":"Girenler","a":"5 + 3 gram","d":"Tepkimeye giren maddelerin toplam kütlesi 5 + 3 = 8 gramdır."},{"t":"Korunum","a":"8 gram","d":"Kütle korunduğu için oluşan yeni maddenin kütlesi de tam 8 gram olur."}],"ans":"Kütle korunduğu için oluşan maddenin kütlesi 5 + 3 = 8 gramdır."},{"q":"İçinde gazlı içecek olan kapalı bir şişe ile aynı içeceğin açık bir bardağı; gaz kaçınca hangisinin kütlesi azalır?","fig":"<svg viewBox='0 0 320 150'><rect x='50' y='40' width='50' height='80' rx='6' fill='none' stroke='#1a2b45'/><rect x='62' y='28' width='26' height='14' fill='#5b6b85' stroke='#1a2b45'/><text x='75' y='140' font-size='10' text-anchor='middle' fill='#1a2b45'>kapalı: sabit</text><path d='M210 45 L250 45 L243 120 L217 120 Z' fill='none' stroke='#1a2b45'/><circle cx='225' cy='35' r='3' fill='#2b6be0'/><circle cx='238' cy='28' r='3' fill='#2b6be0'/><circle cx='232' cy='20' r='3' fill='#2b6be0'/><text x='230' y='140' font-size='10' text-anchor='middle' fill='#1a2b45'>açık: azalır</text></svg>","steps":[{"t":"Kapalı şişe","a":"değişmez","d":"Şişe kapalıyken gaz dışarı çıkamaz, bu yüzden toplam kütle değişmez."},{"t":"Açık bardak","a":"azalır","d":"Açık bardakta karbondioksit gazı havaya kaçar, dışarı madde çıktığı için bardağın kütlesi azalır."}],"ans":"Açık bardakta gaz havaya kaçtığı için kütle azalır; kapalı şişede ise kütle değişmez."},{"q":"Bir bitki büyürken ağırlık kazanır; bu ağırlık 'yoktan' mı gelir?","steps":[{"t":"Yoktan değil","a":"madde alır","d":"Bitki büyürken topraktan su ve havadan karbondioksit gibi maddeler alır."},{"t":"Korunum","a":"madde dönüşür","d":"Aldığı bu maddeleri kendi yapısına katarak ağırlık kazanır; madde yoktan oluşmaz, sadece yer değiştirip dönüşür."}],"ans":"Hayır; bitki ağırlığı yoktan kazanmaz, havadan ve topraktan aldığı maddeleri yapısına katarak büyür."},{"q":"Kapalı bir kapta tepkime olduğunda atomlara ne olur; yeni atom oluşur ya da atom yok olur mu?","steps":[{"t":"Atomlar","a":"yok olmaz","d":"Tepkimede hiçbir atom yok olmaz ya da yoktan var olmaz."},{"t":"Yer değiştirir","a":"yeniden dizilir","d":"Atomlar sadece birbirinden ayrılıp yeniden başka biçimde dizilir; sayıları aynı kaldığı için kütle korunur."}],"ans":"Tepkimede atomlar yok olmaz ya da oluşmaz; sadece yeniden dizilir, bu yüzden toplam kütle korunur."}]},"ortaokul":{"kolay":[{"q":"Kütlenin korunumu yasası neyi ifade eder?","steps":[{"t":"Yasa","a":"kütle korunur","d":"Kapalı bir sistemde kimyasal tepkimeye giren maddelerin toplam kütlesi, oluşan ürünlerin toplam kütlesine eşittir."},{"t":"Nedeni","a":"atomlar korunur","d":"Çünkü tepkimede atomlar yok olmaz ya da oluşmaz; yalnızca yeniden düzenlenir."}],"ans":"Kütlenin korunumu yasasına göre kapalı sistemde tepkenlerin toplam kütlesi, ürünlerin toplam kütlesine eşittir."},{"q":"Bu yasayı ilk kez deneyle ortaya koyan bilim insanı kimdir ve nasıl göstermiştir?","steps":[{"t":"Bilim insanı","a":"Lavoisier","d":"Kütlenin korunumu yasasını sistematik deneylerle Antoine Lavoisier ortaya koymuştur."},{"t":"Yöntemi","a":"kapalı kapta tartma","d":"Maddeleri kapalı kaplarda tepkimeye sokup tepkimeden önce ve sonra tartarak toplam kütlenin değişmediğini göstermiştir."}],"ans":"Yasayı Lavoisier, maddeleri kapalı kapta tepkimeye sokup önce ve sonra tartarak göstermiştir."},{"q":"Su, hidrojen ve oksijenden oluşur. 2 g hidrojen, 16 g oksijenle tam tepkimeye girerse kaç gram su oluşur?","fig":"<svg viewBox='0 0 320 150'><text x='160' y='30' font-size='12' text-anchor='middle' fill='#1a2b45'>2H₂ + O₂ → 2H₂O</text><text x='60' y='75' font-size='12' text-anchor='middle' fill='#1a2b45'>2 g</text><text x='105' y='75' font-size='14' text-anchor='middle' fill='#1a2b45'>+</text><text x='150' y='75' font-size='12' text-anchor='middle' fill='#1a2b45'>16 g</text><text x='200' y='75' font-size='14' text-anchor='middle' fill='#e0552b'>=</text><text x='255' y='75' font-size='12' text-anchor='middle' fill='#1a2b45'>18 g</text><text x='160' y='120' font-size='10' text-anchor='middle' fill='#1a2b45'>kütle korunur</text></svg>","steps":[{"t":"Girenler","a":"2 + 16 gram","d":"Tepkimeye giren hidrojen ve oksijenin toplam kütlesi 2 + 16 = 18 gramdır."},{"t":"Korunum","a":"18 gram su","d":"Kütle korunduğu için oluşan suyun kütlesi de 18 gram olur."}],"ans":"Kütle korunduğu için 2 g hidrojen ile 16 g oksijenden 18 g su oluşur."},{"q":"Açık kapta yapılan yanma deneyinde kütle azalmış görünürse, bu yasanın yanlış olduğu mu anlaşılır?","steps":[{"t":"Görünen azalma","a":"gaz kaçışı","d":"Açık kapta oluşan gazlar havaya karıştığı için tartımda kütle eksik görünür."},{"t":"Doğru yorum","a":"yasa geçerli","d":"Kaçan gazlar da hesaba katıldığında kütle korunur; yasa açık kaplarda da geçerlidir, yalnızca ölçüm eksiktir."}],"ans":"Hayır; açık kapta kaçan gazlar tartılmadığı için kütle eksik görünür, gazlar da sayılırsa yasa geçerlidir."},{"q":"Kimyasal tepkimede atom sayısı korunur. 2H₂ + O₂ → 2H₂O tepkimesinde her iki tarafta kaç hidrojen, kaç oksijen atomu vardır?","steps":[{"t":"Sol taraf","a":"4 H, 2 O","d":"2H₂ → 4 hidrojen atomu; O₂ → 2 oksijen atomu bulunur."},{"t":"Sağ taraf","a":"4 H, 2 O","d":"2H₂O → 4 hidrojen ve 2 oksijen atomu içerir; atom sayıları iki tarafta eşittir."}],"ans":"Her iki tarafta da 4 hidrojen ve 2 oksijen atomu vardır; atom sayıları korunmuştur."}],"zor":[{"q":"Kapalı bir kapta 12 g karbon, 32 g oksijenle yanıp CO₂ oluşturuyor. Oluşan CO₂ kaç gramdır ve bu sonuç hangi yasayla bulunur?","steps":[{"t":"Girenler","a":"12 + 32 gram","d":"Tepkimeye giren karbon ve oksijenin toplam kütlesi 12 + 32 = 44 gramdır. Tepkime: C + O₂ → CO₂."},{"t":"Korunum","a":"44 gram","d":"Kütlenin korunumu yasası gereği ürünün kütlesi tepkenlerin toplamına eşittir; CO₂ = 44 gram olur."}],"ans":"C + O₂ → CO₂ tepkimesinde kütle korunumu gereği 12 + 32 = 44 g CO₂ oluşur."},{"q":"Kapalı kapta tepkimeden önce 50 g madde varken, tepkimeden sonra biri 30 g olan iki ürün oluşuyor. Diğer ürün kaç gramdır?","steps":[{"t":"Toplam korunur","a":"50 gram","d":"Kütle korunduğu için ürünlerin toplam kütlesi de tepken kütlesi olan 50 grama eşit olmalıdır."},{"t":"İkinci ürün","a":"20 gram","d":"Bir ürün 30 g ise, diğeri 50 − 30 = 20 gramdır."}],"ans":"Kütle korunduğu için ürünlerin toplamı 50 g olmalıdır; ikinci ürün 50 − 30 = 20 gramdır."},{"q":"CaCO₃ → CaO + CO₂ tepkimesinde 100 g kalsiyum karbonat ısıtılınca 56 g CaO kalıyor. Açığa çıkan CO₂ kaç gramdır?","fig":"<svg viewBox='0 0 320 150'><text x='160' y='28' font-size='12' text-anchor='middle' fill='#1a2b45'>CaCO₃ → CaO + CO₂</text><rect x='40' y='55' width='70' height='45' fill='#cfd8e8' stroke='#1a2b45'/><text x='75' y='118' font-size='11' text-anchor='middle' fill='#1a2b45'>100 g</text><text x='130' y='82' font-size='16' text-anchor='middle' fill='#1a2b45'>→</text><rect x='160' y='55' width='50' height='45' fill='#cfd8e8' stroke='#1a2b45'/><text x='185' y='118' font-size='11' text-anchor='middle' fill='#1a2b45'>56 g</text><text x='230' y='82' font-size='14' text-anchor='middle' fill='#1a2b45'>+</text><text x='265' y='82' font-size='11' text-anchor='middle' fill='#1a2b45'>44 g (gaz)</text></svg>","steps":[{"t":"Giren","a":"100 gram","d":"Tepkimeye giren kalsiyum karbonat 100 gramdır; ürünler CaO ve CO₂'dir."},{"t":"Korunum","a":"44 gram","d":"Kütle korunduğu için CaO + CO₂ = 100 g olmalı; CO₂ = 100 − 56 = 44 gramdır."}],"ans":"Kütle korunumu gereği CaO + CO₂ = 100 g; açığa çıkan CO₂ = 100 − 56 = 44 gramdır."},{"q":"Bir öğrenci 'yanan odun küçülüp hafifliyor, demek ki madde yok oluyor' diyor. Bu görüş kütlenin korunumuyla nasıl çürütülür?","steps":[{"t":"Görünen kayıp","a":"gazlar çıkar","d":"Odun yanarken karbondioksit ve su buharı gibi gazlar açığa çıkıp havaya karışır, geriye az kül kalır."},{"t":"Gerçek","a":"kütle korunur","d":"Çıkan gazların kütlesi de hesaba katılırsa, ürünlerin toplam kütlesi odun ile harcanan oksijenin toplamına eşittir; madde yok olmaz."}],"ans":"Madde yok olmaz; odunun eksilen kütlesi havaya karışan gazlardadır, gazlar sayılırsa tepken ve ürün kütleleri eşittir."},{"q":"Kütlenin korunumu yasası, kimyasal denklemlerin neden 'denkleştirilmesi' gerektiğini nasıl açıklar?","steps":[{"t":"Atom korunumu","a":"sayı sabit","d":"Tepkimede atomlar yok olmaz ya da oluşmaz; her elementin atom sayısı iki tarafta aynı olmalıdır."},{"t":"Denkleştirme","a":"katsayılarla eşitleme","d":"Bu yüzden denklem, katsayılarla her elementin atom sayısı (ve dolayısıyla kütlesi) iki tarafta eşit olacak biçimde denkleştirilir."}],"ans":"Atomlar korunduğu için her elementin sayısı iki tarafta eşit olmalıdır; denklem, kütle korunumunu sağlamak üzere katsayılarla denkleştirilir."}]},"lise":{"kolay":[{"q":"Kütlenin korunumu yasasını ifade ediniz ve atom-altı temelini açıklayınız.","steps":[{"t":"Yasa","a":"toplam kütle sabit","d":"Kapalı bir sistemde gerçekleşen kimyasal tepkimede tepkenlerin toplam kütlesi, ürünlerin toplam kütlesine eşittir; kütle ne oluşur ne yok olur."},{"t":"Atom temeli","a":"atom korunumu","d":"Tepkimede atomlar yaratılmaz ya da yok edilmez; yalnızca bağları kırılıp yeniden kurularak yeniden düzenlenir, böylece toplam atom türü, sayısı ve kütlesi korunur."}],"ans":"Kapalı sistemde tepken ve ürünlerin toplam kütlesi eşittir; çünkü atomlar yok olmaz ya da oluşmaz, yalnızca yeniden düzenlenir."},{"q":"Antoine Lavoisier'in bu yasaya katkısı nedir ve hangi deneysel yaklaşımı belirleyici olmuştur?","steps":[{"t":"Katkı","a":"niceliksel kimya","d":"Lavoisier, kimyada dikkatli tartıma dayalı niceliksel yöntemi yerleştirip kütlenin korunumunu deneysel temele oturtmuştur."},{"t":"Belirleyici yaklaşım","a":"kapalı kapta tartım","d":"Tepkimeleri kapalı kaplarda yürütüp gazların kaçmasını engelleyerek önce ve sonra tartımın eşit olduğunu göstermesi belirleyici olmuştur."}],"ans":"Lavoisier, kapalı kapta dikkatli tartımla tepkimeden önce ve sonra kütlenin değişmediğini göstererek yasayı deneysel temele oturtmuştur."},{"q":"CH₄ + 2O₂ → CO₂ + 2H₂O tepkimesinin kütle korunumuna uyduğunu atom sayımıyla gösteriniz.","fig":"<svg viewBox='0 0 320 130'><text x='160' y='30' font-size='12' text-anchor='middle' fill='#1a2b45'>CH₄ + 2O₂ → CO₂ + 2H₂O</text><text x='90' y='70' font-size='11' text-anchor='middle' fill='#1a2b45'>sol: 1C 4H 4O</text><text x='160' y='70' font-size='13' text-anchor='middle' fill='#e0552b'>=</text><text x='235' y='70' font-size='11' text-anchor='middle' fill='#1a2b45'>sağ: 1C 4H 4O</text></svg>","steps":[{"t":"Sol taraf","a":"1 C, 4 H, 4 O","d":"CH₄ → 1 karbon, 4 hidrojen; 2O₂ → 4 oksijen atomu bulunur."},{"t":"Sağ taraf","a":"1 C, 4 H, 4 O","d":"CO₂ → 1 karbon, 2 oksijen; 2H₂O → 4 hidrojen, 2 oksijen; toplam 1 C, 4 H, 4 O. İki taraf eşittir."}],"ans":"Sol ve sağ tarafta da 1 karbon, 4 hidrojen ve 4 oksijen atomu vardır; denklem denk olduğundan kütle korunur."},{"q":"Kütlenin korunumu yasası ile kimyasal denklemlerin denkleştirilmesi arasındaki ilişki nedir?","steps":[{"t":"Yasa gereği","a":"atom sayısı eşit","d":"Atomlar tepkimede korunduğu için her elementin atom sayısı denklemin iki tarafında eşit olmalıdır."},{"t":"Denkleştirme","a":"katsayı düzenleme","d":"Denkleştirme, formüllerin önüne katsayılar yazarak bu eşitliği sağlamaktır; böylece denklem kütlenin korunumu yasasına uygun hâle gelir."}],"ans":"Atomlar korunduğu için her elementin sayısı iki tarafta eşit olmalıdır; denkleştirme, katsayılarla bu eşitliği kurarak yasayı sağlar."},{"q":"Açık ve kapalı sistemlerde kütle ölçümünün farklı görünmesi yasayla nasıl bağdaştırılır?","steps":[{"t":"Kapalı sistem","a":"madde alışverişi yok","d":"Kapalı sistemde madde dışarı çıkamaz ya da giremez; bu yüzden ölçülen kütle değişmez ve yasa doğrudan gözlenir."},{"t":"Açık sistem","a":"gaz kaçabilir","d":"Açık sistemde gaz çıkışı ya da girişi kütleyi değiştirmiş gibi gösterir; ancak alınan-verilen tüm madde hesaba katılırsa toplam kütle yine korunur."}],"ans":"Kapalı sistemde ölçülen kütle sabittir; açık sistemde gaz alışverişi ölçümü değiştirir, fakat tüm madde sayılırsa yasa her durumda geçerlidir."}],"zor":[{"q":"32 g metan (CH₄) yeterli oksijenle tam yanıyor. Oluşan CO₂ ve H₂O'nun toplam kütlesini kütle korunumuyla bulunuz. (C=12, H=1, O=16)","steps":[{"t":"Mol ve denklem","a":"2 mol CH₄","d":"CH₄ molkütlesi 16 g/mol; 32 g = 2 mol. Tepkime: CH₄ + 2O₂ → CO₂ + 2H₂O, yani 2 mol CH₄ için 4 mol O₂ gerekir."},{"t":"Harcanan O₂","a":"128 g","d":"4 mol O₂ × 32 g/mol = 128 g oksijen harcanır."},{"t":"Korunum","a":"160 g ürün","d":"Kütle korunumu gereği ürünlerin toplamı tepkenlerin toplamına eşittir: 32 g CH₄ + 128 g O₂ = 160 g (CO₂ + H₂O)."}],"ans":"2 mol CH₄ (32 g) 128 g O₂ ile yanar; kütle korunumu gereği oluşan CO₂ ve H₂O toplam 32 + 128 = 160 gramdır."},{"q":"Kapalı kapta 23 g sodyum ile 35,5 g klor tam tepkir. Oluşan NaCl kaç gramdır ve atom korunumuyla nasıl doğrulanır? (Na=23, Cl=35,5)","steps":[{"t":"Denklem ve mol","a":"2Na + Cl₂ → 2NaCl","d":"23 g Na = 1 mol; 35,5 g Cl, yani 0,5 mol Cl₂'ye karşılık gelir ve 1 mol Na ile tam tepkir."},{"t":"Korunum","a":"58,5 gram","d":"Kütle korunduğu için oluşan NaCl = 23 + 35,5 = 58,5 gramdır (1 mol NaCl = 58,5 g, tutarlı)."},{"t":"Atom kontrolü","a":"atomlar eşit","d":"Giren 1 mol Na ve 1 mol Cl atomu, ürün 1 mol NaCl içinde aynen yer alır; atom sayısı korunmuştur."}],"ans":"Kütle korunumu gereği 23 + 35,5 = 58,5 g NaCl oluşur; giren Na ve Cl atomları ürün içinde korunduğundan sonuç doğrulanır."},{"q":"Bir öğrenci kapalı kapta gaz çıkaran bir tepkime sonrası kabı tarttığında kütlenin sabit kaldığını, kapağı açıp gaz çıkınca azaldığını gözlüyor. Bu durum yasaya aykırı mı?","steps":[{"t":"Kapalı durum","a":"kütle sabit","d":"Kapak kapalıyken oluşan gaz da kabın içinde kaldığından toplam kütle korunur ve değişmez."},{"t":"Kapak açılınca","a":"gaz sistemden çıkar","d":"Kapak açılınca gaz çevreye geçer; bu, sistemin kütle kaybetmesi değil, gazın artık ölçülen sistemin dışına çıkmasıdır. Tüm madde sayılırsa kütle yine korunur."}],"ans":"Aykırı değildir; kapalıyken gaz da sistemde olduğundan kütle sabittir, kapak açılınca gaz sistem dışına çıktığı için ölçüm azalır, oysa toplam madde korunmuştur."},{"q":"Nükleer tepkimelerde kütlenin bir kısmı enerjiye dönüşebilir; bu, kimyasal tepkimelerdeki kütle korunumu yasasıyla nasıl bağdaştırılır?","steps":[{"t":"Kimyasal tepkime","a":"kütle korunur","d":"Kimyasal tepkimelerde yalnızca elektron düzenlenmesi olur; kütle değişimi ölçülemeyecek kadar küçüktür, bu yüzden kütle pratikte tam korunur."},{"t":"Nükleer tepkime","a":"kütle-enerji","d":"Çekirdeğin değiştiği nükleer tepkimelerde belirgin bir kütle, E = mc² uyarınca enerjiye dönüşür; bu, kimyasal değil nükleer bir süreçtir, dolayısıyla kimyasal kütle korunumu yasasını çürütmez."}],"ans":"Kimyasal tepkimelerde kütle pratikte tam korunur; kütlenin enerjiye dönüşmesi yalnızca nükleer süreçlerde belirgindir ve kimyasal kütle korunumu yasasının kapsamı dışındadır."},{"q":"Sınırlayıcı bileşen içeren bir tepkimede bir tepken artarsa, kütlenin korunumu hâlâ geçerli midir? 4 g H₂ ile 40 g O₂ tepkimesini düşününüz. (H=1, O=16)","steps":[{"t":"Sınırlayıcıyı bul","a":"H₂ sınırlayıcı","d":"2H₂ + O₂ → 2H₂O. 4 g H₂ = 2 mol H₂, bunun için 1 mol (32 g) O₂ gerekir; 40 g O₂ olduğundan 8 g O₂ artar, H₂ sınırlayıcıdır."},{"t":"Oluşan su","a":"36 g su","d":"2 mol H₂ ile 1 mol O₂ tepkiyip 2 mol (36 g) su oluşturur."},{"t":"Korunum","a":"toplam 44 g","d":"Sistemin başlangıç kütlesi 4 + 40 = 44 g; sonunda 36 g su + 8 g artan O₂ = 44 g. Kütle korunmuştur."}],"ans":"Evet geçerlidir; H₂ sınırlayıcıdır, 36 g su oluşur ve 8 g O₂ artar, toplam 36 + 8 = 44 g başlangıçtaki 4 + 40 = 44 g'a eşittir."}]}},"maxwellBoltzmann":{"ilkokul":{"kolay":[{"q":"Bir sınıftaki çocukların hepsi tam olarak aynı hızda mı koşar?","steps":[{"t":"Farklı hızlar","a":"hayır","d":"Bazı çocuklar hızlı, bazıları yavaş koşar; hepsi aynı değildir."},{"t":"Tanecikler de öyle","a":"farklı hız","d":"Maddedeki tanecikler de farklı hızlarda hareket eder, hepsi aynı enerjide değildir."}],"ans":"Hayır; herkes <b>farklı hızda</b> koşar."},{"q":"Bir kovadaki suyu ısıtırsak içindeki küçük tanecikler nasıl hareket eder?","steps":[{"t":"Isı verince","a":"hızlanır","d":"Su ısındıkça içindeki tanecikler daha <b>hızlı</b> hareket eder."},{"t":"Soğursa","a":"yavaşlar","d":"Soğuyunca tanecikler yavaşlar."}],"ans":"Isınınca tanecikler daha <b>hızlı</b> hareket eder."},{"q":"Bir grup arıdan bazıları yavaş, bazıları çok hızlı uçar. Maddedeki tanecikler için de benzer ne söylenir?","fig":"<svg viewBox='0 0 220 90'><rect x='0' y='0' width='220' height='90' fill='#f5f7fa'/><circle cx='40' cy='30' r='6' fill='#2b6be0'/><path d='M46 30 L70 30' stroke='#1a2b45' stroke-width='2'/><circle cx='40' cy='60' r='6' fill='#2b6be0'/><path d='M46 60 L120 60' stroke='#e0552b' stroke-width='2'/><text x='150' y='34' fill='#1a2b45' font-size='11'>yavaş</text><text x='150' y='64' fill='#e0552b' font-size='11'>hızlı</text></svg>","steps":[{"t":"Arılar","a":"farklı hız","d":"Arıların kimi yavaş kimi hızlı uçar, hepsi aynı değildir."},{"t":"Tanecik","a":"farklı enerji","d":"Tanecikler de farklı hızlarda, yani farklı <b>enerjilerde</b> olur."}],"ans":"Tanecikler de <b>farklı hızlarda</b> hareket eder."},{"q":"Bir maddeyi ısıttığımızda tanecikleri yavaşlar mı yoksa hızlanır mı?","steps":[{"t":"Isı","a":"enerji verir","d":"Isı maddeye enerji katar."},{"t":"Sonuç","a":"hızlanır","d":"Tanecikler bu enerjiyle daha <b>hızlı</b> hareket eder."}],"ans":"Isıtınca tanecikler <b>hızlanır</b>."},{"q":"Çok hızlı koşan çocukların engeli atlaması daha mı kolaydır?","steps":[{"t":"Hızlı koşan","a":"kolay atlar","d":"Hızlı koşan bir çocuk önündeki küçük engeli daha kolay atlar."},{"t":"Tanecikte","a":"hızlı olan tepkir","d":"Tanecikler de yeterince hızlıysa engeli (eşiği) aşıp tepkimeye girebilir."}],"ans":"Evet; hızlı (enerjik) olanlar engeli daha kolay aşar."}],"zor":[{"q":"Bir maddeyi ısıttığımızda neden daha çok tanecik tepkimeye girebilir hâle gelir?","steps":[{"t":"Isı","a":"hızlandırır","d":"Isı verince tanecikler daha hızlı, daha enerjik olur."},{"t":"Engeli aşmak","a":"kolaylaşır","d":"Daha çok tanecik tepkime için gereken engeli (eşik enerjiyi) aşar."},{"t":"Sonuç","a":"daha çok tepkir","d":"Böylece daha <b>çok</b> tanecik tepkimeye girer, tepkime hızlanır."}],"ans":"Isınınca daha çok tanecik <b>eşiği aşar</b>."},{"q":"Hepsi farklı hızda koşan bir grupta sadece çok hızlı koşanlar yüksek bir duvarı atlayabiliyor. Bu, tepkimedeki neye benzer?","steps":[{"t":"Yüksek duvar","a":"eşik","d":"Yüksek duvar, aşılması gereken eşik enerjiye benzer."},{"t":"Hızlılar atlar","a":"yeterli enerji","d":"Yalnızca yeterince hızlı, yani <b>enerjik</b> olanlar duvarı atlayabilir."},{"t":"Tanecikte","a":"enerjik olan tepkir","d":"Sadece yeterince enerjili tanecikler tepkimeye girer."}],"ans":"Sadece <b>yeterli enerjili</b> tanecikler eşiği aşıp tepkir."},{"q":"Soğuk bir günde reçel kavanozunun kapağını açmak neden daha zordur, bu taneciklerle nasıl ilişkilidir?","steps":[{"t":"Soğukta","a":"yavaş tanecik","d":"Soğukta tanecikler yavaş hareket eder, az enerjiklidir."},{"t":"Isıtınca","a":"hızlanır","d":"Sıcak suya tutunca tanecikler hızlanır ve madde biraz genleşir."},{"t":"Bağlantı","a":"enerji artar","d":"Sıcaklık artınca taneciklerin <b>enerjisi</b> artar; bu, tepkimeleri de kolaylaştırır."}],"ans":"Isı tanecik <b>enerjisini</b> artırır; soğukta enerji azdır."},{"q":"Bir tencere suyu yüksek ateşte mi yoksa kısık ateşte mi daha çabuk kaynar ve neden?","steps":[{"t":"Yüksek ateş","a":"çok enerji","d":"Yüksek ateş suya daha çok enerji verir."},{"t":"Tanecik hızı","a":"artar","d":"Tanecikler daha hızlı hareket eder, daha çoğu yüksek enerjiye ulaşır."},{"t":"Sonuç","a":"çabuk kaynar","d":"Bu yüzden su yüksek ateşte daha <b>çabuk</b> kaynar."}],"ans":"<b>Yüksek ateşte</b>; tanecikler daha çok enerji alır."},{"q":"İki özdeş madde örneğinden biri sıcak, biri soğukken hangisinde tepkime daha hızlı olur?","steps":[{"t":"Sıcak örnek","a":"hızlı tanecik","d":"Sıcak örnekteki tanecikler daha hızlı ve enerjiktir."},{"t":"Eşik","a":"daha çok aşar","d":"Daha çok tanecik tepkime eşiğini aşar."},{"t":"Sonuç","a":"sıcakta hızlı","d":"Tepkime <b>sıcak</b> örnekte daha hızlı gerçekleşir."}],"ans":"<b>Sıcak</b> örnekte tepkime daha hızlıdır."}]},"ortaokul":{"kolay":[{"q":"Bir maddedeki taneciklerin enerjileri hep aynı mıdır?","steps":[{"t":"Enerji çeşitliliği","a":"farklı","d":"Tanecikler sürekli çarpışıp enerji alışverişi yaptığından enerjileri <b>farklıdır</b>."},{"t":"Dağılım","a":"geniş aralık","d":"Çok yavaştan çok hızlıya kadar geniş bir enerji dağılımı vardır."}],"ans":"Hayır; taneciklerin enerjileri <b>farklıdır</b>."},{"q":"Maxwell-Boltzmann dağılımı neyi gösterir?","steps":[{"t":"Tanım","a":"enerji dağılımı","d":"Bir maddedeki taneciklerin sahip olduğu enerjilerin nasıl dağıldığını gösteren eğridir."},{"t":"Bilgi","a":"kaç tanecik hangi enerjide","d":"Hangi enerjide kaç tanecik bulunduğunu görmemizi sağlar."}],"ans":"Taneciklerin <b>enerji dağılımını</b> gösterir."},{"q":"Sıcaklık artınca Maxwell-Boltzmann eğrisi nasıl değişir?","steps":[{"t":"Sıcaklık ↑","a":"eğri sağa kayar","d":"Sıcaklık artınca eğrinin tepesi alçalır ve sağa, yüksek enerjilere doğru kayar."},{"t":"Sonuç","a":"yüksek enerjili çok","d":"Yüksek enerjili tanecik sayısı <b>artar</b>."}],"ans":"Eğri <b>sağa kayar</b>, yüksek enerjili tanecik artar."},{"q":"Sıcaklık artışı tepkime hızını eğri üzerinden nasıl açıklar?","steps":[{"t":"Sağa kayma","a":"Ea'yı aşan artar","d":"Eğri sağa kayınca aktivasyon enerjisini aşan tanecik oranı artar."},{"t":"Sonuç","a":"hız ↑","d":"Daha çok tanecik eşiği aştığı için tepkime <b>hızlanır</b>."}],"ans":"Ea'yı aşan tanecik artar, tepkime <b>hızlanır</b>."},{"q":"Eğrinin tepe noktası neyi gösterir?","steps":[{"t":"Tepe","a":"en çok tanecik","d":"Tepe noktası, en fazla taneciğin sahip olduğu enerjiyi (en olası enerjiyi) gösterir."},{"t":"Anlam","a":"yaygın enerji","d":"Yani taneciklerin çoğunun bu enerji civarında olduğunu belirtir."}],"ans":"En çok taneciğin sahip olduğu <b>en olası enerjiyi</b> gösterir."}],"zor":[{"q":"Maxwell-Boltzmann eğrisinde aktivasyon enerjisi (Ea) çizgisi nasıl yorumlanır?","fig":"<svg viewBox='0 0 240 120'><rect x='0' y='0' width='240' height='120' fill='#f5f7fa'/><path d='M20 100 Q70 20 120 50 Q170 80 220 95' fill='none' stroke='#1a2b45' stroke-width='3'/><line x1='170' y1='100' x2='170' y2='30' stroke='#e0552b' stroke-width='2'/><text x='150' y='25' fill='#e0552b' font-size='12'>Ea</text><text x='185' y='90' fill='#1a2b45' font-size='10'>aşan</text></svg>","steps":[{"t":"Ea çizgisi","a":"dikey sınır","d":"Ea, eğri üzerine çizilen dikey bir çizgiyle gösterilir."},{"t":"Sağdaki alan","a":"tepkir tanecik","d":"Çizginin <b>sağında</b> kalan alan, enerjisi Ea'yı aşan ve tepkimeye girebilecek tanecikleri temsil eder."}],"ans":"Ea çizgisinin <b>sağındaki alan</b> tepkimeye girebilecek tanecikleri gösterir."},{"q":"Sıcaklık artırıldığında eğri altındaki toplam alan neden değişmez ama tepe alçalır?","fig":"<svg viewBox='0 0 240 120'><rect x='0' y='0' width='240' height='120' fill='#f5f7fa'/><path d='M20 105 Q55 25 95 55 Q150 100 228 104 L20 105 Z' fill='#2b6be022' stroke='#2b6be0' stroke-width='2'/><path d='M20 105 Q80 50 130 65 Q175 85 228 100' fill='none' stroke='#e0552b' stroke-width='2' stroke-dasharray='5 3'/><text x='70' y='90' fill='#1a2b45' font-size='10'>alan = tanecik sayısı</text></svg>","steps":[{"t":"Toplam alan","a":"tanecik sayısı","d":"Eğri altındaki toplam alan toplam tanecik sayısını verir; bu sayı sabittir."},{"t":"Tepe alçalır–genişler","a":"yayılma","d":"Sıcaklıkla enerjiler daha geniş bir aralığa yayılır; tepe alçalır ve eğri sağa doğru genişler."},{"t":"Sonuç","a":"alan korunur","d":"Tanecik sayısı değişmediğinden toplam alan <b>korunur</b>."}],"ans":"Tanecik sayısı sabit kaldığından <b>toplam alan korunur</b>; sadece dağılım yayılır."},{"q":"Katalizör eklemenin Maxwell-Boltzmann eğrisindeki etkisi nedir?","steps":[{"t":"Eğri","a":"değişmez","d":"Katalizör taneciklerin enerji dağılımını (eğriyi) değiştirmez."},{"t":"Ea çizgisi","a":"sola kayar","d":"Katalizör Ea'yı düşürdüğü için dikey Ea çizgisi sola kayar."},{"t":"Sonuç","a":"aşan tanecik ↑","d":"Eğri sabit kalsa da Ea sola kaydığından eşiği aşan tanecik oranı <b>artar</b>."}],"ans":"Eğri sabit kalır, <b>Ea çizgisi sola kayar</b>; aşan tanecik artar."},{"q":"Sıcaklık az miktar arttığında bile tepkime hızının belirgin artmasını eğri üzerinden açıklayın.","steps":[{"t":"Sağa kayma","a":"yüksek enerji ucu","d":"Sıcaklık artışı eğriyi sağa kaydırır; özellikle yüksek enerjili (Ea'yı aşan) bölge belirgin büyür."},{"t":"Aşan oran","a":"katlanarak artar","d":"Ea'yı aşan tanecik oranı küçük sıcaklık artışıyla bile büyük oranda artar."},{"t":"Sonuç","a":"hız belirgin ↑","d":"Bu yüzden hız küçük sıcaklık değişiminde bile <b>belirgin</b> artar."}],"ans":"Ea'yı aşan tanecik oranı belirgin büyüdüğü için <b>hız belirgin artar</b>."},{"q":"İki özdeş örnekten biri 25 °C, diğeri 60 °C ise eğri ve Ea'yı aşan tanecik açısından karşılaştırın.","steps":[{"t":"60 °C eğrisi","a":"daha sağda","d":"Sıcak örneğin eğrisi daha alçak tepeli ve daha sağda yer alır."},{"t":"Ea'yı aşan","a":"60 °C'de çok","d":"Aynı Ea çizgisinin sağında kalan alan 60 °C örneğinde daha büyüktür."},{"t":"Sonuç","a":"60 °C hızlı","d":"60 °C örneğinde daha çok tanecik tepkir; tepkime <b>daha hızlıdır</b>."}],"ans":"60 °C örneğinde eğri sağda, Ea'yı aşan tanecik <b>daha çok</b>; tepkime hızlıdır."}]},"lise":{"kolay":[{"q":"Maxwell-Boltzmann enerji dağılımı neyi ifade eder?","steps":[{"t":"Tanım","a":"enerji dağılımı eğrisi","d":"Belirli sıcaklıkta bir gazdaki taneciklerin kinetik enerjilerinin nasıl dağıldığını gösterir."},{"t":"Eksenler","a":"enerji – tanecik sayısı","d":"Yatay eksen tanecik enerjisi, dikey eksen o enerjideki tanecik sayısıdır."}],"ans":"Taneciklerin <b>kinetik enerji dağılımını</b> gösterir."},{"q":"Eğrinin temel biçimsel özellikleri nelerdir?","fig":"<svg viewBox='0 0 240 120'><rect x='0' y='0' width='240' height='120' fill='#f5f7fa'/><line x1='20' y1='105' x2='230' y2='105' stroke='#1a2b45' stroke-width='2'/><line x1='20' y1='105' x2='20' y2='15' stroke='#1a2b45' stroke-width='2'/><path d='M20 105 Q55 25 95 55 Q150 100 228 104' fill='none' stroke='#2b6be0' stroke-width='3'/><text x='150' y='118' fill='#1a2b45' font-size='10'>enerji</text></svg>","steps":[{"t":"Başlangıç","a":"orijinden çıkar","d":"Sıfır enerjili tanecik yoktur; eğri orijinden başlar."},{"t":"Kuyruk","a":"sağa uzanır","d":"Eğrinin yüksek enerjili ucu uzun bir kuyruk yapar ve eksene asla değmez."}],"ans":"Orijinden çıkar, tepe yapar ve sağa doğru <b>uzun kuyruk</b> ile devam eder."},{"q":"Sıcaklık artışının Maxwell-Boltzmann eğrisine etkisi nedir?","fig":"<svg viewBox='0 0 240 120'><rect x='0' y='0' width='240' height='120' fill='#f5f7fa'/><path d='M20 105 Q60 25 100 55 Q150 95 220 102' fill='none' stroke='#1a2b45' stroke-width='3'/><path d='M20 105 Q80 50 130 65 Q175 80 220 95' fill='none' stroke='#e0552b' stroke-width='3' stroke-dasharray='5 3'/><text x='30' y='40' fill='#1a2b45' font-size='10'>T₁</text><text x='110' y='55' fill='#e0552b' font-size='10'>T₂&gt;T₁</text></svg>","steps":[{"t":"Tepe","a":"alçalır","d":"Sıcaklık artınca eğrinin tepesi alçalır."},{"t":"Kayma","a":"sağa","d":"Eğri sağa kayar; yüksek enerjili tanecik oranı artar."}],"ans":"Tepe alçalır, eğri <b>sağa kayar</b>; yüksek enerjili tanecik oranı artar."},{"q":"Eğri altında kalan toplam alan neyi temsil eder?","steps":[{"t":"Toplam alan","a":"tanecik sayısı","d":"Eğri altındaki toplam alan örnekteki toplam tanecik sayısına eşittir."},{"t":"Sabitlik","a":"değişmez","d":"Sıcaklık değişse de tanecik sayısı sabit kaldığından toplam alan değişmez."}],"ans":"Örnekteki <b>toplam tanecik sayısını</b> temsil eder."},{"q":"Ea çizgisinin sağındaki alan tepkime hızıyla nasıl ilişkilidir?","steps":[{"t":"Sağ alan","a":"tepkir tanecik","d":"Ea çizgisinin sağındaki alan, enerjisi eşiği aşan tanecik sayısını verir."},{"t":"İlişki","a":"alan ↑ → hız ↑","d":"Bu alan büyüdükçe etkin çarpışma çoğalır, tepkime hızı artar."}],"ans":"Bu alan büyüdükçe tepkime hızı <b>artar</b>."}],"zor":[{"q":"Sıcaklık artışında çarpışma sıklığı az değiştiği hâlde hızın katlanarak artmasını Maxwell-Boltzmann dağılımı nasıl açıklar?","steps":[{"t":"Çarpışma sıklığı","a":"~√T ile az artar","d":"Çarpışma sıklığı taneciklerin ortalama hızıyla (kabaca √T ile) görece az artar."},{"t":"Kuyruk alanı","a":"hızla büyür","d":"Sıcaklık artınca dağılımın Ea'yı aşan kuyruk alanı çok daha keskin büyür."},{"t":"Sonuç","a":"etkin çarpışma fırlar","d":"Hızdaki büyük artış, esas olarak <b>Ea'yı aşan tanecik oranının</b> katlanarak artmasından gelir."}],"ans":"Asıl etki çarpışma sıklığı değil, <b>Ea'yı aşan tanecik oranının</b> keskin artışıdır."},{"q":"Katalizör ve sıcaklık artışı, Ea'yı aşan tanecik sayısını artırırken eğri üzerinde nasıl farklı davranır?","fig":"<svg viewBox='0 0 240 120'><rect x='0' y='0' width='240' height='120' fill='#f5f7fa'/><path d='M20 105 Q60 25 100 55 Q160 100 228 104' fill='none' stroke='#1a2b45' stroke-width='3'/><line x1='150' y1='105' x2='150' y2='35' stroke='#e0552b' stroke-width='2'/><text x='130' y='30' fill='#e0552b' font-size='11'>Ea</text><line x1='110' y1='105' x2='110' y2='50' stroke='#5b6b85' stroke-width='2' stroke-dasharray='4 3'/><text x='80' y='48' fill='#5b6b85' font-size='10'>Ea(kat.)</text></svg>","steps":[{"t":"Sıcaklık artışı","a":"eğriyi değiştirir","d":"Sıcaklık artışı dağılım eğrisini değiştirir: tepe alçalır, eğri sağa kayar."},{"t":"Katalizör","a":"eğriyi değiştirmez","d":"Katalizör eğriyi değiştirmez; yalnızca Ea çizgisini sola kaydırır."},{"t":"Ortak sonuç","a":"aşan tanecik ↑","d":"İki yöntem de farklı mekanizmayla <b>Ea'yı aşan tanecik oranını</b> artırır."}],"ans":"Sıcaklık <b>eğriyi</b> değiştirir, katalizör <b>Ea çizgisini</b> kaydırır; ikisi de aşan taneciği artırır."},{"q":"Bir tepkimenin Ea'sı çok yüksekse, Maxwell-Boltzmann dağılımına göre oda sıcaklığında neden çok yavaş ilerler?","steps":[{"t":"Yüksek Ea","a":"çok sağda","d":"Ea çizgisi eğrinin çok sağında, yüksek enerjili bölgede yer alır."},{"t":"Aşan alan","a":"çok küçük","d":"Çizginin sağında kalan alan (eşiği aşan tanecik oranı) çok küçüktür."},{"t":"Sonuç","a":"çok az etkin çarpışma","d":"Herhangi anda çok az tanecik tepkir; bu nedenle tepkime <b>çok yavaştır</b>."}],"ans":"Ea'yı aşan tanecik oranı <b>çok küçük</b> olduğundan çok az etkin çarpışma olur."},{"q":"İki gazdan birinin sıcaklığı artırıldığında ortalama enerji ile en olası enerji (tepe) arasındaki ilişki nasıl değişir?","steps":[{"t":"Tepe konumu","a":"en olası enerji","d":"Eğrinin tepesi en olası (en çok taneciğin sahip olduğu) enerjiyi verir."},{"t":"Sıcaklık ↑","a":"ikisi de sağa","d":"Sıcaklık artınca hem en olası enerji hem ortalama enerji artar (sağa kayar)."},{"t":"İlişki","a":"ortalama > en olası","d":"Kuyruk asimetrik olduğundan ortalama enerji daima en olası enerjiden biraz <b>büyüktür</b>; sıcaklıkla aradaki fark da büyür."}],"ans":"İkisi de sağa kayar; ortalama enerji en olası enerjiden <b>büyük</b> kalır, fark artar."},{"q":"Aynı sıcaklıktaki iki tepkimeden A'nın Ea'sı küçük, B'nin Ea'sı büyükse Maxwell-Boltzmann dağılımı üzerinde hangisinin daha çok tanecikle tepkidiğini açıklayın.","steps":[{"t":"Tek eğri","a":"aynı sıcaklık","d":"Aynı sıcaklıkta tanecikler tek bir enerji dağılımı eğrisi üzerinde temsil edilir."},{"t":"Ea çizgileri","a":"A solda, B sağda","d":"A'nın küçük Ea çizgisi solda, B'nin büyük Ea çizgisi sağdadır."},{"t":"Aşan alan","a":"A büyük","d":"Sol çizginin (A) sağındaki alan daha büyüktür; A'da daha çok tanecik eşiği aşar."}],"ans":"<b>A</b> tepkimesinde; küçük Ea çizgisinin sağındaki alan daha büyüktür."}]}},"mekanizma":{"ilkokul":{"kolay":[{"q":"Bir tepkime tek bir anda mı olur, yoksa adım adım mı gerçekleşir?","steps":[{"t":"Tek anda değil","a":"adımlar var","d":"Çoğu tepkime tek seferde değil, küçük adımlar halinde olur."},{"t":"Sıra ile","a":"basamak basamak","d":"Tıpkı merdiven çıkar gibi tepkime basamak basamak ilerler."}],"ans":"Bir tepkime çoğu zaman tek anda değil, adım adım (basamaklar halinde) gerçekleşir."},{"q":"Tepkimenin adım adım gerçekleşme sırasına ne ad verilir?","steps":[{"t":"Adımların sırası","a":"yol","d":"Tepkimenin hangi adımlardan geçtiğinin sırasıdır."},{"t":"Adı","a":"mekanizma","d":"Bu adım adım gerçekleşme yoluna tepkime mekanizması denir."}],"ans":"Tepkimenin adım adım gerçekleşme yoluna mekanizma denir."},{"q":"Bir trende en yavaş vagon tüm trenin hızını belirler. Tepkimede de en yavaş adım neyi belirler?","fig":"<svg viewBox='0 0 320 130'><rect x='30' y='55' width='50' height='35' rx='5' fill='#2b6be0' stroke='#1a2b45'/><rect x='95' y='55' width='50' height='35' rx='5' fill='#e0552b' stroke='#1a2b45'/><rect x='160' y='55' width='50' height='35' rx='5' fill='#2b6be0' stroke='#1a2b45'/><circle cx='45' cy='95' r='6' fill='#1a2b45'/><circle cx='65' cy='95' r='6' fill='#1a2b45'/><circle cx='175' cy='95' r='6' fill='#1a2b45'/><circle cx='195' cy='95' r='6' fill='#1a2b45'/><circle cx='110' cy='95' r='6' fill='#1a2b45'/><circle cx='130' cy='95' r='6' fill='#1a2b45'/><text x='120' y='40' font-size='10' text-anchor='middle' fill='#1a2b45'>en yavaş vagon</text></svg>","steps":[{"t":"En yavaş adım","a":"frenler","d":"Adımlardan biri çok yavaşsa, tüm tepkime onun hızında ilerler."},{"t":"Sonuç","a":"toplam hız","d":"En yavaş adım tepkimenin toplam hızını belirler."}],"ans":"En yavaş adım, tüm tepkimenin hızını belirler."},{"q":"Bir adımda oluşup hemen sonraki adımda kullanılan, sonunda kalmayan maddeye ne benzetebiliriz?","steps":[{"t":"Geçici madde","a":"ortada görünmez","d":"Bir adımda oluşan, sonraki adımda harcanan geçici bir madde vardır."},{"t":"Ara ürün","a":"sonunda yok","d":"Bu geçici maddeye ara ürün denir; tepkime bitince ortada kalmaz."}],"ans":"Bir adımda oluşup sonraki adımda harcanan geçici maddeye ara ürün denir; sonunda kalmaz."},{"q":"Bir köprüyü inşa edip iş bitince geri toplayan vinç gibi, tepkimeye girip sonra geri çıkan yardımcı maddeye ne denir?","steps":[{"t":"Girip çıkar","a":"yardımcı","d":"Bu madde tepkimeye girer, yardım eder, sonra yeniden dışarı çıkar."},{"t":"Adı","a":"katalizör","d":"Girip sonra geri çıkan bu yardımcı maddeye katalizör denir."}],"ans":"Tepkimeye girip sonra geri çıkan yardımcı maddeye katalizör denir."}],"zor":[{"q":"Tepkime basamaklarından biri çok yavaş, biri çok hızlıysa tepkime ne kadar sürede biter?","steps":[{"t":"Yavaş belirleyici","a":"yavaş adım","d":"Tepkimenin toplam süresini en yavaş adım belirler."},{"t":"Sonuç","a":"yavaş adıma bağlı","d":"Hızlı adım ne kadar çabuk olursa olsun, yavaş adım bitmeden tepkime tamamlanmaz."}],"ans":"Tepkime, en yavaş basamağın süresince tamamlanır; hızlı adımlar bunu değiştirmez."},{"q":"Ara ürün ile katalizör arasındaki en basit fark nedir?","steps":[{"t":"Ara ürün","a":"oluşur, tükenir","d":"Ara ürün önce bir adımda oluşur, sonra başka adımda harcanır."},{"t":"Katalizör","a":"girer, çıkar","d":"Katalizör ise önce tepkimeye girer, sonra geri çıkar; tükenmez."}],"ans":"Ara ürün önce oluşup sonra tükenir; katalizör ise önce girip sonra geri çıkar ve tükenmez."},{"q":"Bir pasta yaparken hamuru karıştırmak çok hızlı, fırında pişirmek çok yavaşsa, pasta ne zaman hazır olur?","steps":[{"t":"En yavaş iş","a":"pişirme","d":"En yavaş adım fırında pişirmektir."},{"t":"Toplam süre","a":"pişirmeye bağlı","d":"Pasta, en yavaş adım olan pişirme tamamlanınca hazır olur."}],"ans":"Pasta, en yavaş adım olan pişirme bitince hazır olur; en yavaş adım toplam süreyi belirler."},{"q":"Bir tepkime iki adımda olduğunda, ilk adımda çıkan ürün hemen ikinci adımda kullanılırsa bu maddeye ne denir?","steps":[{"t":"İlk adım ürünü","a":"hemen kullanılır","d":"İlk adımda oluşan madde beklemeden ikinci adımda harcanır."},{"t":"Ara ürün","a":"adı budur","d":"Bu şekilde oluşup hemen tüketilen maddeye ara ürün denir."}],"ans":"İlk adımda oluşup ikinci adımda hemen kullanılan bu maddeye ara ürün denir."},{"q":"Tepkime mekanizmasını bilmek bize ne işe yarar?","steps":[{"t":"Adımları görme","a":"nasıl olduğu","d":"Mekanizma, tepkimenin hangi adımlarla gerçekleştiğini gösterir."},{"t":"Hızı anlama","a":"yavaş adım","d":"Hangi adımın yavaş olduğunu bilince tepkimeyi nasıl hızlandıracağımızı anlarız."}],"ans":"Mekanizmayı bilmek, tepkimenin nasıl olduğunu ve hangi adımı hızlandırırsak hızlanacağını anlamamızı sağlar."}]},"ortaokul":{"kolay":[{"q":"Tepkime mekanizması ne anlama gelir?","steps":[{"t":"Basamaklar","a":"adım adım","d":"Çoğu tepkime tek hamlede değil, birbirini izleyen küçük basamaklar halinde gerçekleşir."},{"t":"Tanım","a":"basamaklar dizisi","d":"Bu basamakların tamamına ve sırasına tepkime mekanizması denir."}],"ans":"Tepkime mekanizması, bir tepkimenin gerçekleştiği basamakların tamamı ve sırasıdır."},{"q":"Hız belirleyen basamak hangisidir?","fig":"<svg viewBox='0 0 320 165'><rect x='40' y='110' width='50' height='40' fill='#2b6be0' stroke='#1a2b45'/><rect x='130' y='40' width='50' height='110' fill='#e0552b' stroke='#1a2b45'/><rect x='220' y='100' width='50' height='50' fill='#2b6be0' stroke='#1a2b45'/><text x='65' y='135' font-size='10' text-anchor='middle' fill='#fff'>hızlı</text><text x='155' y='95' font-size='10' text-anchor='middle' fill='#fff'>yavaş</text><text x='245' y='130' font-size='10' text-anchor='middle' fill='#fff'>hızlı</text></svg>","steps":[{"t":"En yavaş adım","a":"belirleyici","d":"Mekanizmadaki en yavaş basamak tüm tepkimenin hızını belirler."},{"t":"Adı","a":"hız belirleyen basamak","d":"Bu en yavaş basamağa hız belirleyen basamak denir."}],"ans":"Mekanizmadaki en yavaş basamak hız belirleyen basamaktır; tüm tepkimenin hızını o belirler."},{"q":"Ara ürün nedir?","steps":[{"t":"Oluşma","a":"bir basamakta","d":"Ara ürün, bir basamakta oluşan bir maddedir."},{"t":"Tükenme","a":"sonraki basamakta","d":"Sonraki basamakta tükendiği için net tepkime denkleminde görünmez."}],"ans":"Ara ürün, bir basamakta oluşup sonraki basamakta tükenen ve net denklemde görünmeyen maddedir."},{"q":"Katalizör mekanizmada nasıl davranır?","steps":[{"t":"Önce girer","a":"tepken gibi","d":"Katalizör ilk basamakta tepken olarak tepkimeye girer."},{"t":"Sonra çıkar","a":"geri kazanılır","d":"Sonraki basamakta tekrar açığa çıkar, böylece net olarak tükenmez."}],"ans":"Katalizör mekanizmada önce tepkimeye girer, sonra geri çıkar; net olarak tükenmez."},{"q":"Neden en yavaş basamak tepkimenin toplam hızını belirler?","steps":[{"t":"Darboğaz","a":"en yavaş geçit","d":"En yavaş basamak bir darboğaz gibidir; tepkime bu adımdan daha hızlı ilerleyemez."},{"t":"Sonuç","a":"hız ona bağlı","d":"Hızlı basamaklar yavaş basamağı beklediği için toplam hız yavaş adıma bağlıdır."}],"ans":"En yavaş basamak bir darboğaz oluşturur; tepkime ondan hızlı ilerleyemediğinden toplam hızı o belirler."}],"zor":[{"q":"İki basamaklı bir tepkimede ilk basamak yavaşsa, hız hangi basamağa bağlıdır?","steps":[{"t":"Yavaş basamak","a":"ilk basamak","d":"İlk basamak yavaş olduğundan hız belirleyen basamak odur."},{"t":"Hız ifadesi","a":"yavaşa göre","d":"Tepkime hızı, hız belirleyen (yavaş) basamaktaki tepken derişimlerine bağlıdır."}],"ans":"İlk basamak yavaşsa hız ona bağlıdır; tepkime hızı yavaş (hız belirleyen) basamaktaki tepkenlere göre belirlenir."},{"q":"Ara ürün ve katalizör net tepkime denkleminde neden ikisi de görünmez?","fig":"<svg viewBox='0 0 320 120'><text x='20' y='40' font-size='10' fill='#1a2b45'>1. A + K → AK</text><text x='20' y='65' font-size='10' fill='#1a2b45'>2. AK + B → C + K</text><line x1='15' y1='80' x2='200' y2='80' stroke='#1a2b45'/><text x='20' y='100' font-size='10' fill='#1a2b45'>net: A + B → C</text><text x='150' y='40' font-size='9' fill='#9ed9a8'>AK ara ürün</text><text x='200' y='65' font-size='9' fill='#e0552b'>K katalizör</text></svg>","steps":[{"t":"Ara ürün","a":"oluşup tükenir","d":"Ara ürün bir basamakta oluşup diğerinde harcandığından basamaklar toplanınca sadeleşir."},{"t":"Katalizör","a":"girip çıkar","d":"Katalizör de önce girip sonra çıktığından toplamda sadeleşir; ikisi de net denklemde yer almaz."}],"ans":"Ara ürün oluşup tükendiği, katalizör girip çıktığı için basamaklar toplandığında her ikisi de sadeleşir ve net denklemde görünmez."},{"q":"Bir mekanizmada ilk basamak hızlı, ikinci basamak yavaşsa hangi basamak hız belirleyendir?","steps":[{"t":"Yavaş olan","a":"ikinci basamak","d":"Hız belirleyen basamak her zaman en yavaş olandır; burada ikinci basamak yavaştır."},{"t":"Sonuç","a":"ikinci belirler","d":"Bu nedenle tepkimenin hızını ikinci (yavaş) basamak belirler."}],"ans":"En yavaş olan ikinci basamak hız belirleyen basamaktır; tepkimenin hızını o belirler."},{"q":"Tek basamakta gerçekleşen bir tepkime ile çok basamaklı tepkime arasındaki fark nedir?","steps":[{"t":"Tek basamak","a":"doğrudan","d":"Tek basamaklı (elementer) tepkimede tepkenler tek bir çarpışmada doğrudan ürüne dönüşür."},{"t":"Çok basamak","a":"ara türler var","d":"Çok basamaklıda araya ara ürünler girer ve birden çok adım vardır; bu adımların en yavaşı hızı belirler."}],"ans":"Tek basamaklı tepkime tek hamlede gerçekleşir; çok basamaklıda ise ara ürünler içeren birden çok adım bulunur ve en yavaş adım hızı belirler."},{"q":"Mekanizmayı bilmek bir tepkimenin hızını artırmak için neden önemlidir?","steps":[{"t":"Yavaş adım hedef","a":"darboğazı bul","d":"Mekanizma sayesinde hangi basamağın hız belirleyen (yavaş) olduğu bulunur."},{"t":"Müdahale","a":"o adımı hızlandır","d":"Tepkimeyi hızlandırmak için doğru noktaya, yani yavaş adıma (örneğin katalizörle) müdahale edilir."}],"ans":"Mekanizma, hız belirleyen yavaş basamağı gösterir; tepkimeyi hızlandırmak için tam o adıma müdahale edileceğinden bilmek önemlidir."}]},"lise":{"kolay":[{"q":"Bir tepkime mekanizmasını oluşturan elementer basamaklar nedir?","steps":[{"t":"Elementer basamak","a":"tek adımda","d":"Elementer basamak, tek bir çarpışma veya olayla gerçekleşen, daha alt adıma bölünemeyen tepkime adımıdır."},{"t":"Mekanizma","a":"basamaklar dizisi","d":"Mekanizma, net tepkimeyi veren bu elementer basamakların ardışık dizisidir."}],"ans":"Mekanizma, net tepkimeyi veren ve her biri tek bir olayla gerçekleşen elementer basamakların ardışık dizisidir."},{"q":"Hız belirleyen basamak tepkime hız ifadesini nasıl belirler?","steps":[{"t":"En yavaş basamak","a":"darboğaz","d":"Tepkime, en yavaş (hız belirleyen) basamaktan daha hızlı ilerleyemez."},{"t":"Hız ifadesi","a":"o basamağa göre","d":"Bu yüzden deneysel hız ifadesi, hız belirleyen basamaktaki tepkenlerin derişimlerine göre yazılır."}],"ans":"Hız belirleyen (en yavaş) basamak tepkimenin darboğazıdır; deneysel hız ifadesi bu basamağın tepken derişimlerine göre belirlenir."},{"q":"Ara ürün ile katalizör mekanizmada nasıl ayırt edilir?","fig":"<svg viewBox='0 0 320 150'><line x1='30' y1='75' x2='290' y2='75' stroke='#1a2b45' stroke-width='2'/><polygon points='290,75 280,70 280,80' fill='#1a2b45'/><circle cx='110' cy='75' r='14' fill='#9ed9a8' stroke='#1a2b45'/><text x='110' y='79' font-size='9' text-anchor='middle' fill='#1a2b45'>ara</text><text x='110' y='45' font-size='8' text-anchor='middle' fill='#1a2b45'>oluşur-tükenir</text><circle cx='210' cy='75' r='14' fill='#e0552b' stroke='#1a2b45'/><text x='210' y='79' font-size='9' text-anchor='middle' fill='#fff'>kat</text><text x='210' y='45' font-size='8' text-anchor='middle' fill='#1a2b45'>girer-çıkar</text></svg>","steps":[{"t":"Ara ürün","a":"önce oluşur","d":"Ara ürün bir basamakta ürün olarak oluşur, sonraki basamakta tepken olarak tükenir."},{"t":"Katalizör","a":"önce girer","d":"Katalizör ise ilk basamakta tepken olarak girer, sonraki basamakta yeniden oluşur (geri kazanılır)."}],"ans":"Ara ürün önce oluşup sonra tükenir; katalizör önce tüketilip sonra geri kazanılır. İkisi de net denklemde görünmez ama ortaya çıkış sırası terstir."},{"q":"Bir mekanizmanın geçerli kabul edilmesi için hangi koşulu sağlaması gerekir?","steps":[{"t":"Toplam = net","a":"basamaklar toplanır","d":"Elementer basamaklar toplandığında ara türler sadeleşip net (deneysel) tepkime denklemini vermelidir."},{"t":"Hız uyumu","a":"deneysel hız","d":"Ayrıca mekanizmadan türetilen hız ifadesi, deneyle bulunan hız ifadesiyle uyuşmalıdır."}],"ans":"Geçerli mekanizma, basamakları toplandığında net tepkimeyi vermeli ve türetilen hız ifadesi deneysel hız ifadesiyle uyuşmalıdır."},{"q":"Moleküleritesi (basamağa giren tanecik sayısı) ile hız ifadesi arasındaki ilişki nedir?","steps":[{"t":"Moleküleriti","a":"giren tanecik","d":"Bir elementer basamağın moleküleritesi, o basamakta çarpışan tanecik sayısıdır (tek, çift, üçlü)."},{"t":"Üs = katsayı","a":"sadece elementerde","d":"Yalnızca elementer basamakta hız ifadesindeki üsler, tepken katsayılarına eşittir."}],"ans":"Elementer bir basamakta hız ifadesindeki derişim üsleri, basamağın moleküleritesini veren tepken katsayılarına eşittir; bu net tepkime için geçerli değildir."}],"zor":[{"q":"İki basamaklı bir mekanizmada birinci basamak yavaşsa hız ifadesi nasıl yazılır?","steps":[{"t":"Yavaş basamak","a":"hız belirleyen","d":"Birinci basamak yavaşsa hız belirleyen odur; hız bu basamaktaki tepken derişimlerine bağlıdır."},{"t":"Hız ifadesi","a":"yavaş basamaktan","d":"Örneğin yavaş basamak A + B → C ise hız = k·[A]·[B] şeklinde, yavaş basamağın tepkenlerine göre yazılır."}],"ans":"Birinci basamak yavaşsa hız belirleyen odur; hız ifadesi doğrudan o basamağın tepken derişimlerine göre (örn. hız = k·[A]·[B]) yazılır."},{"q":"Hız belirleyen basamak ikinci basamaksa ve ara ürün içeriyorsa, hız ifadesindeki ara ürün derişimi nasıl yok edilir?","steps":[{"t":"Ön denge","a":"hızlı 1. basamak","d":"Hızlı birinci basamak dengede kabul edilir (ön denge yaklaşımı); ileri ve geri hızlar eşitlenir."},{"t":"Yerine koyma","a":"ara ürünü ifade et","d":"Bu eşitlikten ara ürün derişimi, başlangıç tepkenleri cinsinden çözülüp yavaş basamağın hız ifadesinde yerine konur."}],"ans":"Hızlı birinci basamak ön dengede kabul edilir; bu dengeden ara ürün derişimi tepkenler cinsinden bulunup yavaş basamağın hız ifadesinde yerine konarak ara ürün ifadeden çıkarılır."},{"q":"Bir tepkimenin deneysel hız derecesi (mol sayısının) toplam denklem katsayılarına eşit olmayabilir; bunun nedeni mekanizma açısından nedir?","steps":[{"t":"Net denklem","a":"toplam reaksiyon","d":"Net denklem yalnızca başlangıç ve bitiş maddelerini gösterir, gerçek adımları göstermez."},{"t":"Hız belirleyen","a":"sadece yavaş adım","d":"Hız yalnızca hız belirleyen basamaktaki tanecik sayısına bağlı olduğundan, derece net denklem katsayılarıyla genelde örtüşmez."}],"ans":"Hız yalnızca hız belirleyen (yavaş) basamağa bağlı olduğundan, net denklemdeki toplam katsayılar gerçek adımları yansıtmaz; bu yüzden deneysel hız derecesi net denklem katsayılarına eşit olmayabilir."},{"q":"Kararlı hal (steady-state) yaklaşımı bir mekanizmada ara ürün için neyi varsayar?","steps":[{"t":"Varsayım","a":"derişim sabit","d":"Kararlı hal yaklaşımında, tepken kısa süre sonra ara ürünün oluşma ve tükenme hızları eşitlenir, derişimi yaklaşık sabit kabul edilir."},{"t":"Net hız sıfır","a":"d[ara]/dt ≈ 0","d":"Ara ürünün net derişim değişimi sıfır alınarak (d[ara ürün]/dt ≈ 0) derişimi tepkenler cinsinden çözülür ve hız ifadesinden elenir."}],"ans":"Kararlı hal yaklaşımı, ara ürünün oluşma ve tükenme hızlarının eşitlenip derişiminin sabit (d[ara ürün]/dt ≈ 0) kaldığını varsayar; böylece ara ürün hız ifadesinden çıkarılır."},{"q":"Bir katalizörlü tepkimede mekanizma incelendiğinde katalizörün varlığı net denkleme ve ΔH'ye neden yansımaz?","steps":[{"t":"Net denklemde yok","a":"girip çıkar","d":"Katalizör ilk basamakta girip son basamakta geri çıktığından, basamaklar toplanınca sadeleşir ve net denklemde görünmez."},{"t":"ΔH değişmez","a":"uç enerjiler aynı","d":"Mekanizma değişse de tepkenler ve ürünlerin enerji düzeyleri sabittir; katalizör yalnızca aktivasyon enerjisini düşürür, ΔH'yi değiştirmez."}],"ans":"Katalizör mekanizmada girip geri çıktığından net denklemde sadeleşir; ayrıca yalnızca aktivasyon enerjisini düşürüp tepken/ürün enerji düzeylerini değiştirmediğinden ΔH'ye de yansımaz."}]}},"notrlesme":{"ilkokul":{"kolay":[{"q":"Bir asit ile bir baz karıştırıldığında birbirinin etkisini gidermesine ne denir?","steps":[{"t":"Karışma","a":"asit + baz","d":"Asit ve baz bir araya geldiğinde tepkimeye girer."},{"t":"Etki kaybı","a":"nötrleşme","d":"Birbirinin etkisini yok ettikleri bu olaya nötrleşme denir."}],"ans":"Asit ile bazın birbirinin etkisini gidermesine nötrleşme denir."},{"q":"Limon ve sirke gibi ekşi tatlı maddeler hangi gruba girer?","steps":[{"t":"Tat","a":"ekşi","d":"Limon ve sirke ekşi tada sahiptir."},{"t":"Grup","a":"asit","d":"Ekşi tatlı bu maddeler asitler grubuna girer."}],"ans":"Limon ve sirke gibi ekşi maddeler asitlerdir."},{"q":"Sabun ve karbonat gibi maddeler hangi gruba girer?","steps":[{"t":"His","a":"kayganımsı","d":"Sabun ve karbonatlı maddeler elde kaygan hissedilir, acı olabilir."},{"t":"Grup","a":"baz","d":"Bu maddeler bazlar grubuna girer."}],"ans":"Sabun ve karbonat gibi kaygan maddeler bazlardır."},{"q":"Karıncanın ya da arının soktuğu yere neden karbonatlı (bazik) su sürülür?","fig":"<svg viewBox='0 0 320 150'><circle cx='90' cy='75' r='24' fill='#e0552b' stroke='#1a2b45'/><text x='90' y='80' font-size='10' text-anchor='middle' fill='#fff'>asit</text><text x='135' y='80' font-size='16' text-anchor='middle' fill='#1a2b45'>+</text><circle cx='185' cy='75' r='24' fill='#2b6be0' stroke='#1a2b45'/><text x='185' y='80' font-size='10' text-anchor='middle' fill='#fff'>baz</text><text x='230' y='80' font-size='16' text-anchor='middle' fill='#1a2b45'>→</text><text x='280' y='80' font-size='10' text-anchor='middle' fill='#1a2b45'>nötr</text></svg>","steps":[{"t":"Sokma asidik","a":"asit bırakır","d":"Arı/karınca sokunca deriye asidik bir madde bırakır."},{"t":"Bazla nötrleme","a":"karbonat","d":"Bazik karbonatlı su bu asidi nötrleştirip yanma hissini azaltır."}],"ans":"Sokma asidik olduğu için, bazik karbonatlı su asidi nötrleştirir ve rahatsızlığı azaltır."},{"q":"Saf su asidik mi, bazik mi yoksa nötr müdür?","steps":[{"t":"Ne ekşi ne kaygan","a":"ortada","d":"Saf su ne ekşidir ne de bazların özelliğini gösterir."},{"t":"Sonuç","a":"nötr","d":"Bu yüzden saf su nötr kabul edilir."}],"ans":"Saf su nötrdür; asidik de bazik de değildir."}],"zor":[{"q":"Midemiz çok ekşidiğinde (mide ekşimesi) neden bazik bir ilaç (mide ilacı) içilir?","steps":[{"t":"Fazla asit","a":"midede asit","d":"Mide ekşimesinde midede fazla asit (HCl) bulunur."},{"t":"Bazla nötrleme","a":"ilaç bazik","d":"Bazik mide ilacı bu fazla asidi nötrleştirip rahatsızlığı giderir."}],"ans":"Mide ekşimesinde fazla mide asidini nötrleştirmek için bazik mide ilacı içilir."},{"q":"Asit ile baz tam olarak nötrleşince ortaya hangi iki tür madde çıkar?","steps":[{"t":"Birinci ürün","a":"tuz","d":"Asit ve baz tepkimesinden bir tuz oluşur."},{"t":"İkinci ürün","a":"su","d":"Ayrıca su (H₂O) açığa çıkar; yani ürünler tuz ve sudur."}],"ans":"Asit ile baz nötrleşince tuz ve su oluşur."},{"q":"Turnusol kâğıdı asitte ve bazda hangi renkleri alır?","fig":"<svg viewBox='0 0 320 150'><rect x='60' y='55' width='60' height='40' fill='#e0552b' stroke='#1a2b45'/><text x='90' y='115' font-size='10' text-anchor='middle' fill='#1a2b45'>asit: kırmızı</text><rect x='200' y='55' width='60' height='40' fill='#2b6be0' stroke='#1a2b45'/><text x='230' y='115' font-size='10' text-anchor='middle' fill='#1a2b45'>baz: mavi</text></svg>","steps":[{"t":"Asit","a":"kırmızı","d":"Mavi turnusol asitte kırmızıya döner."},{"t":"Baz","a":"mavi","d":"Kırmızı turnusol bazda maviye döner."}],"ans":"Turnusol asitte kırmızı, bazda mavi renk alır."},{"q":"Toprak çok asidikse (ekşiyse) çiftçiler neden kireç (bazik) ekler?","steps":[{"t":"Asidik toprak","a":"bitkiye zor","d":"Çok asidik toprak bazı bitkiler için uygun değildir."},{"t":"Kireçle nötrleme","a":"bazik kireç","d":"Bazik olan kireç toprağın asidini nötrleştirip pH'ı dengeler, toprağı bitkiye uygun hale getirir."}],"ans":"Asidik toprağı nötrleştirmek için bazik özellikteki kireç eklenir; böylece toprak bitki için uygun hale gelir."},{"q":"Diş macunu çoğunlukla neden hafif baziktir?","steps":[{"t":"Ağızda asit","a":"diş çürütür","d":"Yiyecek artıkları ağızda asit oluşturur, bu asit dişi aşındırır."},{"t":"Bazik macun","a":"nötrler","d":"Hafif bazik diş macunu bu asidi nötrleştirerek dişleri korur."}],"ans":"Diş macunu, ağızdaki asidi nötrleştirip dişleri koruduğu için çoğunlukla hafif baziktir."}]},"ortaokul":{"kolay":[{"q":"Nötrleşme tepkimesinin genel denklemi nasıldır?","steps":[{"t":"Girenler","a":"asit + baz","d":"Bir asit ile bir baz tepkimeye girer."},{"t":"Ürünler","a":"tuz + su","d":"Sonuçta bir tuz ve su oluşur: asit + baz → tuz + su."}],"ans":"Nötrleşmenin genel denklemi: asit + baz → tuz + su biçimindedir."},{"q":"HCl + NaOH → NaCl + H₂O tepkimesinde hangi tuz oluşur?","fig":"<svg viewBox='0 0 320 150'><text x='75' y='75' font-size='12' text-anchor='middle' fill='#1a2b45'>HCl + NaOH</text><text x='160' y='75' font-size='16' text-anchor='middle' fill='#1a2b45'>→</text><text x='245' y='75' font-size='12' text-anchor='middle' fill='#1a2b45'>NaCl + H₂O</text></svg>","steps":[{"t":"Asit ve baz","a":"HCl ve NaOH","d":"Hidroklorik asit (HCl) ile sodyum hidroksit (NaOH) tepkimeye girer."},{"t":"Tuz","a":"NaCl","d":"Oluşan tuz sodyum klorürdür (NaCl, yemek tuzu); ayrıca su açığa çıkar."}],"ans":"HCl + NaOH → NaCl + H₂O tepkimesinde sodyum klorür (NaCl) tuzu ve su oluşur."},{"q":"pH cetvelinde 7 değeri neyi gösterir?","steps":[{"t":"Cetvel","a":"0 - 14","d":"pH cetveli 0 ile 14 arasında değer alır."},{"t":"Orta nokta","a":"nötr","d":"pH = 7 nötrlüğü gösterir; 7'den küçük asidik, büyük baziktir."}],"ans":"pH = 7 nötrlüğü gösterir; 7'den küçük değerler asidik, büyük değerler baziktir."},{"q":"Nötrleşme sırasında ortamın pH'ı genel olarak nasıl değişir?","steps":[{"t":"Başlangıç","a":"asit düşük pH","d":"Asidik ortamın pH'ı düşüktür (7'nin altında)."},{"t":"Baz eklenince","a":"7'ye doğru","d":"Üzerine baz eklendikçe asit nötrleşir ve pH 7'ye (nötre) doğru yaklaşır."}],"ans":"Asidik ortama baz eklendikçe asit nötrleşir ve pH 7'ye (nötr değere) doğru yaklaşır."},{"q":"Nötrleşmenin günlük hayattan bir örneğini veriniz.","steps":[{"t":"Olay","a":"mide ekşimesi","d":"Midede fazla asit (HCl) birikince mide ekşimesi olur."},{"t":"Çözüm","a":"bazik ilaç","d":"Bazik mide ilacı (örneğin Mg(OH)₂ içeren) bu asidi nötrleştirir."}],"ans":"Mide ekşimesinde bazik mide ilacının fazla mide asidini nötrleştirmesi, nötrleşmenin günlük bir örneğidir."}],"zor":[{"q":"HCl + NaOH → NaCl + H₂O denkleminin denk olduğunu gösteriniz.","steps":[{"t":"H ve Cl","a":"H 2=2, Cl 1=1","d":"Solda HCl (1 H, 1 Cl) + NaOH (1 H) → 2 H; sağda H₂O → 2 H ve NaCl → 1 Cl; eşit."},{"t":"Na ve O","a":"Na 1=1, O 1=1","d":"Solda NaOH → 1 Na, 1 O; sağda NaCl → 1 Na, H₂O → 1 O atomu; eşit, denklem denktir."}],"ans":"H (2 = 2), Cl (1 = 1), Na (1 = 1) ve O (1 = 1) atomları iki tarafta eşit olduğundan HCl + NaOH → NaCl + H₂O denktir."},{"q":"Sülfürik asitin sodyum hidroksitle nötrleşmesi neden 2NaOH gerektirir? (H₂SO₄ + 2NaOH → Na₂SO₄ + 2H₂O)","fig":"<svg viewBox='0 0 320 150'><text x='85' y='70' font-size='11' text-anchor='middle' fill='#1a2b45'>H₂SO₄ + 2NaOH</text><text x='175' y='70' font-size='15' text-anchor='middle' fill='#1a2b45'>→</text><text x='255' y='70' font-size='11' text-anchor='middle' fill='#1a2b45'>Na₂SO₄ + 2H₂O</text></svg>","steps":[{"t":"İki H⁺","a":"diprotik asit","d":"H₂SO₄ iki adet H⁺ verebilir, bu yüzden iki OH⁻ ile tepkimesi gerekir."},{"t":"Denklik","a":"2NaOH gerekir","d":"İki OH⁻ sağlamak için 2NaOH alınır; böylece H 4=4, Na 2=2, S 1=1, O 6=6 olarak denkleşir."}],"ans":"H₂SO₄ iki H⁺ verdiğinden iki OH⁻ gerekir; bu yüzden 2NaOH alınır ve H₂SO₄ + 2NaOH → Na₂SO₄ + 2H₂O denkleşir."},{"q":"Nötrleşme tepkimesi enerji açısından neden ekzotermiktir?","steps":[{"t":"İyon birleşmesi","a":"H⁺ + OH⁻","d":"Nötrleşmede asitten gelen H⁺ ile bazdan gelen OH⁻ birleşerek su oluşturur."},{"t":"Enerji salımı","a":"ısı verir","d":"Bu birleşme daha kararlı (düşük enerjili) su molekülü oluşturduğundan ısı açığa çıkar; bu yüzden nötrleşme ekzotermiktir."}],"ans":"Nötrleşmede H⁺ ile OH⁻ birleşip kararlı su oluşturduğundan ısı açığa çıkar; bu nedenle tepkime ekzotermiktir."},{"q":"Bir tepkimede pH 2 olan asit ortamına yeterince baz eklenirse pH nasıl ve neden değişir?","steps":[{"t":"Asit nötrlenir","a":"H⁺ azalır","d":"Eklenen baz, ortamdaki H⁺ iyonlarını OH⁻ ile birleştirerek azaltır."},{"t":"pH artar","a":"7'ye, sonra üstüne","d":"H⁺ azaldıkça pH 2'den yükselir; tam nötrleşmede 7 olur, fazla baz eklenirse 7'nin üstüne (bazik tarafa) çıkar."}],"ans":"Baz eklendikçe H⁺ azaldığı için pH 2'den yükselir; tam nötrleşmede 7'ye gelir, fazla baz eklenirse pH 7'nin üstüne çıkar."},{"q":"Bir asidin pH'ı 3 ise H⁺ derişimi ne kadardır ve bu ortam asidik mi baziktir? (pH = −log[H⁺])","steps":[{"t":"Bağıntı","a":"pH = −log[H⁺]","d":"pH ile H⁺ derişimi pH = −log[H⁺] bağıntısıyla ilişkilidir."},{"t":"Hesap","a":"[H⁺] = 10⁻³ mol/L","d":"pH = 3 için [H⁺] = 10⁻³ mol/L olur; pH 7'den küçük olduğundan ortam asidiktir."}],"ans":"pH = 3 için [H⁺] = 10⁻³ mol/L'dir ve pH 7'den küçük olduğundan ortam asidiktir."}]},"lise":{"kolay":[{"q":"Nötrleşme tepkimesi Arrhenius yaklaşımıyla nasıl tanımlanır?","steps":[{"t":"Asit ve baz","a":"H⁺ ve OH⁻","d":"Arrhenius'a göre asit suya H⁺, baz ise OH⁻ verir."},{"t":"Net olay","a":"su oluşur","d":"Nötrleşmede H⁺ + OH⁻ → H₂O olur; genel olarak asit + baz → tuz + su biçimindedir."}],"ans":"Arrhenius yaklaşımıyla nötrleşme, asidin verdiği H⁺ ile bazın verdiği OH⁻'nin birleşip su oluşturmasıdır: asit + baz → tuz + su."},{"q":"Nötrleşmenin net iyon denklemi nedir ve neden tuz bu denklemde görünmez?","steps":[{"t":"İzleyici iyon","a":"tuz iyonları","d":"Tuzu oluşturan iyonlar (örneğin Na⁺, Cl⁻) tepkimeye doğrudan katılmaz, ortamda serbest kalır (izleyici iyon)."},{"t":"Net denklem","a":"H⁺ + OH⁻ → H₂O","d":"Geriye sadece H⁺ ile OH⁻'nin su oluşturması kalır; net iyon denklemi H⁺ + OH⁻ → H₂O'dur."}],"ans":"Nötrleşmenin net iyon denklemi H⁺ + OH⁻ → H₂O'dur; tuz iyonları izleyici olduğundan tepkimeye girmez ve net denklemde görünmez."},{"q":"Kuvvetli asit-kuvvetli baz nötrleşmesinde eşdeğerlik noktasında pH neden 7'dir?","steps":[{"t":"Tam tepkime","a":"H⁺ = OH⁻","d":"Kuvvetli asit ve kuvvetli baz tam iyonlaştığından eşdeğerlik noktasında H⁺ ve OH⁻ tam birbirini tüketir."},{"t":"Nötr tuz","a":"pH = 7","d":"Oluşan tuz suyu asidik/bazik etkilemez (hidroliz olmaz); 25 °C'de ortam nötr, pH = 7 olur."}],"ans":"Kuvvetli asit-kuvvetli baz nötrleşmesinde H⁺ ve OH⁻ tam tükenir ve oluşan tuz nötr olduğundan 25 °C'de eşdeğerlik noktasında pH = 7'dir."},{"q":"pH + pOH toplamı 25 °C'de neden 14'tür?","steps":[{"t":"Suyun iyon dengesi","a":"Kw = 10⁻¹⁴","d":"25 °C'de suyun iyon çarpımı Kw = [H⁺]·[OH⁻] = 1,0·10⁻¹⁴'tür."},{"t":"Logaritma","a":"pH + pOH = 14","d":"Bu eşitliğin negatif logaritması alınınca pH + pOH = 14 elde edilir."}],"ans":"25 °C'de Kw = [H⁺]·[OH⁻] = 10⁻¹⁴ olduğundan, negatif logaritmasıyla pH + pOH = 14 olur."},{"q":"Günlük hayatta antasit (mide ilacı) Mg(OH)₂'nin mide asidini nötrlemesi nasıl açıklanır?","steps":[{"t":"Mide asidi","a":"HCl","d":"Mide özsuyu hidroklorik asit (HCl) içerir; fazlası ekşimeye yol açar."},{"t":"Nötrleşme","a":"Mg(OH)₂ + 2HCl → MgCl₂ + 2H₂O","d":"Bazik Mg(OH)₂ asitle tepkimeye girip tuz ve su oluşturarak fazla asidi nötrler."}],"ans":"Bazik Mg(OH)₂, mide asidiyle Mg(OH)₂ + 2HCl → MgCl₂ + 2H₂O tepkimesini verip fazla HCl'yi nötrleştirir; bu nötrleşmenin günlük bir uygulamasıdır."}],"zor":[{"q":"H₂SO₄ + 2NaOH → Na₂SO₄ + 2H₂O denkleminin tüm atomlar için denk olduğunu gösteriniz.","fig":"<svg viewBox='0 0 320 150'><text x='85' y='65' font-size='11' text-anchor='middle' fill='#1a2b45'>H₂SO₄ + 2NaOH</text><text x='175' y='65' font-size='15' text-anchor='middle' fill='#1a2b45'>→</text><text x='255' y='65' font-size='11' text-anchor='middle' fill='#1a2b45'>Na₂SO₄ + 2H₂O</text><text x='160' y='105' font-size='10' text-anchor='middle' fill='#1a2b45'>H:4 Na:2 S:1 O:6</text></svg>","steps":[{"t":"H ve Na","a":"H 4=4, Na 2=2","d":"Solda H₂SO₄ (2 H) + 2NaOH (2 H) = 4 H; sağda 2H₂O → 4 H. Na: solda 2NaOH → 2 Na, sağda Na₂SO₄ → 2 Na; eşit."},{"t":"S ve O","a":"S 1=1, O 6=6","d":"S: her iki tarafta 1. O: solda H₂SO₄ (4 O) + 2NaOH (2 O) = 6 O; sağda Na₂SO₄ (4 O) + 2H₂O (2 O) = 6 O; eşit, denklem denktir."}],"ans":"H (4 = 4), Na (2 = 2), S (1 = 1) ve O (6 = 6) atom sayıları iki tarafta eşit olduğundan H₂SO₄ + 2NaOH → Na₂SO₄ + 2H₂O denktir."},{"q":"0,1 mol HCl içeren çözeltiyi tam nötrlemek için 0,5 M NaOH çözeltisinden kaç litre gerekir? (HCl + NaOH → NaCl + H₂O)","steps":[{"t":"Mol oranı","a":"1 HCl : 1 NaOH","d":"Denkleme göre 1 mol HCl, 1 mol NaOH ile nötrleşir; 0,1 mol HCl için 0,1 mol NaOH gerekir."},{"t":"Hacim","a":"V = mol / M","d":"V = 0,1 mol / 0,5 mol/L = 0,2 L."}],"ans":"0,1 mol HCl için 0,1 mol NaOH gerekir; 0,5 M çözeltiden V = 0,1 / 0,5 = 0,2 litre (200 mL) gerekir."},{"q":"[H⁺] = 1,0·10⁻⁴ mol/L olan bir çözeltinin pH ve pOH değerlerini bulunuz. (pH + pOH = 14)","steps":[{"t":"pH","a":"4","d":"pH = −log[H⁺] = −log(10⁻⁴) = 4; pH 7'den küçük olduğundan ortam asidiktir."},{"t":"pOH","a":"10","d":"pH + pOH = 14 olduğundan pOH = 14 − 4 = 10."}],"ans":"[H⁺] = 10⁻⁴ mol/L için pH = 4 ve pOH = 14 − 4 = 10'dur; ortam asidiktir."},{"q":"Kuvvetli ve zayıf asit-baz nötrleşmelerinde eşdeğerlik noktası pH'ını ve nedenini karşılaştırınız.","steps":[{"t":"Kuvvetli-kuvvetli","a":"pH ≈ 7","d":"Kuvvetli asit + kuvvetli baz nötrleşmesinde oluşan tuz hidroliz olmaz, eşdeğerlik noktası pH'ı 7 civarındadır."},{"t":"Zayıf bileşen","a":"7'den sapar","d":"Zayıf asit + kuvvetli baz tuzu bazik hidroliz yapar (pH > 7); kuvvetli asit + zayıf baz tuzu asidik hidroliz yapar (pH < 7)."}],"ans":"Kuvvetli asit-kuvvetli bazda eşdeğerlik pH'ı yaklaşık 7'dir; zayıf asit-kuvvetli bazda oluşan tuz bazik hidrolizle pH'ı 7'nin üstüne, kuvvetli asit-zayıf bazda asidik hidrolizle 7'nin altına kaydırır."},{"q":"50 mL 0,2 M HCl çözeltisi, 50 mL 0,2 M NaOH ile karıştırılırsa ortam asidik mi bazik mi nötr olur ve neden?","steps":[{"t":"Mol hesabı","a":"0,01 = 0,01 mol","d":"HCl: 0,050 L × 0,2 mol/L = 0,01 mol; NaOH: 0,050 L × 0,2 mol/L = 0,01 mol; mol sayıları eşit."},{"t":"Tam nötrleşme","a":"pH ≈ 7","d":"1:1 mol oranıyla H⁺ ve OH⁻ tam birbirini tüketir; oluşan NaCl nötr tuzdur, dolayısıyla ortam nötr (pH ≈ 7) olur."}],"ans":"HCl ve NaOH mol sayıları eşit (0,01 mol) olduğundan 1:1 oranla tam nötrleşir; oluşan NaCl nötr tuz olduğundan ortam nötr (pH ≈ 7) olur."}]}},"sentezAnaliz":{"ilkokul":{"kolay":[{"q":"İki ayrı madde birleşip tek bir yeni madde oluşturursa buna ne tür bir tepkime denir?","steps":[{"t":"Birleşme","a":"yan yana gelir","d":"İki ya da daha çok madde bir araya gelip birbirine bağlanır."},{"t":"Tek ürün","a":"sentez (birleşme)","d":"Sonuçta tek bir yeni madde oluşursa buna birleşme (sentez) tepkimesi denir."}],"ans":"İki maddenin birleşip tek yeni madde oluşturduğu tepkimeye birleşme (sentez) tepkimesi denir."},{"q":"Tek bir madde parçalanıp daha basit maddelere ayrılırsa buna ne denir?","steps":[{"t":"Parçalanma","a":"ikiye ayrılır","d":"Bir madde, daha küçük ve basit maddelere ayrılır."},{"t":"Ad","a":"analiz (ayrışma)","d":"Bir maddenin daha basit maddelere ayrıldığı bu olaya ayrışma (analiz) tepkimesi denir."}],"ans":"Tek maddenin daha basit maddelere ayrılmasına ayrışma (analiz) tepkimesi denir."},{"q":"Su (H₂O) hangi iki maddenin birleşmesiyle oluşur?","fig":"<svg viewBox='0 0 320 160'><circle cx='70' cy='80' r='18' fill='#cfd8e8' stroke='#1a2b45'/><text x='70' y='85' font-size='11' text-anchor='middle' fill='#1a2b45'>H₂</text><text x='110' y='85' font-size='16' text-anchor='middle' fill='#1a2b45'>+</text><circle cx='150' cy='80' r='18' fill='#e0552b' stroke='#1a2b45'/><text x='150' y='85' font-size='11' text-anchor='middle' fill='#fff'>O₂</text><text x='195' y='85' font-size='18' text-anchor='middle' fill='#1a2b45'>→</text><circle cx='250' cy='80' r='20' fill='#9ed9a8' stroke='#1a2b45'/><text x='250' y='85' font-size='11' text-anchor='middle' fill='#1a2b45'>H₂O</text></svg>","steps":[{"t":"Maddeler","a":"hidrojen ve oksijen","d":"Hidrojen gazı (H₂) ile oksijen gazı (O₂) birleşir."},{"t":"Ürün","a":"su","d":"Bu iki gaz birleşerek suyu (H₂O) oluşturur."}],"ans":"Su, hidrojen (H₂) ile oksijenin (O₂) birleşmesiyle oluşur."},{"q":"Birleşme tepkimesinde madde sayısı nasıl değişir?","steps":[{"t":"Başta","a":"çok madde","d":"Tepkimeye iki ya da daha çok madde girer."},{"t":"Sonda","a":"tek madde","d":"Bunlar birleşip tek bir ürün oluşturur, yani çoktan teke iner."}],"ans":"Birleşme tepkimesinde birden çok madde birleşip tek bir madde oluşur."},{"q":"Ayrışma tepkimesinde madde sayısı nasıl değişir?","steps":[{"t":"Başta","a":"tek madde","d":"Tepkimeye tek bir madde girer."},{"t":"Sonda","a":"çok madde","d":"Bu madde parçalanıp birden fazla basit maddeye ayrılır."}],"ans":"Ayrışma tepkimesinde tek bir madde parçalanıp birden çok madde oluşur."}],"zor":[{"q":"Yumurta kabuğundaki kireç taşı (CaCO₃) ısıtılınca ikiye ayrılıyorsa bu hangi tepkime türüdür?","steps":[{"t":"Tek madde girer","a":"kireç taşı","d":"Tepkimeye sadece kireç taşı (CaCO₃) girer."},{"t":"Ayrılma","a":"ayrışma","d":"Isıtınca iki ayrı maddeye ayrıldığı için bu bir ayrışma (analiz) tepkimesidir."}],"ans":"Tek madde ısıtılıp parçalandığı için bu bir ayrışma (analiz) tepkimesidir."},{"q":"Demir (Fe) ile kükürt (S) tozları ısıtılınca tek bir madde oluşuyorsa bu hangi tür tepkimedir?","steps":[{"t":"İki madde girer","a":"demir ve kükürt","d":"Demir ile kükürt iki ayrı maddedir ve birlikte ısıtılır."},{"t":"Birleşme","a":"sentez","d":"Birleşip tek yeni madde oluşturdukları için bu bir birleşme (sentez) tepkimesidir."}],"ans":"İki madde birleşip tek madde oluşturduğu için bu bir birleşme (sentez) tepkimesidir."},{"q":"Suyun ayrışmasıyla hangi iki gaz açığa çıkar?","fig":"<svg viewBox='0 0 320 160'><circle cx='80' cy='80' r='22' fill='#9ed9a8' stroke='#1a2b45'/><text x='80' y='85' font-size='12' text-anchor='middle' fill='#1a2b45'>H₂O</text><text x='135' y='85' font-size='18' text-anchor='middle' fill='#1a2b45'>→</text><circle cx='200' cy='80' r='18' fill='#cfd8e8' stroke='#1a2b45'/><text x='200' y='85' font-size='11' text-anchor='middle' fill='#1a2b45'>H₂</text><text x='240' y='85' font-size='16' text-anchor='middle' fill='#1a2b45'>+</text><circle cx='280' cy='80' r='18' fill='#e0552b' stroke='#1a2b45'/><text x='280' y='85' font-size='11' text-anchor='middle' fill='#fff'>O₂</text></svg>","steps":[{"t":"Girem","a":"su","d":"Tek madde olarak su (H₂O) ayrışır."},{"t":"Ürünler","a":"hidrojen ve oksijen","d":"Sudan hidrojen gazı (H₂) ile oksijen gazı (O₂) açığa çıkar."}],"ans":"Suyun ayrışmasıyla hidrojen (H₂) ve oksijen (O₂) gazları açığa çıkar."},{"q":"Birleşme tepkimesi, ayrışma tepkimesinin tersi gibi midir?","steps":[{"t":"Birleşme","a":"çoktan teke","d":"Birleşmede çok madde tek maddeye dönüşür."},{"t":"Ayrışma","a":"tekten çoka","d":"Ayrışmada tek madde çok maddeye dönüşür; bu yönüyle birleşmenin tersi gibidir."}],"ans":"Evet; birleşme çok maddeyi tek maddeye, ayrışma ise tek maddeyi çok maddeye çevirir, bu yönden birbirinin tersi gibidir."},{"q":"Karbon (C) ile oksijen (O₂) birleşip soluk verdiğimiz gazı oluşturuyorsa bu gaz nedir?","steps":[{"t":"Birleşenler","a":"karbon ve oksijen","d":"Karbon (C) ile oksijen gazı (O₂) birleşir."},{"t":"Ürün","a":"karbondioksit","d":"Birleşme sonucu karbondioksit (CO₂) gazı oluşur."}],"ans":"Karbon ile oksijen birleşince karbondioksit (CO₂) gazı oluşur."}]},"ortaokul":{"kolay":[{"q":"Birleşme (sentez) tepkimesinin genel gösterimi nasıldır?","steps":[{"t":"Girenler","a":"A + B","d":"İki ya da daha çok madde tepkimeye girer."},{"t":"Ürün","a":"AB","d":"Bunlar birleşip tek bir bileşik oluşturur: A + B → AB."}],"ans":"Birleşme tepkimesi A + B → AB biçiminde gösterilir; girenler tek bir üründe birleşir."},{"q":"Ayrışma (analiz) tepkimesinin genel gösterimi nasıldır?","steps":[{"t":"Giren","a":"AB","d":"Tek bir bileşik tepkimeye girer."},{"t":"Ürünler","a":"A + B","d":"Bu bileşik daha basit maddelere ayrılır: AB → A + B."}],"ans":"Ayrışma tepkimesi AB → A + B biçiminde gösterilir; tek bileşik basit maddelere ayrılır."},{"q":"2H₂ + O₂ → 2H₂O denkleminde tepkime türü nedir?","fig":"<svg viewBox='0 0 320 150'><text x='90' y='80' font-size='13' text-anchor='middle' fill='#1a2b45'>2H₂ + O₂</text><text x='160' y='80' font-size='18' text-anchor='middle' fill='#1a2b45'>→</text><text x='240' y='80' font-size='13' text-anchor='middle' fill='#1a2b45'>2H₂O</text><text x='160' y='120' font-size='11' text-anchor='middle' fill='#1a2b45'>iki madde → tek ürün</text></svg>","steps":[{"t":"Girenler","a":"H₂ ve O₂","d":"İki ayrı madde (hidrojen ve oksijen) tepkimeye girer."},{"t":"Ürün","a":"tek madde","d":"Tek ürün (su) oluştuğu için bu bir birleşme (sentez) tepkimesidir."}],"ans":"2H₂ + O₂ → 2H₂O tepkimesi bir birleşme (sentez) tepkimesidir."},{"q":"CaCO₃ → CaO + CO₂ denkleminde tepkime türü nedir?","steps":[{"t":"Giren","a":"CaCO₃","d":"Tek bir bileşik (kalsiyum karbonat) tepkimeye girer."},{"t":"Ürünler","a":"iki madde","d":"İki ürüne (CaO ve CO₂) ayrıldığı için bu bir ayrışma (analiz) tepkimesidir."}],"ans":"CaCO₃ → CaO + CO₂ tepkimesi bir ayrışma (analiz) tepkimesidir."},{"q":"Tepkimelerde kütlenin korunumu yasası ne der?","steps":[{"t":"Atomlar yok olmaz","a":"korunur","d":"Tepkimede atomlar yok olmaz ya da yoktan var olmaz, sadece yeniden dizilir."},{"t":"Kütle eşit","a":"giren = çıkan","d":"Bu yüzden girenlerin toplam kütlesi, ürünlerin toplam kütlesine eşittir."}],"ans":"Kütlenin korunumu yasasına göre tepkimede atom sayısı korunur; girenlerin kütlesi ürünlerin kütlesine eşittir."}],"zor":[{"q":"2H₂ + O₂ → 2H₂O denklemi neden denktir, atomları sayarak açıklayınız.","steps":[{"t":"Hidrojen sayımı","a":"4 = 4","d":"Solda 2H₂ → 4 H atomu; sağda 2H₂O → 4 H atomu, eşittir."},{"t":"Oksijen sayımı","a":"2 = 2","d":"Solda O₂ → 2 O atomu; sağda 2H₂O → 2 O atomu, eşittir."}],"ans":"Hem hidrojen (4 = 4) hem oksijen (2 = 2) atom sayısı iki tarafta eşit olduğundan denklem denktir."},{"q":"2Na + Cl₂ → 2NaCl birleşme tepkimesinde atom sayıları nasıl denkleşir?","fig":"<svg viewBox='0 0 320 150'><circle cx='55' cy='75' r='16' fill='#cfd8e8' stroke='#1a2b45'/><text x='55' y='80' font-size='10' text-anchor='middle' fill='#1a2b45'>Na</text><text x='95' y='80' font-size='14' text-anchor='middle' fill='#1a2b45'>+</text><circle cx='135' cy='75' r='16' fill='#9ed9a8' stroke='#1a2b45'/><text x='135' y='80' font-size='10' text-anchor='middle' fill='#1a2b45'>Cl₂</text><text x='180' y='80' font-size='16' text-anchor='middle' fill='#1a2b45'>→</text><text x='250' y='80' font-size='12' text-anchor='middle' fill='#1a2b45'>2NaCl</text></svg>","steps":[{"t":"Klor sayımı","a":"2 = 2","d":"Solda Cl₂ → 2 Cl atomu; sağda 2NaCl → 2 Cl atomu, eşit."},{"t":"Sodyum sayımı","a":"2 = 2","d":"Sağda 2 Cl olduğundan 2 NaCl gerekir; bu da 2 Na atomu ister, bu yüzden sola 2Na yazılır."}],"ans":"Cl₂ iki klor verdiği için sağda 2NaCl, dolayısıyla solda 2Na gerekir; böylece Na (2 = 2) ve Cl (2 = 2) denkleşir."},{"q":"2H₂O → 2H₂ + O₂ ayrışma tepkimesinin denk olduğunu gösteriniz.","steps":[{"t":"Hidrojen","a":"4 = 4","d":"Solda 2H₂O → 4 H; sağda 2H₂ → 4 H atomu, eşit."},{"t":"Oksijen","a":"2 = 2","d":"Solda 2H₂O → 2 O; sağda O₂ → 2 O atomu, eşit."}],"ans":"Hidrojen (4 = 4) ve oksijen (2 = 2) atom sayıları iki tarafta eşit olduğundan 2H₂O → 2H₂ + O₂ denktir."},{"q":"Bir bileşiğin ayrışması (analiz) genellikle neden enerji gerektirir?","steps":[{"t":"Bağ kırma","a":"enerji ister","d":"Ayrışmada var olan bağların koparılması gerekir, bunun için dışarıdan enerji (ısı, elektrik) verilir."},{"t":"Sonuç","a":"endotermik","d":"Enerji dışarıdan alındığı için ayrışma çoğunlukla endotermiktir; örneğin su elektrik akımıyla ayrışır."}],"ans":"Ayrışmada bağların kırılması için dışarıdan enerji gerektiğinden bu tepkimeler çoğunlukla endotermiktir (örneğin suyun elektrikle ayrışması)."},{"q":"N₂ + 3H₂ → 2NH₃ (amonyak sentezi) tepkimesinde hangi atom sayıları kontrol edilmelidir ve denk midir?","fig":"<svg viewBox='0 0 320 150'><text x='70' y='75' font-size='12' text-anchor='middle' fill='#1a2b45'>N₂ + 3H₂</text><text x='150' y='75' font-size='16' text-anchor='middle' fill='#1a2b45'>→</text><text x='220' y='75' font-size='12' text-anchor='middle' fill='#1a2b45'>2NH₃</text><text x='160' y='115' font-size='10' text-anchor='middle' fill='#1a2b45'>N: 2=2   H: 6=6</text></svg>","steps":[{"t":"Azot","a":"2 = 2","d":"Solda N₂ → 2 N atomu; sağda 2NH₃ → 2 N atomu, eşit."},{"t":"Hidrojen","a":"6 = 6","d":"Solda 3H₂ → 6 H atomu; sağda 2NH₃ → 6 H atomu, eşit."}],"ans":"Azot (2 = 2) ve hidrojen (6 = 6) atom sayıları iki tarafta eşit olduğundan N₂ + 3H₂ → 2NH₃ denktir; bu bir birleşme (sentez) tepkimesidir."}]},"lise":{"kolay":[{"q":"Sentez (birleşme) tepkimesi nasıl tanımlanır ve genel formu nedir?","steps":[{"t":"Tanım","a":"birleşme","d":"İki ya da daha çok madde birleşerek tek bir ürün (bileşik) oluşturur."},{"t":"Genel form","a":"A + B → AB","d":"Genel olarak A + B → AB biçimindedir; örnek: 2H₂ + O₂ → 2H₂O."}],"ans":"Sentez tepkimesi, A + B → AB biçiminde iki veya daha çok maddenin birleşip tek ürün oluşturduğu tepkimedir."},{"q":"Analiz (ayrışma) tepkimesi nasıl tanımlanır ve genel formu nedir?","steps":[{"t":"Tanım","a":"ayrışma","d":"Tek bir bileşik, ısı/ışık/elektrik etkisiyle daha basit maddelere ayrılır."},{"t":"Genel form","a":"AB → A + B","d":"Genel olarak AB → A + B biçimindedir; örnek: CaCO₃ → CaO + CO₂."}],"ans":"Analiz tepkimesi, AB → A + B biçiminde tek bileşiğin daha basit maddelere ayrıldığı tepkimedir."},{"q":"Sentez tepkimeleri enerji açısından genellikle nasıldır?","steps":[{"t":"Bağ oluşumu","a":"enerji salar","d":"Birleşmede yeni bağlar oluşur, bağ oluşumu enerji açığa çıkarır."},{"t":"Tür","a":"ekzotermik","d":"Bu nedenle sentez tepkimeleri çoğunlukla ekzotermiktir (ısı verir)."}],"ans":"Sentez tepkimelerinde yeni bağlar oluştuğundan enerji açığa çıkar; bu yüzden çoğunlukla ekzotermiktir."},{"q":"Analiz tepkimeleri enerji açısından genellikle nasıldır?","steps":[{"t":"Bağ kırma","a":"enerji ister","d":"Ayrışmada var olan bağlar kırılır; bağ kırma dışarıdan enerji gerektirir."},{"t":"Tür","a":"endotermik","d":"Bu nedenle analiz tepkimeleri çoğunlukla endotermiktir (ısı, ışık veya elektrik enerjisi alır)."}],"ans":"Analiz tepkimelerinde bağlar kırıldığından dışarıdan enerji gerekir; bu yüzden çoğunlukla endotermiktir."},{"q":"CaCO₃ → CaO + CO₂ tepkimesi nerede sınai olarak kullanılır ve türü nedir?","steps":[{"t":"Tür","a":"ayrışma","d":"Tek bileşik (CaCO₃) iki ürüne ayrıldığından bu bir ayrışma (analiz) tepkimesidir."},{"t":"Kullanım","a":"kireç üretimi","d":"Kireç taşı yüksek sıcaklıkta ısıtılarak sönmemiş kireç (CaO) ve karbondioksit (CO₂) elde edilir; çimento ve kireç sanayisinde kullanılır."}],"ans":"CaCO₃ → CaO + CO₂ bir ayrışma tepkimesidir ve sanayide kireç (CaO) üretiminde kullanılır."}],"zor":[{"q":"N₂ + 3H₂ ⇌ 2NH₃ amonyak sentezinin denk olduğunu ve neden denge tepkimesi olduğunu açıklayınız.","fig":"<svg viewBox='0 0 320 150'><text x='65' y='70' font-size='12' text-anchor='middle' fill='#1a2b45'>N₂ + 3H₂</text><text x='150' y='70' font-size='16' text-anchor='middle' fill='#1a2b45'>⇌</text><text x='225' y='70' font-size='12' text-anchor='middle' fill='#1a2b45'>2NH₃</text><text x='160' y='110' font-size='10' text-anchor='middle' fill='#1a2b45'>N: 2=2   H: 6=6   tersinir</text></svg>","steps":[{"t":"Denklik","a":"N 2=2, H 6=6","d":"Solda N₂ ve 3H₂ → 2 N ve 6 H; sağda 2NH₃ → 2 N ve 6 H atomu; iki taraf eşit, denklem denktir."},{"t":"Denge","a":"çift yön","d":"Tepkime hem ileri (sentez) hem geri (ayrışma) yürüyebildiği için tersinirdir; ⇌ ile gösterilir ve dinamik dengeye ulaşır (Le Chatelier ilkesiyle yorumlanır)."}],"ans":"N (2 = 2) ve H (6 = 6) atomları eşit olduğundan denklem denktir; tepkime ileri ve geri yönde yürüyebildiğinden tersinir bir denge tepkimesidir (⇌)."},{"q":"2KClO₃ → 2KCl + 3O₂ ayrışma tepkimesinin denk olduğunu atom sayımıyla gösteriniz.","steps":[{"t":"K ve Cl","a":"2 = 2","d":"Solda 2KClO₃ → 2 K ve 2 Cl; sağda 2KCl → 2 K ve 2 Cl atomu; eşit."},{"t":"Oksijen","a":"6 = 6","d":"Solda 2KClO₃ → 6 O atomu; sağda 3O₂ → 6 O atomu; eşit, denklem denktir."}],"ans":"K (2 = 2), Cl (2 = 2) ve O (6 = 6) atom sayıları iki tarafta eşit olduğundan 2KClO₃ → 2KCl + 3O₂ denktir; bu bir analiz (ayrışma) tepkimesidir."},{"q":"Sentez ve analiz tepkimelerini bağ enerjisi ve entalpi (ΔH) açısından karşılaştırınız.","steps":[{"t":"Sentez","a":"ΔH genelde < 0","d":"Sentezde net olarak yeni ve daha kararlı bağlar oluşur; salınan enerji baskın olduğundan ΔH genellikle negatiftir (ekzotermik)."},{"t":"Analiz","a":"ΔH genelde > 0","d":"Analizde kararlı bağların kırılması için enerji gerekir; soğurulan enerji baskın olduğundan ΔH genellikle pozitiftir (endotermik)."}],"ans":"Sentezde bağ oluşumu baskındır ve ΔH genelde negatiftir (ekzotermik); analizde bağ kırılması baskındır ve ΔH genelde pozitiftir (endotermik). İkisi enerji yönü bakımından çoğunlukla ters işaretlidir."},{"q":"3,2 g metan (CH₄) yerine 4 g O₂ kullanarak 2H₂O → 2H₂ + O₂ ayrışmasından üretilebilecek O₂ mantığına benzer biçimde: 36 g suyun tamamen ayrışmasından NK'de kaç litre O₂ açığa çıkar? (H=1, O=16)","steps":[{"t":"Mol su","a":"2 mol","d":"Su molmüktarı 18 g/mol; mol = 36 / 18 = 2 mol H₂O."},{"t":"Mol oranı","a":"2 H₂O → 1 O₂","d":"2H₂O → 2H₂ + O₂ denklemine göre 2 mol su 1 mol O₂ verir; 2 mol su → 1 mol O₂."},{"t":"Hacim","a":"22,4 L","d":"NK'de 1 mol gaz 22,4 L; 1 mol O₂ → 1 × 22,4 = 22,4 L."}],"ans":"36 g su 2 mol eder; 2H₂O → 2H₂ + O₂ oranıyla 1 mol O₂ açığa çıkar ve NK'de bu 22,4 litredir."},{"q":"2H₂ + O₂ → 2H₂O tepkimesinde 4 g H₂ ile yeterli O₂ kullanılırsa kaç gram su oluşur? (H=1, O=16)","fig":"<svg viewBox='0 0 320 140'><text x='80' y='65' font-size='12' text-anchor='middle' fill='#1a2b45'>2H₂ + O₂</text><text x='155' y='65' font-size='16' text-anchor='middle' fill='#1a2b45'>→</text><text x='220' y='65' font-size='12' text-anchor='middle' fill='#1a2b45'>2H₂O</text><text x='160' y='105' font-size='10' text-anchor='middle' fill='#1a2b45'>2 mol : 2 mol</text></svg>","steps":[{"t":"Mol H₂","a":"2 mol","d":"H₂ molmüktarı 2 g/mol; mol = 4 / 2 = 2 mol H₂."},{"t":"Mol oranı","a":"2 H₂ → 2 H₂O","d":"Denkleme göre 2 mol H₂, 2 mol H₂O verir; 2 mol H₂ → 2 mol H₂O."},{"t":"Kütle","a":"36 g","d":"Su molmüktarı 18 g/mol; 2 mol × 18 g/mol = 36 g su."}],"ans":"4 g H₂ → 2 mol H₂; 2H₂ + O₂ → 2H₂O oranıyla 2 mol (36 g) su oluşur."}]}},"sicaklikEtki":{"ilkokul":{"kolay":[{"q":"Bir şeker sıcak suda mı yoksa soğuk suda mı daha çabuk çözünür?","fig":"<svg viewBox='0 0 320 160'><rect x='40' y='40' width='90' height='100' fill='#ffd9c2' stroke='#1a2b45'/><circle cx='85' cy='90' r='10' fill='#fff' stroke='#1a2b45'/><text x='85' y='155' font-size='11' text-anchor='middle' fill='#e0552b'>sıcak su</text><rect x='190' y='40' width='90' height='100' fill='#cfe3ff' stroke='#1a2b45'/><circle cx='235' cy='90' r='10' fill='#fff' stroke='#1a2b45'/><text x='235' y='155' font-size='11' text-anchor='middle' fill='#2b6be0'>soğuk su</text></svg>","steps":[{"t":"Sıcak su","a":"hızlı tanecik","d":"Sıcak suda tanecikler daha hızlı hareket eder."},{"t":"Sonuç","a":"çabuk çözünür","d":"Hızlı hareket eden tanecikler şekeri daha çabuk çözer."}],"ans":"Şeker sıcak suda daha çabuk çözünür, çünkü tanecikler hızlı hareket eder."},{"q":"Sıcaklık artınca tanecikler daha hızlı mı yoksa daha yavaş mı hareket eder?","steps":[{"t":"Isı verilir","a":"enerji artar","d":"Sıcaklık artınca tanecikler daha çok enerji kazanır."},{"t":"Hareket","a":"hızlanır","d":"Enerji artınca tanecikler daha hızlı hareket eder."}],"ans":"Sıcaklık artınca tanecikler daha hızlı hareket eder."},{"q":"Yemekler buzdolabında neden geç bozulur?","steps":[{"t":"Soğuk","a":"yavaş tanecik","d":"Buzdolabı soğuk olduğundan tanecikler yavaş hareket eder."},{"t":"Bozulma","a":"yavaşlar","d":"Yavaş tanecikler bozulma tepkimelerini de yavaşlatır."}],"ans":"Buzdolabı soğuk olduğu için tanecikler yavaşlar ve yemekler geç bozulur."},{"q":"Sıcak bir ortamda tepkimeler daha hızlı mı olur?","steps":[{"t":"Sıcaklık","a":"hızlı tanecik","d":"Sıcak ortamda tanecikler hızlı hareket edip sık çarpışır."},{"t":"Sonuç","a":"hızlanır","d":"Bu yüzden sıcak ortamda tepkimeler daha hızlı olur."}],"ans":"Evet, sıcak ortamda tanecikler hızlı çarpıştığı için tepkimeler daha hızlı olur."},{"q":"Soğuk su mu sıcak su mu kahveyi daha çabuk eritir?","steps":[{"t":"Sıcak su","a":"hızlı tanecik","d":"Sıcak suda tanecikler hızlıdır ve kahveyi çabuk eritir."},{"t":"Soğuk su","a":"yavaş","d":"Soğuk suda tanecikler yavaş olduğundan kahve geç erir."}],"ans":"Sıcak su kahveyi daha çabuk eritir, çünkü tanecikleri hızlı hareket eder."}],"zor":[{"q":"Sıcaklık artınca tepkime neden hızlanır? İki nedenini söyleyiniz.","steps":[{"t":"Hızlı çarpışma","a":"sık çarpışma","d":"Sıcaklık artınca tanecikler hızlanır, daha sık çarpışır."},{"t":"Güçlü çarpışma","a":"daha güçlü","d":"Tanecikler daha hızlı olduğundan çarpışmaları da daha güçlü ve etkili olur."}],"ans":"Sıcaklık artınca tanecikler hem daha sık hem de daha güçlü çarpıştığı için tepkime hızlanır."},{"q":"Bir tepkimeyi yavaşlatmak istersek sıcaklığı artırmalı mıyız azaltmalı mıyız?","steps":[{"t":"Yavaşlatmak","a":"soğutmak","d":"Tepkimeyi yavaşlatmak için ortamı soğutmak gerekir."},{"t":"Neden","a":"yavaş tanecik","d":"Soğuyunca tanecikler yavaşlar, çarpışmalar azalır ve tepkime yavaşlar."}],"ans":"Tepkimeyi yavaşlatmak için sıcaklığı azaltmalıyız; soğuyunca tanecikler yavaşlar."},{"q":"İki özdeş tepkimeden biri sıcak biri soğuk ortamda. Hangisi önce biter?","fig":"<svg viewBox='0 0 320 150'><rect x='35' y='35' width='100' height='90' fill='#ffd9c2' stroke='#1a2b45'/><circle cx='60' cy='60' r='5' fill='#e0552b'/><circle cx='100' cy='70' r='5' fill='#e0552b'/><circle cx='80' cy='100' r='5' fill='#e0552b'/><text x='85' y='142' font-size='10' text-anchor='middle' fill='#e0552b'>sıcak</text><rect x='185' y='35' width='100' height='90' fill='#cfe3ff' stroke='#1a2b45'/><circle cx='210' cy='65' r='5' fill='#2b6be0'/><circle cx='255' cy='95' r='5' fill='#2b6be0'/><text x='235' y='142' font-size='10' text-anchor='middle' fill='#2b6be0'>soğuk</text></svg>","steps":[{"t":"Sıcak ortam","a":"hızlı tanecik","d":"Sıcak ortamda tanecikler hızlı hareket eder ve sık çarpışır."},{"t":"Sonuç","a":"sıcak biter","d":"Bu yüzden sıcak ortamdaki tepkime daha önce biter."}],"ans":"Sıcak ortamdaki tepkime daha hızlı olduğu için önce biter."},{"q":"Süt neden sıcakta çabuk, dolapta geç ekşir?","steps":[{"t":"Sıcakta","a":"hızlı tepkime","d":"Sıcakta tanecikler hızlandığından ekşime tepkimesi hızlanır."},{"t":"Dolapta","a":"yavaş tepkime","d":"Dolap soğuk olduğundan tanecikler yavaşlar ve ekşime gecikir."}],"ans":"Sıcakta tanecikler hızlanıp ekşime tepkimesini hızlandırır; dolapta soğuk olduğundan tanecikler yavaşlar ve süt geç ekşir."},{"q":"Kıvılcımla yanmaya başlayan odun neden sıcak havada daha kolay tutuşur?","steps":[{"t":"Sıcak hava","a":"enerjili tanecik","d":"Sıcak havada tanecikler daha çok enerjiye ve hıza sahiptir."},{"t":"Tutuşma","a":"kolaylaşır","d":"Enerjili tanecikler yanma tepkimesini daha kolay başlatır."}],"ans":"Sıcak havada tanecikler daha enerjili olduğundan yanma tepkimesi daha kolay başlar ve odun daha çabuk tutuşur."}]},"ortaokul":{"kolay":[{"q":"Sıcaklık artışı tepkime hızını nasıl etkiler ve neden?","steps":[{"t":"Tanecik enerjisi","a":"artar","d":"Sıcaklık artınca taneciklerin hızı ve enerjisi artar."},{"t":"Çarpışma","a":"sık ve etkili","d":"Tanecikler hem daha sık hem de yeterli enerjiyle çarpışır, bu yüzden tepkime hızlanır."}],"ans":"Sıcaklık artınca taneciklerin hız ve enerjisi artar; çarpışmalar hem sıklaşır hem de etkili hale geldiğinden tepkime hızı artar."},{"q":"Tepkime hızı kuralına göre sıcaklık her 10 °C arttığında hız yaklaşık nasıl değişir?","steps":[{"t":"Genel kural","a":"yaklaşık 2 kat","d":"Birçok tepkimede sıcaklık her 10 °C arttığında hız yaklaşık iki katına çıkar."},{"t":"Neden","a":"etkin çarpışma artar","d":"Çünkü yüksek sıcaklıkta yeterli enerjili (etkin) çarpışma sayısı belirgin artar."}],"ans":"Birçok tepkimede sıcaklık her 10 °C arttığında hız yaklaşık iki katına çıkar."},{"q":"Yiyecekleri dondurarak saklamak bozulmayı neden yavaşlatır?","fig":"<svg viewBox='0 0 320 150'><rect x='90' y='30' width='140' height='90' fill='#cfe3ff' stroke='#1a2b45'/><circle cx='120' cy='55' r='6' fill='#5b6b85'/><circle cx='160' cy='90' r='6' fill='#5b6b85'/><circle cx='200' cy='60' r='6' fill='#5b6b85'/><text x='160' y='140' font-size='11' text-anchor='middle' fill='#2b6be0'>düşük sıcaklık → yavaş tanecik</text></svg>","steps":[{"t":"Düşük sıcaklık","a":"yavaş tanecik","d":"Donma sıcaklığında tanecikler çok yavaş hareket eder."},{"t":"Tepkime","a":"yavaşlar","d":"Bozulmaya yol açan tepkimeler çok yavaşladığı için yiyecek uzun süre dayanır."}],"ans":"Düşük sıcaklıkta tanecikler çok yavaşladığından bozulma tepkimeleri yavaşlar ve yiyecekler uzun süre saklanabilir."},{"q":"Sıcaklık düşürülürse tepkime hızı nasıl değişir?","steps":[{"t":"Soğuma","a":"enerji azalır","d":"Sıcaklık düşünce taneciklerin hız ve enerjisi azalır."},{"t":"Hız","a":"azalır","d":"Çarpışmalar hem seyrekleşir hem zayıflar, tepkime yavaşlar."}],"ans":"Sıcaklık düşünce tanecik enerjisi azalır; çarpışmalar seyrekleşip zayıfladığından tepkime hızı azalır."},{"q":"Neden ateşi körüklemek (hava + sıcaklık) yanmayı hızlandırır?","steps":[{"t":"Sıcaklık","a":"hızlı tanecik","d":"Yüksek sıcaklık tanecikleri hızlandırıp enerjilerini artırır."},{"t":"Etkin çarpışma","a":"çoğalır","d":"Eşik enerjiyi aşan etkin çarpışmalar çoğaldığından yanma tepkimesi hızlanır."}],"ans":"Sıcaklık artışı tanecikleri hızlandırır ve eşik enerjiyi aşan etkin çarpışmaları çoğalttığı için yanma hızlanır."}],"zor":[{"q":"Sıcaklık 20 °C'den 50 °C'ye çıkarılırsa, her 10 °C'de hız 2 kat oluyorsa hız yaklaşık kaç katına çıkar?","fig":"<svg viewBox='0 0 320 120'><text x='160' y='40' font-size='13' text-anchor='middle' fill='#1a2b45'>20 °C → 50 °C : 30 °C artış</text><text x='160' y='70' font-size='13' text-anchor='middle' fill='#1a2b45'>3 × 10 °C  ⇒  2³</text><text x='160' y='100' font-size='14' text-anchor='middle' fill='#1a2b45'>2³ = 8 kat</text></svg>","steps":[{"t":"Sıcaklık farkı","a":"30 °C","d":"50 − 20 = 30 °C'lik bir artış vardır, bu üç tane 10 °C'lik basamaktır."},{"t":"Hesap","a":"2³ = 8","d":"Her 10 °C'de hız 2 katına çıktığından toplam 2×2×2 = 2³ = 8 kat olur."}],"ans":"30 °C'lik artış üç tane 10 °C basamağıdır; hız 2³ = 8 katına çıkar."},{"q":"Sıcaklık artışı tepkime hızını hangi iki ayrı etkiyle artırır? Hangisi daha baskındır?","steps":[{"t":"Çarpışma sıklığı","a":"biraz artar","d":"Tanecikler hızlandığından birim zamanda biraz daha sık çarpışır."},{"t":"Etkin çarpışma oranı","a":"çok artar","d":"Eşik (aktivasyon) enerjisini aşabilen tanecik oranı sıcaklıkla hızla büyür."},{"t":"Baskın etki","a":"etkin çarpışma","d":"Hızdaki büyük artışın asıl nedeni, eşik enerjiyi aşan etkin çarpışma oranının çok artmasıdır."}],"ans":"Sıcaklık hem çarpışma sıklığını biraz hem de eşik enerjiyi aşan etkin çarpışma oranını çok artırır; asıl baskın etki etkin çarpışma oranındaki büyük artıştır."},{"q":"Sıcaklık artışının taneciklerin enerji dağılımına etkisini ve etkin çarpışmaya yansımasını açıklayınız.","fig":"<svg viewBox='0 0 320 160'><line x1='40' y1='130' x2='290' y2='130' stroke='#1a2b45'/><line x1='40' y1='130' x2='40' y2='30' stroke='#1a2b45'/><path d='M40 130 Q90 45 150 75 T280 125' fill='none' stroke='#2b6be0' stroke-width='2'/><path d='M40 130 Q120 70 190 80 T285 122' fill='none' stroke='#e0552b' stroke-width='2'/><line x1='215' y1='30' x2='215' y2='130' stroke='#5b6b85' stroke-dasharray='4 4'/><text x='215' y='25' font-size='10' text-anchor='middle' fill='#1a2b45'>Ea</text><text x='250' y='50' font-size='10' fill='#e0552b'>yüksek T</text><text x='95' y='50' font-size='10' fill='#2b6be0'>düşük T</text></svg>","steps":[{"t":"Enerji dağılımı","a":"tanecikler farklı enerjide","d":"Bir örnekte tanecikler farklı hızlarda olduğundan farklı enerjilere sahiptir; bu bir dağılım eğrisiyle gösterilir."},{"t":"Sıcaklık artışı","a":"eğri sağa kayar","d":"Sıcaklık artınca eğri sağa-aşağıya kayar; eşik enerji (Ea) sağındaki tanecik oranı belirgin artar."},{"t":"Sonuç","a":"etkin çarpışma artar","d":"Ea'yı aşan tanecik oranı arttığından etkin çarpışma sayısı çoğalır ve tepkime hızlanır."}],"ans":"Sıcaklık artınca tanecik enerji dağılımı yüksek enerjilere kayar; eşik enerji Ea'yı aşabilen tanecik oranı belirgin biçimde artar, bu da etkin çarpışmaları çoğaltarak tepkime hızını yükseltir."},{"q":"Hem endotermik hem ekzotermik tepkimelerin hızı sıcaklık artışıyla neden artar?","steps":[{"t":"Hız vs ısı türü","a":"bağımsız","d":"Tepkimenin ısı alması (endotermik) ya da vermesi (ekzotermik) tepkime hızını doğrudan belirlemez."},{"t":"Sıcaklık etkisi","a":"her ikisinde aynı","d":"Sıcaklık artışı her iki tür tepkimede de tanecik enerjisini ve etkin çarpışmayı artırır."},{"t":"Sonuç","a":"ikisi de hızlanır","d":"Bu yüzden ısı türünden bağımsız olarak sıcaklık artınca hem endotermik hem ekzotermik tepkimenin hızı artar."}],"ans":"Sıcaklık artışı, tepkimenin ısı alıp vermesinden bağımsız olarak tanecik enerjisini ve eşik enerjiyi aşan etkin çarpışma oranını artırdığından hem endotermik hem ekzotermik tepkimelerin hızı artar."},{"q":"Soğutmanın (örneğin buz banyosu) bir tepkimeyi kontrol altında tutmak için kullanılmasını tanecik düzeyinde açıklayınız.","steps":[{"t":"Soğutma","a":"enerji azalır","d":"Buz banyosu sıcaklığı düşürerek taneciklerin enerjisini azaltır."},{"t":"Etkin çarpışma","a":"azalır","d":"Eşik enerjiyi aşabilen tanecik oranı düştüğünden etkin çarpışma sayısı azalır."},{"t":"Sonuç","a":"hız kontrolü","d":"Tepkime yavaşlar; böylece hızlı/aşırı ısınan (kontrolsüz) tepkime güvenli biçimde yavaşlatılmış olur."}],"ans":"Soğutma tanecik enerjisini düşürüp eşik enerjiyi aşan etkin çarpışma oranını azaltır; tepkime yavaşladığından hızlı ve aşırı ısı veren tepkimeler güvenli biçimde kontrol altında tutulur."}]},"lise":{"kolay":[{"q":"Sıcaklık artışının tepkime hızını artırmasını çarpışma kuramı ve aktivasyon enerjisiyle açıklayınız.","steps":[{"t":"Çarpışma sıklığı","a":"artar","d":"Sıcaklık artınca taneciklerin ortalama hızı (kinetik enerjisi) artar, birim zamandaki çarpışma sayısı çoğalır."},{"t":"Etkin çarpışma oranı","a":"belirgin artar","d":"Aktivasyon enerjisi (Ea) eşiğini aşabilen tanecik oranı sıcaklıkla üstel biçimde büyür."},{"t":"Sonuç","a":"hız artar","d":"Hem çarpışma sıklığı hem de etkin çarpışma oranı arttığından tepkime hızı belirgin yükselir."}],"ans":"Sıcaklık artınca tanecik kinetik enerjisi yükselir; çarpışma sıklığı biraz, Ea eşiğini aşan etkin çarpışma oranı ise üstel biçimde artar. İki etki birleşince tepkime hızı belirgin biçimde artar."},{"q":"Aktivasyon enerjisi (Ea) nedir ve tepkime hızını nasıl belirler?","steps":[{"t":"Tanım","a":"eşik enerji","d":"Aktivasyon enerjisi, tepken taneciklerin aktifleşmiş kompleksi (geçiş hâli) oluşturup tepkimeye girmesi için gereken en az enerjidir."},{"t":"Hıza etki","a":"yüksek Ea → yavaş","d":"Ea ne kadar büyükse onu aşabilen tanecik oranı o kadar azdır, tepkime o kadar yavaştır."}],"ans":"Aktivasyon enerjisi tepkimenin başlaması için gereken en az enerjidir; Ea büyüdükçe eşiği aşan tanecik oranı azalır ve tepkime yavaşlar."},{"q":"Maxwell-Boltzmann enerji dağılımına göre sıcaklık artınca etkin çarpışma sayısı neden artar?","fig":"<svg viewBox='0 0 320 160'><line x1='40' y1='130' x2='290' y2='130' stroke='#1a2b45'/><line x1='40' y1='130' x2='40' y2='30' stroke='#1a2b45'/><path d='M40 130 Q90 45 150 75 T280 125' fill='none' stroke='#2b6be0' stroke-width='2'/><path d='M40 130 Q120 72 195 82 T285 122' fill='none' stroke='#e0552b' stroke-width='2'/><line x1='210' y1='30' x2='210' y2='130' stroke='#5b6b85' stroke-dasharray='4 4'/><text x='210' y='25' font-size='10' text-anchor='middle' fill='#1a2b45'>Ea</text><text x='150' y='150' font-size='10' text-anchor='middle' fill='#1a2b45'>enerji →</text></svg>","steps":[{"t":"Dağılım","a":"enerjilere yayılım","d":"Maxwell-Boltzmann dağılımı, bir örnekteki taneciklerin sahip olduğu enerjilerin dağılımını gösterir."},{"t":"Sıcaklık artışı","a":"sağa kayma","d":"Sıcaklık artınca eğri sağa kayıp yayvanlaşır; Ea'nın sağında kalan (eşiği aşan) alan büyür."},{"t":"Sonuç","a":"etkin çarpışma artar","d":"Ea'yı aşan tanecik oranı arttığından etkin çarpışma sayısı, dolayısıyla hız artar."}],"ans":"Maxwell-Boltzmann dağılımına göre sıcaklık artınca eğri yüksek enerjilere kayar ve Ea'nın sağındaki tanecik oranı büyür; eşiği aşan etkin çarpışmalar çoğaldığından tepkime hızı artar."},{"q":"Yaklaşık kural olarak sıcaklık her 10 °C arttığında hızın ~2 katına çıkmasının nedeni nedir?","steps":[{"t":"Gözlem","a":"~2 kat","d":"Birçok tepkimede 10 °C'lik artış hızı yaklaşık iki katına çıkarır (yaklaşık kural)."},{"t":"Neden","a":"Ea'yı aşan oran","d":"Bu artışın asıl nedeni çarpışma sıklığı değil; küçük sıcaklık artışının bile Ea'yı aşan tanecik oranını belirgin (üstel) biçimde büyütmesidir."}],"ans":"Sıcaklık 10 °C arttığında hızın yaklaşık iki katına çıkmasının nedeni, çarpışma sıklığındaki küçük artıştan çok, aktivasyon enerjisini aşan etkin tanecik oranının üstel biçimde büyümesidir."},{"q":"Katalizör ile sıcaklık artışı hızı artırma bakımından nasıl farklıdır?","steps":[{"t":"Sıcaklık","a":"daha çok enerjili tanecik","d":"Sıcaklık artışı taneciklere enerji vererek Ea'yı aşan tanecik oranını artırır; Ea'yı değiştirmez."},{"t":"Katalizör","a":"Ea düşürür","d":"Katalizör ise alternatif yol sunarak aktivasyon enerjisini (Ea) düşürür; daha çok tanecik eşiği aşar."}],"ans":"Sıcaklık artışı taneciklere enerji verip Ea'yı aşanları çoğaltır ama Ea'yı değiştirmez; katalizör ise aktivasyon enerjisini düşürerek daha fazla taneciğin eşiği aşmasını sağlar."}],"zor":[{"q":"Arrhenius bağıntısı k = A·e^(−Ea/RT) sıcaklık ile hız sabiti ilişkisini nasıl açıklar?","fig":"<svg viewBox='0 0 320 120'><text x='160' y='45' font-size='15' text-anchor='middle' fill='#1a2b45'>k = A · e^(−Ea / RT)</text><text x='160' y='80' font-size='12' text-anchor='middle' fill='#1a2b45'>T ↑  ⇒  Ea/RT ↓  ⇒  k ↑</text></svg>","steps":[{"t":"Bağıntı","a":"k = A·e^(−Ea/RT)","d":"Arrhenius bağıntısında k hız sabiti; A çarpışma çarpanı, Ea aktivasyon enerjisi, R gaz sabiti, T mutlak sıcaklıktır."},{"t":"Sıcaklık etkisi","a":"üstel terim","d":"T artınca Ea/RT küçülür, e^(−Ea/RT) terimi büyür, dolayısıyla k artar."},{"t":"Sonuç","a":"hız artar","d":"k üstel biçimde arttığından sıcaklık artışı tepkime hızını belirgin biçimde yükseltir."}],"ans":"Arrhenius bağıntısında k = A·e^(−Ea/RT)'dir; sıcaklık (T) artınca Ea/RT küçülür ve e^(−Ea/RT) üstel terimi büyür, böylece hız sabiti k ve dolayısıyla tepkime hızı belirgin biçimde artar."},{"q":"Düşük aktivasyon enerjili bir tepkime, yüksek aktivasyon enerjili bir tepkimeye göre sıcaklık değişimine neden daha az duyarlıdır?","steps":[{"t":"Arrhenius","a":"k = A·e^(−Ea/RT)","d":"Hız sabitinin sıcaklığa duyarlılığı üsteldeki Ea terimine bağlıdır."},{"t":"Düşük Ea","a":"az duyarlı","d":"Ea küçükse Ea/RT zaten küçüktür; sıcaklık değişimi e^(−Ea/RT) terimini görece az değiştirir."},{"t":"Yüksek Ea","a":"çok duyarlı","d":"Ea büyükse aynı sıcaklık değişimi üstel terimi çok daha fazla değiştirir, hız sıcaklığa çok daha duyarlı olur."}],"ans":"Arrhenius bağıntısında duyarlılık Ea'ya bağlıdır; düşük Ea'da Ea/RT küçük olduğundan sıcaklık değişimi üstel terimi az değiştirir, bu yüzden düşük aktivasyon enerjili tepkime sıcaklık değişimine daha az duyarlıdır."},{"q":"Sıcaklığı 27 °C'den 37 °C'ye (300 K → 310 K) çıkarmak, 10 °C kuralına göre vücut tepkimelerini hızlandırmasını ve bu kuralın sınırını açıklayınız.","steps":[{"t":"10 °C kuralı","a":"~2 kat","d":"300 K'den 310 K'ye 10 K (10 °C) artış olduğundan yaklaşık kurala göre hız kabaca iki katına çıkar."},{"t":"Mekanizma","a":"etkin çarpışma","d":"Bu artış, Ea'yı aşan tanecik oranının büyümesinden kaynaklanır."},{"t":"Kuralın sınırı","a":"yaklaşıktır","d":"Kural yaklaşıktır; gerçek katsayı Ea'ya bağlıdır (Arrhenius). Yüksek Ea'da 2'den büyük, düşük Ea'da 2'den küçük çıkabilir."}],"ans":"300 K → 310 K (10 °C) artışta yaklaşık kurala göre hız kabaca iki katına çıkar; bu, Ea'yı aşan etkin çarpışma oranının büyümesinden ileri gelir. Ancak kural yaklaşıktır: gerçek artış oranı tepkimenin Ea değerine bağlı olarak 2'den farklı olabilir."},{"q":"Tepkenlerin derişimi sabit tutulurken sadece sıcaklık artırılırsa hız neden artar? Çarpışma sıklığı ve enerji açısından ayırt ediniz.","steps":[{"t":"Derişim sabit","a":"tanecik sayısı aynı","d":"Derişim sabit tutulduğundan birim hacimdeki tanecik sayısı değişmez."},{"t":"Çarpışma sıklığı","a":"hafif artar","d":"Tanecikler hızlandığından birim zamanda biraz daha sık çarpışır (sınırlı katkı)."},{"t":"Etkin çarpışma","a":"baskın artış","d":"Asıl artış, Ea eşiğini aşan etkin çarpışma oranının üstel büyümesinden gelir, bu yüzden hız belirgin artar."}],"ans":"Derişim sabit kaldığından tanecik sayısı değişmez; sıcaklık artışı çarpışma sıklığını hafifçe, Ea eşiğini aşan etkin çarpışma oranını ise üstel biçimde artırır. Asıl belirgin hız artışı bu etkin çarpışma oranındaki büyümeden kaynaklanır."},{"q":"Geri (ters) tepkimenin aktivasyon enerjisi farklı olsa bile sıcaklık artışı hem ileri hem geri tepkimeyi neden hızlandırır?","steps":[{"t":"İki yön","a":"farklı Ea","d":"İleri ve geri tepkimelerin genelde farklı aktivasyon enerjileri vardır."},{"t":"Sıcaklık etkisi","a":"her iki k artar","d":"Arrhenius'a göre sıcaklık artışı her iki yönün hız sabitini (k) de büyütür, çünkü her ikisinde de Ea/RT küçülür."},{"t":"Sonuç","a":"dengeye çabuk ulaşır","d":"Hem ileri hem geri hız arttığından sistem daha çabuk dengeye ulaşır; denge konumu ise tepkimenin ısı türüne (endo/ekzo) göre kayar."}],"ans":"İleri ve geri tepkimelerin Ea'ları farklı olsa da Arrhenius bağıntısına göre sıcaklık artışı her iki yönün hız sabitini de büyütür; böylece hem ileri hem geri tepkime hızlanır ve sistem daha çabuk dengeye ulaşır (denge konumunun kayması ise ayrı bir konudur)."}]}},"temasYuzeyi":{"ilkokul":{"kolay":[{"q":"Toz şeker mi yoksa kesme şeker mi suda daha çabuk erir?","steps":[{"t":"Toz şeker","a":"küçük tanecik","d":"Toz şeker küçük taneciklerden oluşur, suyla her yeri temas eder."},{"t":"Sonuç","a":"çabuk erir","d":"Daha çok temas olduğu için toz şeker suda daha çabuk erir."}],"ans":"Toz şeker küçük taneli olduğu ve suyla çok temas ettiği için daha çabuk erir."},{"q":"Bir odunu kütük hâlinde mi yoksa ince çıralar hâlinde mi tutuşturmak daha kolaydır?","steps":[{"t":"İnce çıra","a":"çok yüzey","d":"İnce çıralar daha çok havayla temas eder."},{"t":"Kolay tutuşur","a":"çabuk yanar","d":"Çok temas olduğu için çıralar kütükten daha kolay ve çabuk tutuşur."}],"ans":"İnce çıralar havayla çok temas ettiği için kütükten daha kolay ve çabuk tutuşur."},{"q":"Bütün bir elma mı yoksa dilimlenmiş elma mı daha çabuk kararır?","steps":[{"t":"Dilimli elma","a":"açık yüzey","d":"Dilimlenince elmanın iç yüzeyi havaya açılır."},{"t":"Çabuk kararır","a":"daha hızlı","d":"Havayla daha çok temas ettiği için dilimli elma daha çabuk kararır."}],"ans":"Dilimlenmiş elma iç yüzeyi havaya açıldığı için bütününden daha çabuk kararır."},{"q":"Tuz hangi hâlde suda daha hızlı çözünür?","fig":"<svg viewBox='0 0 320 150'><rect x='30' y='40' width='40' height='40' fill='#cfd8e8' stroke='#1a2b45'/><text x='50' y='110' font-size='10' text-anchor='middle' fill='#1a2b45'>iri parca</text><circle cx='210' cy='45' r='5' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='230' cy='55' r='5' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='225' cy='70' r='5' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='245' cy='65' r='5' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='205' cy='68' r='5' fill='#cfd8e8' stroke='#1a2b45'/><text x='225' y='110' font-size='10' text-anchor='middle' fill='#1a2b45'>toz hali</text></svg>","steps":[{"t":"Toz hâli","a":"küçük tanecik","d":"İnce öğütülmüş toz tuz küçük taneciklerden oluşur."},{"t":"Sonuç","a":"hızlı çözünür","d":"Daha çok yüzey suyla temas ettiği için toz tuz daha hızlı çözünür."}],"ans":"Toz (ince) hâldeki tuz, suyla daha çok temas ettiği için daha hızlı çözünür."},{"q":"İlaç tableti ile aynı ilacın toz hâli midede hangisi daha çabuk çözülür?","steps":[{"t":"Toz hâli","a":"çok yüzey","d":"Toz ilaç küçük taneciklere ayrılmış olduğu için çok yüzeye sahiptir."},{"t":"Çabuk çözülür","a":"hızlı etki","d":"Daha çok temas olduğu için toz ilaç tabletten daha çabuk çözülür."}],"ans":"Toz hâlindeki ilaç daha çok yüzeye sahip olduğu için tabletten daha çabuk çözülür."}],"zor":[{"q":"Patates kızartırken neden ince doğrananlar kalın doğrananlardan daha çabuk pişer?","steps":[{"t":"İnce dilim","a":"çok yüzey","d":"İnce dilimlerin yüzeyi hacmine göre daha geniştir, yağla çok temas eder."},{"t":"Çabuk pişer","a":"hızlı ısı","d":"Çok temas ısının her yere hızlı ulaşmasını sağlar, ince dilimler çabuk pişer."}],"ans":"İnce dilimlerin yüzeyi geniş olduğu için yağ ve ısıyla çok temas eder, daha çabuk pişer."},{"q":"Bir avuç un, bir somun ekmekten neden çok daha kolay tutuşabilir, hatta patlayabilir?","steps":[{"t":"Un tanecikleri","a":"çok küçük yüzey","d":"Un çok ince taneciklerden oluşur, toplam yüzeyi çok büyüktür."},{"t":"Hızlı yanma","a":"ani tepkime","d":"Havadaki oksijenle bu kadar geniş yüzey ani ve şiddetli yanma (patlama) yapabilir."}],"ans":"Unun tanecikleri çok ince olup büyük yüzey sunduğundan havayla ani ve şiddetli yanabilir."},{"q":"Aynı miktar şekerin küp hâli ile toz hâli çayda eritiliyor. Hangisini karıştırınca daha çabuk çözünür ve neden?","steps":[{"t":"Toz hâli","a":"geniş yüzey","d":"Toz şekerin toplam yüzeyi küp şekerden çok daha büyüktür."},{"t":"Karıştırma","a":"temas artar","d":"Karıştırmak suyu sürekli yeniler; geniş yüzeyle birleşince toz şeker çok daha hızlı çözünür."}],"ans":"Toz şeker geniş yüzeye sahip olduğundan, karıştırınca küp şekerden çok daha hızlı çözünür."},{"q":"Demir bir çivi ile demir tozu havada nemle hangisi daha çabuk paslanır?","steps":[{"t":"Demir tozu","a":"çok yüzey","d":"Demir tozu küçük taneciklere ayrılmış, toplam yüzeyi çok geniştir."},{"t":"Hızlı paslanma","a":"çok temas","d":"Geniş yüzey havadaki oksijen ve nemle çok temas ettiği için toz çabuk paslanır."}],"ans":"Demir tozu çok geniş yüzeye sahip olup oksijenle çok temas ettiği için çividen daha çabuk paslanır."},{"q":"Mangal yakarken kömürü neden önce kırıp küçük parçalara ayırırız?","steps":[{"t":"Küçük parça","a":"çok yüzey","d":"Kömürü kırınca toplam yüzeyi artar, havayla daha çok temas eder."},{"t":"Kolay yanar","a":"hızlı tutuşur","d":"Geniş yüzey oksijenle daha çok temas ettiği için kömür daha kolay ve hızlı tutuşur."}],"ans":"Kömürü kırmak yüzeyini artırır, oksijenle daha çok temas ettiği için daha kolay ve hızlı tutuşur."}]},"ortaokul":{"kolay":[{"q":"Temas yüzeyi arttıkça tepkime hızı nasıl değişir?","steps":[{"t":"Geniş yüzey","a":"çok çarpışma","d":"Yüzey arttıkça tepkimeye giren tanecikler birbirine daha çok temas eder."},{"t":"Hız","a":"artar","d":"Daha çok temas (çarpışma) tepkime hızını artırır."}],"ans":"Temas yüzeyi arttıkça tanecikler daha çok çarpışır, bu yüzden tepkime hızı artar."},{"q":"Bir maddeyi toz hâline getirmek tepkime hızını neden artırır?","steps":[{"t":"Parçalama","a":"yüzey artar","d":"Bir maddeyi öğütmek toplam yüzey alanını çok artırır."},{"t":"Hız","a":"yükselir","d":"Artan yüzey daha çok temas demektir, tepkime hızlanır."}],"ans":"Toz hâline getirmek toplam yüzey alanını artırdığı için tepkime hızlanır."},{"q":"Aynı kütlede mermer tozu mu yoksa mermer parçası mı asitle daha hızlı tepkir?","steps":[{"t":"Mermer tozu","a":"geniş yüzey","d":"Toz hâli aynı kütlede çok daha geniş yüzeye sahiptir."},{"t":"Hızlı tepkime","a":"çok temas","d":"Asitle daha çok yüzey temas ettiği için toz daha hızlı tepkir."}],"ans":"Mermer tozu aynı kütlede daha geniş yüzeye sahip olduğu için asitle daha hızlı tepkir."},{"q":"Yüzey alanının tepkime hızına etkisi günlük hayatta nerelerde görülür?","fig":"<svg viewBox='0 0 320 150'><rect x='40' y='50' width='50' height='50' fill='#cfd8e8' stroke='#1a2b45'/><text x='65' y='120' font-size='10' text-anchor='middle' fill='#1a2b45'>butun</text><rect x='180' y='50' width='24' height='24' fill='#cfd8e8' stroke='#1a2b45'/><rect x='210' y='50' width='24' height='24' fill='#cfd8e8' stroke='#1a2b45'/><rect x='180' y='80' width='24' height='24' fill='#cfd8e8' stroke='#1a2b45'/><rect x='210' y='80' width='24' height='24' fill='#cfd8e8' stroke='#1a2b45'/><text x='207' y='120' font-size='10' text-anchor='middle' fill='#1a2b45'>parcalanmis</text></svg>","steps":[{"t":"Örnekler","a":"çıra, toz ilaç, kömür","d":"İnce çıranın tutuşması, toz ilacın çabuk çözülmesi, kırık kömürün hızlı yanması örnektir."},{"t":"Ortak nokta","a":"yüzey artışı","d":"Hepsinde madde parçalanarak yüzey artırılır ve tepkime hızlanır."}],"ans":"Çıra, toz ilaç ve kırık kömür gibi örneklerde yüzey artışı tepkime hızını artırır."},{"q":"İki tepken katı ise yüzey alanı neden tepkime hızı için önemlidir?","steps":[{"t":"Temas sınırı","a":"sadece yüzeyde","d":"Katılarda tepkime yalnızca dış yüzeyde, temas eden noktalarda olur."},{"t":"Yüzey artışı","a":"hız artar","d":"Yüzey arttıkça temas noktası çoğalır, tepkime hızlanır."}],"ans":"Katılarda tepkime yalnızca yüzeyde olduğundan, yüzey arttıkça temas noktası çoğalır ve hız artar."}],"zor":[{"q":"Aynı kütledeki çinkonun toz ve levha hâli asitle tepkimede neden farklı hız gösterir?","fig":"<svg viewBox='0 0 320 150'><rect x='40' y='50' width='70' height='50' fill='#5b6b85' stroke='#1a2b45'/><text x='75' y='120' font-size='10' text-anchor='middle' fill='#1a2b45'>levha (az yuzey)</text><circle cx='190' cy='55' r='6' fill='#5b6b85' stroke='#1a2b45'/><circle cx='215' cy='70' r='6' fill='#5b6b85' stroke='#1a2b45'/><circle cx='240' cy='55' r='6' fill='#5b6b85' stroke='#1a2b45'/><circle cx='205' cy='90' r='6' fill='#5b6b85' stroke='#1a2b45'/><circle cx='235' cy='90' r='6' fill='#5b6b85' stroke='#1a2b45'/><text x='220' y='120' font-size='10' text-anchor='middle' fill='#1a2b45'>toz (cok yuzey)</text></svg>","steps":[{"t":"Yüzey farkı","a":"toz geniş","d":"Toz çinkonun toplam yüzeyi levhadan kat kat fazladır."},{"t":"Çarpışma","a":"daha sık","d":"Geniş yüzeyde asit tanecikleri çinkoya daha sık çarpar."},{"t":"Sonuç","a":"toz hızlı","d":"Bu yüzden toz çinko levhadan çok daha hızlı tepkir ve gazı çabuk çıkarır."}],"ans":"Toz çinkonun yüzeyi çok geniş olduğundan asitle daha sık çarpışır ve levhadan çok daha hızlı tepkir."},{"q":"Bir küp 1 cm kenarlı iken, onu 8 eşit küçük küpe bölersek toplam yüzey nasıl değişir?","fig":"<svg viewBox='0 0 320 150'><rect x='40' y='40' width='60' height='60' fill='#cfd8e8' stroke='#1a2b45'/><text x='70' y='120' font-size='10' text-anchor='middle' fill='#1a2b45'>1 kup: 6 cm²</text><rect x='190' y='40' width='28' height='28' fill='#cfd8e8' stroke='#1a2b45'/><rect x='222' y='40' width='28' height='28' fill='#cfd8e8' stroke='#1a2b45'/><rect x='190' y='72' width='28' height='28' fill='#cfd8e8' stroke='#1a2b45'/><rect x='222' y='72' width='28' height='28' fill='#cfd8e8' stroke='#1a2b45'/><text x='220' y='120' font-size='10' text-anchor='middle' fill='#1a2b45'>8 kup: 12 cm²</text></svg>","steps":[{"t":"Başlangıç yüzey","a":"6 cm²","d":"1 cm'lik küpün yüzeyi 6×(1×1) = 6 cm²'dir."},{"t":"Bölünmüş küpler","a":"0,5 cm kenar","d":"8 eşit küpe bölünürse her birinin kenarı 0,5 cm, yüzeyi 6×0,25 = 1,5 cm²'dir."},{"t":"Toplam","a":"12 cm²","d":"8 küp toplamda 8×1,5 = 12 cm²; yani toplam yüzey 2 katına çıkar."}],"ans":"Küpü 8 eşit parçaya bölmek toplam yüzeyi 6 cm²'den 12 cm²'ye, yani 2 katına çıkarır; tepkime hızlanır."},{"q":"Toz hâlindeki yanıcı maddeler (un, kömür tozu) fabrikalarda neden patlama riski taşır?","steps":[{"t":"Çok geniş yüzey","a":"havayla temas","d":"Havada asılı kalan toz tanecikleri oksijenle çok geniş bir yüzeyden temas eder."},{"t":"Ani yanma","a":"patlama","d":"Bir kıvılcımla bu geniş yüzey aynı anda yanınca enerji çok hızlı açığa çıkar, patlama olur."}],"ans":"Havada asılı tozun yüzeyi çok geniş olduğundan oksijenle ani ve şiddetli yanar; bu, toz patlaması riskine yol açar."},{"q":"Aynı çözünen için karıştırma ve toz hâline getirme birlikte çözünmeyi nasıl hızlandırır?","steps":[{"t":"Toz hâli","a":"yüzey artar","d":"Toz hâli çözünenin yüzeyini artırır, suyla teması çoğaltır."},{"t":"Karıştırma","a":"temas yeniler","d":"Karıştırma doymaya başlayan suyu uzaklaştırıp taze su getirir."},{"t":"Birlikte","a":"çok hızlı","d":"Geniş yüzey ve sürekli yenilenen temas birleşince çözünme çok hızlanır."}],"ans":"Toz hâli yüzeyi artırır, karıştırma teması sürekli yeniler; ikisi birlikte çözünmeyi çok hızlandırır."},{"q":"Sindirim sisteminde çiğneme neden önemlidir; temas yüzeyiyle ilişkilendirin.","steps":[{"t":"Çiğneme","a":"parçalar","d":"Çiğnemek besini küçük parçalara ayırır, yüzeyini artırır."},{"t":"Enzim teması","a":"hızlanır","d":"Geniş yüzeyde sindirim enzimleri besinle daha çok temas eder."},{"t":"Sonuç","a":"hızlı sindirim","d":"Bu yüzden iyi çiğnenmiş besin daha hızlı ve kolay sindirilir."}],"ans":"Çiğneme besinin yüzeyini artırır; enzimler daha çok temas ettiği için sindirim hızlanır."}]},"lise":{"kolay":[{"q":"Temas yüzeyinin tepkime hızını artırması çarpışma kuramıyla nasıl açıklanır?","fig":"<svg viewBox='0 0 320 150'><line x1='120' y1='30' x2='120' y2='120' stroke='#1a2b45'/><rect x='60' y='50' width='50' height='50' fill='#5b6b85' stroke='#1a2b45'/><circle cx='30' cy='75' r='6' fill='#2b6be0'/><line x1='36' y1='75' x2='58' y2='75' stroke='#2b6be0'/><circle cx='200' cy='45' r='5' fill='#5b6b85' stroke='#1a2b45'/><circle cx='230' cy='75' r='5' fill='#5b6b85' stroke='#1a2b45'/><circle cx='200' cy='105' r='5' fill='#5b6b85' stroke='#1a2b45'/><circle cx='160' cy='45' r='6' fill='#2b6be0'/><circle cx='270' cy='75' r='6' fill='#2b6be0'/><circle cx='160' cy='105' r='6' fill='#2b6be0'/><text x='235' y='138' font-size='9' text-anchor='middle' fill='#1a2b45'>genis yuzey: cok carpisma</text></svg>","steps":[{"t":"Çarpışma kuramı","a":"temas gerekir","d":"Tepkime için tanecikler çarpışmalı; çarpışma yüzeyde gerçekleşir."},{"t":"Yüzey artışı","a":"çarpışma sıklığı","d":"Yüzey arttıkça birim zamanda etkili çarpışma sayısı artar, hız yükselir."}],"ans":"Yüzey arttıkça etkili çarpışma sayısı arttığından, çarpışma kuramına göre tepkime hızı yükselir."},{"q":"Temas yüzeyi faktörü hangi hâldeki tepkenler için belirleyicidir?","steps":[{"t":"Heterojen tepkime","a":"farklı faz","d":"Yüzey etkisi özellikle katı-sıvı, katı-gaz gibi farklı fazlı (heterojen) tepkimelerde belirleyicidir."},{"t":"Homojen","a":"etkisiz","d":"Tek faz (gaz-gaz, çözelti) homojen tepkimelerde temas yüzeyi anlamlı bir değişken değildir."}],"ans":"Temas yüzeyi, katı içeren heterojen tepkimelerde belirleyicidir; tek fazlı homojen tepkimelerde etkisizdir."},{"q":"Hacme göre yüzey oranı (yüzey/hacim) parçacık küçüldükçe nasıl değişir?","steps":[{"t":"Küçülme","a":"oran artar","d":"Parçacık küçüldükçe yüzeyin hacme oranı büyür."},{"t":"Sonuç","a":"daha reaktif","d":"Yüksek yüzey/hacim oranı daha çok temas demektir, küçük parçacıklar daha reaktiftir."}],"ans":"Parçacık küçüldükçe yüzey/hacim oranı büyür; bu da daha çok temas ve daha yüksek tepkime hızı demektir."},{"q":"Nanoparçacıkların yüksek reaktifliği temas yüzeyiyle nasıl ilişkilidir?","steps":[{"t":"Çok küçük boyut","a":"dev yüzey","d":"Nanoparçacıklar çok küçük olduğundan kütlelerine göre çok büyük yüzey sunar."},{"t":"Reaktiflik","a":"yüksek","d":"Bu dev yüzey çok temas sağladığından nanoparçacıklar olağanüstü reaktif olur."}],"ans":"Nanoparçacıkların kütlelerine göre çok büyük yüzeyi olduğundan teması çok fazladır, bu da onları çok reaktif yapar."},{"q":"Mermer (CaCO₃) ile HCl tepkimesinde yüzey artışının gaz çıkış hızına etkisi nedir?","fig":"<svg viewBox='0 0 320 150'><rect x='40' y='70' width='60' height='50' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='55' cy='60' r='3' fill='#5b6b85'/><circle cx='75' cy='45' r='3' fill='#5b6b85'/><text x='70' y='138' font-size='9' text-anchor='middle' fill='#1a2b45'>parca: az gaz</text><rect x='200' y='70' width='60' height='50' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='210' cy='55' r='3' fill='#5b6b85'/><circle cx='230' cy='40' r='3' fill='#5b6b85'/><circle cx='245' cy='52' r='3' fill='#5b6b85'/><circle cx='250' cy='35' r='3' fill='#5b6b85'/><text x='230' y='138' font-size='9' text-anchor='middle' fill='#1a2b45'>toz: cok CO₂</text></svg>","steps":[{"t":"Tepkime","a":"CaCO₃ + 2HCl → CaCl₂ + H₂O + CO₂","d":"Mermer asitle tepkiyerek CO₂ gazı çıkarır."},{"t":"Toz hâli","a":"hızlı CO₂","d":"Mermer toz hâline getirilirse yüzey artar, CO₂ gazı çok daha hızlı çıkar."}],"ans":"CaCO₃ + 2HCl → CaCl₂ + H₂O + CO₂ tepkimesinde mermerin toz hâli yüzeyi artırarak CO₂ çıkış hızını yükseltir."}],"zor":[{"q":"1 cm kenarlı bir küpü 1000 eşit küçük küpe bölersek toplam yüzey kaç katına çıkar?","fig":"<svg viewBox='0 0 320 150'><rect x='40' y='40' width='60' height='60' fill='#cfd8e8' stroke='#1a2b45'/><text x='70' y='120' font-size='10' text-anchor='middle' fill='#1a2b45'>1 buyuk kup</text><rect x='190' y='40' width='14' height='14' fill='#cfd8e8' stroke='#1a2b45'/><rect x='210' y='40' width='14' height='14' fill='#cfd8e8' stroke='#1a2b45'/><rect x='230' y='40' width='14' height='14' fill='#cfd8e8' stroke='#1a2b45'/><rect x='190' y='60' width='14' height='14' fill='#cfd8e8' stroke='#1a2b45'/><rect x='210' y='60' width='14' height='14' fill='#cfd8e8' stroke='#1a2b45'/><rect x='230' y='60' width='14' height='14' fill='#cfd8e8' stroke='#1a2b45'/><text x='215' y='120' font-size='10' text-anchor='middle' fill='#1a2b45'>cok kucuk kup</text></svg>","steps":[{"t":"Başlangıç","a":"6 cm²","d":"1 cm'lik küpün yüzeyi 6 cm²'dir."},{"t":"Bölme","a":"0,1 cm kenar","d":"1000 = 10³ eşit küpe bölünürse her küpün kenarı 0,1 cm, yüzeyi 6×0,01 = 0,06 cm²'dir."},{"t":"Toplam","a":"60 cm²","d":"1000×0,06 = 60 cm²; toplam yüzey 6'dan 60'a, yani 10 katına çıkar."}],"ans":"Küpü 1000 eşit parçaya bölmek toplam yüzeyi 6 cm²'den 60 cm²'ye, yani 10 katına çıkarır."},{"q":"Heterojen katalizde (örneğin egzoz katalizöründe) bal peteği yapı neden tercih edilir? Temas yüzeyiyle açıklayın.","steps":[{"t":"Bal peteği yapı","a":"çok kanal","d":"Bal peteği yapı çok sayıda ince kanal ve gözenek içerir."},{"t":"Geniş yüzey","a":"çok aktif merkez","d":"Bu yapı küçük hacimde çok büyük bir katalizör yüzeyi sunar."},{"t":"Sonuç","a":"hızlı dönüşüm","d":"Geniş yüzey egzoz gazlarıyla çok temas sağlar, zararlı gazlar hızlıca zararsızlara dönüşür."}],"ans":"Bal peteği yapı küçük hacimde çok büyük katalizör yüzeyi sunduğundan egzoz gazlarıyla teması artırır ve dönüşümü hızlandırır."},{"q":"İki deneyde 5 g çinko toz, 5 g çinko levha aynı asitle tepkiyor. Üretilen H₂ gazının toplam miktarı ve hızı nasıl olur?","steps":[{"t":"Toplam H₂","a":"eşit","d":"Aynı kütlede çinko aynı mol H₂ verir; toplam gaz miktarı iki deneyde eşittir."},{"t":"Hız","a":"toz hızlı","d":"Toz hâlin yüzeyi geniş olduğundan başlangıç hızı yüksektir, gaz çabuk çıkar."},{"t":"Süre","a":"toz erken biter","d":"Toz deneyi daha erken tamamlanır; levha aynı gazı daha uzun sürede çıkarır."}],"ans":"Toplam H₂ miktarı eşittir; ancak toz çinko geniş yüzeyi sayesinde gazı daha hızlı çıkarıp tepkimeyi daha erken bitirir."},{"q":"Yüzey alanı, sıcaklık ve derişim faktörleri arasında temas yüzeyinin kendine özgü farkı nedir?","steps":[{"t":"Sıcaklık/derişim","a":"enerji ve tanecik","d":"Sıcaklık tanecik enerjisini, derişim birim hacimdeki tanecik sayısını değiştirir."},{"t":"Yüzey alanı","a":"temas sınırı","d":"Yüzey alanı ise yalnızca fazlar arası temas sınırını büyütür, çarpışmaların olabileceği alanı artırır."},{"t":"Fark","a":"sadece heterojen","d":"Bu yüzden yüzey etkisi yalnızca katı içeren heterojen sistemlerde anlamlıdır; diğer ikisi her sistemde etkilidir."}],"ans":"Yüzey alanı, sıcaklık ve derişimden farklı olarak fazlar arası temas sınırını büyütür ve etkisi yalnızca katı içeren heterojen sistemlerde görülür."},{"q":"Bir parçacığın yarıçapı yarıya inerse aynı kütle için toplam yüzey alanı nasıl değişir?","steps":[{"t":"Hacim ve sayı","a":"8 kat parça","d":"Yarıçap yarıya inince her parçanın hacmi 1/8'e iner; aynı kütle için parça sayısı 8 katına çıkar."},{"t":"Tek yüzey","a":"1/4 olur","d":"Tek bir parçanın yüzeyi yarıçapın karesiyle orantılı olduğundan 1/4'e iner."},{"t":"Toplam","a":"2 katı","d":"Toplam yüzey = 8 × (1/4) = 2 kat; yani parçacık yarıçapı yarıya inince toplam yüzey 2 katına çıkar."}],"ans":"Yarıçap yarıya inince parça sayısı 8 katına, tek yüzey 1/4'e iner; toplam yüzey 2 katına çıkar, böylece tepkime hızlanır."}]}},"tepkimeBelirti":{"ilkokul":{"kolay":[{"q":"Demir bir çiviyi uzun süre nemde bıraktığımızda üzerinde turuncu renkli pas oluşması neyin işaretidir?","fig":"<svg viewBox='0 0 320 150'><rect x='40' y='65' width='90' height='20' fill='#cfd8e8' stroke='#1a2b45'/><text x='85' y='110' font-size='11' text-anchor='middle' fill='#1a2b45'>parlak çivi</text><text x='150' y='80' font-size='16' text-anchor='middle' fill='#1a2b45'>→</text><rect x='190' y='65' width='90' height='20' fill='#e0552b' stroke='#1a2b45'/><text x='235' y='110' font-size='11' text-anchor='middle' fill='#1a2b45'>paslı çivi</text></svg>","steps":[{"t":"Ne gözlüyoruz","a":"renk değişimi","d":"Parlak gri çivi, zamanla turuncu-kahverengi bir renge dönüşür."},{"t":"Bu ne anlama gelir","a":"yeni madde","d":"Renk değişmesi, çivide pas adında yeni bir madde oluştuğunu, yani kimyasal bir olay olduğunu gösterir."}],"ans":"Renk değişimi yeni bir madde (pas) oluştuğunu, yani kimyasal bir tepkime olduğunu gösterir."},{"q":"Bir bardak sirkenin içine karbonat attığımızda kabarcıklar ve köpük çıkması neyi gösterir?","fig":"<svg viewBox='0 0 320 150'><rect x='110' y='40' width='100' height='90' fill='none' stroke='#1a2b45'/><line x1='110' y1='75' x2='210' y2='75' stroke='#2b6be0'/><circle cx='135' cy='60' r='5' fill='#2b6be0'/><circle cx='160' cy='52' r='5' fill='#2b6be0'/><circle cx='185' cy='58' r='5' fill='#2b6be0'/><circle cx='150' cy='40' r='4' fill='#2b6be0'/><circle cx='175' cy='38' r='4' fill='#2b6be0'/><text x='160' y='145' font-size='11' text-anchor='middle' fill='#1a2b45'>gaz kabarcıkları</text></svg>","steps":[{"t":"Ne görüyoruz","a":"gaz kabarcıkları","d":"Sirke ile karbonat karışınca bir sürü kabarcık ve köpük oluşur."},{"t":"Anlamı","a":"gaz çıkışı","d":"Kabarcıklar yeni bir gaz oluştuğunu, yani kimyasal bir tepkimenin gerçekleştiğini gösterir."}],"ans":"Kabarcık ve köpük çıkması, gaz oluştuğunu yani kimyasal bir tepkime olduğunu gösterir."},{"q":"Bir mum yandığında etrafa ısı ve ışık vermesi neyin belirtisidir?","steps":[{"t":"Ne hissediyoruz","a":"ısı ve ışık","d":"Yanan mumun yanında elimiz ısınır ve etraf aydınlanır."},{"t":"Anlamı","a":"kimyasal olay","d":"Isı ve ışık çıkması, mumun yanarak yeni maddelere dönüştüğü kimyasal bir olayın işaretidir."}],"ans":"Isı ve ışık vermesi, mumun yandığı bir kimyasal tepkimenin belirtisidir."},{"q":"Bozulan bir yumurtanın kötü kokması neyi gösterir?","steps":[{"t":"Ne fark ediyoruz","a":"kötü koku","d":"Bozulan yumurta açıldığında çok kötü bir koku yayılır."},{"t":"Anlamı","a":"yeni madde","d":"Bu koku, yumurtada kokulu yeni maddeler oluşturan kimyasal bir değişimin gerçekleştiğini gösterir."}],"ans":"Kötü koku yayılması, yumurtada kimyasal bir değişim (bozulma) olduğunu gösterir."},{"q":"İki berrak sıvıyı karıştırınca dibe bulanık beyaz bir toz çökmesi neyin işaretidir?","fig":"<svg viewBox='0 0 320 150'><path d='M120 40 L200 40 L185 120 L135 120 Z' fill='none' stroke='#1a2b45'/><rect x='137' y='95' width='46' height='22' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='148' cy='110' r='3' fill='#5b6b85'/><circle cx='160' cy='113' r='3' fill='#5b6b85'/><circle cx='172' cy='109' r='3' fill='#5b6b85'/><text x='160' y='140' font-size='11' text-anchor='middle' fill='#1a2b45'>dibe çöken katı</text></svg>","steps":[{"t":"Ne görüyoruz","a":"çökme","d":"İki berrak sıvı karışınca kabın dibinde bulanık beyaz bir madde toplanır."},{"t":"Anlamı","a":"yeni katı madde","d":"Dibe çöken bu madde, karışım sırasında oluşan yeni bir katıdır; bu da kimyasal bir tepkime belirtisidir."}],"ans":"Dibe katı bir maddenin çökmesi, kimyasal bir tepkime sonucu yeni madde oluştuğunu gösterir."}],"zor":[{"q":"Bir elmayı kestiğimizde kesik yüzeyinin zamanla kahverengiye dönmesi fiziksel mi kimyasal mı bir olaydır?","steps":[{"t":"Ne oluyor","a":"renk değişiyor","d":"Elmanın açık renkli iç yüzeyi havayla temas edince yavaşça kahverengiye döner."},{"t":"Karar","a":"kimyasal","d":"Renk değişip yeni bir madde oluştuğu için bu kimyasal bir olaydır, sadece şeklin değişmesi değildir."}],"ans":"Renk değiştiği ve yeni madde oluştuğu için elmanın kararması kimyasal bir olaydır."},{"q":"Suyun kaynayıp buhar olması ile odunun yanıp küle dönmesi arasındaki temel fark nedir?","fig":"<svg viewBox='0 0 320 150'><text x='80' y='25' font-size='11' text-anchor='middle' fill='#1a2b45'>su → buhar</text><rect x='50' y='40' width='60' height='30' fill='#cfd8e8' stroke='#1a2b45'/><text x='80' y='110' font-size='10' text-anchor='middle' fill='#1a2b45'>fiziksel</text><text x='240' y='25' font-size='11' text-anchor='middle' fill='#1a2b45'>odun → kül</text><rect x='210' y='40' width='60' height='30' fill='#5b6b85' stroke='#1a2b45'/><text x='240' y='110' font-size='10' text-anchor='middle' fill='#1a2b45'>kimyasal</text></svg>","steps":[{"t":"Su buharı","a":"yine su","d":"Su kaynayıp buhar olur ama soğuyunca yine suya döner; yeni bir madde oluşmaz."},{"t":"Yanan odun","a":"kül ve gaz","d":"Yanan odun küle ve gazlara dönüşür; geri odun olmaz, yeni maddeler oluşur."}],"ans":"Su buharı yeni madde oluşturmaz (fiziksel), oysa odunun yanması yeni maddeler oluşturur (kimyasal)."},{"q":"Bir bardak süt ekşiyip topaklanırsa bunun kimyasal bir tepkime olduğunu hangi belirtilerden anlarız?","steps":[{"t":"Belirtiler","a":"koku ve görünüm","d":"Ekşiyen süt hem ekşi kokar hem de topaklanıp eski kıvamından çıkar."},{"t":"Sonuç","a":"yeni madde","d":"Koku ve yapı değiştiği, eski hâle dönmediği için sütte yeni maddeler oluşmuştur; bu kimyasaldır."}],"ans":"Ekşi koku ve topaklanma yeni madde oluştuğunu gösterir; sütün ekşimesi kimyasal bir tepkimedir."},{"q":"Havai fişeklerin patlarken hem ses hem ışık hem de renkli alevler çıkarması hangi tepkime belirtilerini bir arada gösterir?","steps":[{"t":"Gözlenenler","a":"ışık, ısı, renk","d":"Havai fişekte parlak ışık, sıcaklık ve farklı renkler aynı anda görülür."},{"t":"Anlamı","a":"birçok belirti","d":"Işık, ısı ve renk değişimi belirtilerinin hepsi birden görülür; bunların hepsi kimyasal tepkime işaretidir."}],"ans":"Havai fişek ışık, ısı ve renk değişimi belirtilerini bir arada gösteren bir kimyasal tepkimedir."},{"q":"Bir demir çiviyi çekiçle eğip bükmek ile aynı çivinin paslanması neden farklı türde olaylardır?","steps":[{"t":"Bükme","a":"şekil değişir","d":"Çiviyi büktüğümüzde sadece şekli değişir, demir yine demir olarak kalır."},{"t":"Paslanma","a":"yeni madde","d":"Paslanmada ise demir, pas adı verilen yepyeni bir maddeye dönüşür."}],"ans":"Bükmede sadece şekil değişir (fiziksel), paslanmada ise yeni madde oluşur (kimyasal)."}]},"ortaokul":{"kolay":[{"q":"Kimyasal bir tepkimenin gerçekleştiğini gösteren başlıca belirtiler nelerdir?","steps":[{"t":"Belirtiler","a":"beş temel işaret","d":"Renk değişimi, gaz çıkışı, ısı veya ışık alışverişi, çökelek oluşumu ve koku değişimi başlıca belirtilerdir."},{"t":"Ortak nokta","a":"yeni madde","d":"Bu belirtilerin hepsi, başlangıçtakinden farklı yeni maddelerin oluştuğuna işaret eder."}],"ans":"Renk değişimi, gaz çıkışı, ısı/ışık, çökelek oluşumu ve koku değişimi kimyasal tepkimenin başlıca belirtileridir."},{"q":"Çökelek (çökelti) oluşumu bir tepkimede neyi gösterir?","steps":[{"t":"Çökelek nedir","a":"katı madde","d":"İki çözelti karışınca çözünmeyip dibe çöken katı maddeye çökelek denir."},{"t":"Anlamı","a":"yeni bileşik","d":"Çökeleğin oluşması, çözeltide yeni ve çözünmeyen bir bileşik meydana geldiğini, yani kimyasal tepkime olduğunu gösterir."}],"ans":"Çökelek oluşumu, çözeltide çözünmeyen yeni bir katı bileşiğin oluştuğunu, yani kimyasal tepkime olduğunu gösterir."},{"q":"Bir tepkimede dışarıya ısı verilmesi ile dışarıdan ısı alınması arasındaki farkı nasıl ayırt ederiz?","steps":[{"t":"Isı veren","a":"ekzotermik","d":"Ortamı ısıtan, kabı sıcak hisset­tiren tepkimeler ısı verir (örneğin yanma)."},{"t":"Isı alan","a":"endotermik","d":"Ortamı soğutan, kabı serin hissettiren tepkimeler ise dışarıdan ısı alır."}],"ans":"Ortamı ısıtan tepkime ısı verir (ekzotermik), ortamı soğutan tepkime ise dışarıdan ısı alır (endotermik)."},{"q":"Magnezyum şeridinin yanarken çok parlak beyaz ışık vermesi hangi belirtiye örnektir?","steps":[{"t":"Gözlem","a":"parlak ışık","d":"Magnezyum şeridi tutuşunca göz kamaştıran beyaz bir ışık yayar."},{"t":"Belirti türü","a":"ışık çıkışı","d":"Bu, kimyasal tepkimede ışık (ve ısı) çıkışı belirtisine örnektir; magnezyum, magnezyum oksite dönüşür."}],"ans":"Parlak ışık yayması, kimyasal tepkimede ışık çıkışı belirtisine bir örnektir."},{"q":"Karbonatın limon suyu ile karışınca köpürmesi hangi tepkime belirtisini gösterir?","steps":[{"t":"Gözlem","a":"köpürme","d":"Karbonat limon suyuna eklenince hızla köpürür ve kabarcıklar oluşur."},{"t":"Belirti türü","a":"gaz çıkışı","d":"Bu kabarcıklar karbondioksit gazıdır; dolayısıyla gözlenen belirti gaz çıkışıdır."}],"ans":"Köpürme ve kabarcık oluşması, kimyasal tepkimedeki gaz çıkışı belirtisini gösterir."}],"zor":[{"q":"Renk değişimi her zaman kimyasal tepkimenin kesin kanıtı mıdır? Açıklayınız.","steps":[{"t":"Genelde","a":"kimyasal işaret","d":"Renk değişimi çoğu zaman yeni madde oluştuğunu, yani kimyasal tepkimeyi gösterir."},{"t":"İstisna","a":"her zaman değil","d":"Bazı durumlarda renk farkı sadece karışma ya da seyrelme gibi fiziksel nedenlerden olabilir; bu yüzden tek başına kesin kanıt sayılmaz."}],"ans":"Renk değişimi güçlü bir belirtidir ama tek başına kesin kanıt değildir; bazı renk değişimleri fiziksel nedenlerle de olur."},{"q":"Su buharı çıkışı ile bir tepkimede gaz çıkışını karıştırmamak için nelere dikkat edilir?","steps":[{"t":"Su buharı","a":"fiziksel","d":"Suyu ısıtınca çıkan buhar, suyun hâl değiştirmesidir; soğuyunca yine suya döner, yeni madde yoktur."},{"t":"Tepkime gazı","a":"yeni madde","d":"Tepkimede çıkan gaz ise (örneğin CO₂) yepyeni bir maddedir ve kendiliğinden suya geri dönmez."}],"ans":"Su buharı yalnızca hâl değişimidir (fiziksel); tepkimede çıkan gaz ise yeni bir maddedir (kimyasal)."},{"q":"Bir öğrenci 'kabın ısınması her zaman kimyasal tepkime demektir' diyor. Bu doğru mu?","steps":[{"t":"Kimyasal ısı","a":"tepkimeyle","d":"Bir kabın bir tepkime sonucu ısınması ekzotermik kimyasal olaya işaret edebilir."},{"t":"Fiziksel ısı","a":"karışma/sürtünme","d":"Ancak bazı tuzların suda çözünmesi ya da suya asit eklenmesi gibi fiziksel olaylarda da ısı açığa çıkabilir; bu nedenle her ısınma kimyasal sayılmaz."}],"ans":"Hayır; ısınma kimyasal tepkime işareti olabilir ama çözünme gibi bazı fiziksel olaylarda da ısı açığa çıkar."},{"q":"İki şeffaf çözelti karıştırıldığında bulanıklaşma görülürse, bunun çökelme tepkimesi olduğunu hangi gözlemle doğrularız?","steps":[{"t":"İlk gözlem","a":"bulanıklık","d":"Karışım anında çözelti bulanıklaşır, çünkü çok küçük katı tanecikler oluşmaya başlar."},{"t":"Doğrulama","a":"dibe çökme","d":"Bir süre beklenince bu katı taneciklerin dibe çökmesi, gerçekten çözünmeyen yeni bir bileşik (çökelek) oluştuğunu doğrular."}],"ans":"Bulanıklığın ardından katının dibe çökmesi, çözünmeyen yeni bir bileşiğin oluştuğunu, yani çökelme tepkimesini doğrular."},{"q":"Demirin paslanması, mumun yanması ve buzun erimesi olaylarını belirtilerine göre fiziksel/kimyasal olarak sınıflandırınız.","steps":[{"t":"Paslanma ve yanma","a":"kimyasal","d":"Paslanmada renk değişimiyle yeni madde (pas), yanmada ısı-ışıkla yeni maddeler oluşur; ikisi de kimyasaldır."},{"t":"Buzun erimesi","a":"fiziksel","d":"Buzun erimesinde sadece hâl değişir, madde yine sudur; yeni madde oluşmadığı için fizikseldir."}],"ans":"Paslanma ve yanma yeni madde oluşturduğu için kimyasal, buzun erimesi yeni madde oluşturmadığı için fizikseldir."}]},"lise":{"kolay":[{"q":"Kimyasal bir tepkimenin gerçekleştiğini gösteren belirtiler nelerdir ve bunların ortak temel nedeni nedir?","steps":[{"t":"Belirtiler","a":"renk, gaz, ısı/ışık, çökelek, koku","d":"Renk değişimi, gaz çıkışı, ısı ya da ışık alışverişi, çökelek oluşumu ve koku değişimi başlıca makroskobik belirtilerdir."},{"t":"Ortak neden","a":"bağların yeniden düzenlenmesi","d":"Bu belirtilerin tümü, tepkenlerdeki bağların kırılıp yeni ürün maddelerin oluşmasından, yani kimyasal kimliğin değişmesinden kaynaklanır."}],"ans":"Renk, gaz, ısı/ışık, çökelek ve koku değişimi belirtilerinin ortak nedeni, bağların yeniden düzenlenip yeni maddelerin oluşmasıdır."},{"q":"Fiziksel değişim ile kimyasal değişim arasındaki temel ayrımı tanecik düzeyinde açıklayınız.","steps":[{"t":"Fiziksel değişim","a":"madde aynı kalır","d":"Hâl değişimi ya da şekil değişiminde maddenin kimliği değişmez; tanecik türü aynı kalır, yalnızca dizilişi/hareketi değişir."},{"t":"Kimyasal değişim","a":"yeni madde","d":"Kimyasal değişimde bağlar kırılıp yeniden kurulur, atomlar yeniden düzenlenerek farklı kimliğe sahip yeni maddeler oluşur."}],"ans":"Fiziksel değişimde maddenin kimliği korunur (yalnızca düzen/hâl değişir), kimyasal değişimde ise atomlar yeniden düzenlenip yeni maddeler oluşur."},{"q":"Ekzotermik ve endotermik tepkimeler belirtileriyle nasıl ayırt edilir?","fig":"<svg viewBox='0 0 320 150'><text x='80' y='30' font-size='11' text-anchor='middle' fill='#1a2b45'>ekzotermik</text><rect x='40' y='40' width='80' height='40' fill='#e0552b' stroke='#1a2b45'/><text x='80' y='65' font-size='10' text-anchor='middle' fill='#1a2b45'>ısı verir</text><text x='80' y='105' font-size='10' text-anchor='middle' fill='#1a2b45'>ortam ısınır</text><text x='240' y='30' font-size='11' text-anchor='middle' fill='#1a2b45'>endotermik</text><rect x='200' y='40' width='80' height='40' fill='#2b6be0' stroke='#1a2b45'/><text x='240' y='65' font-size='10' text-anchor='middle' fill='#f5f7fa'>ısı alır</text><text x='240' y='105' font-size='10' text-anchor='middle' fill='#1a2b45'>ortam soğur</text></svg>","steps":[{"t":"Ekzotermik","a":"ısı verir","d":"Ekzotermik tepkime çevreye ısı verir; ortam ve kap sıcaklığı artar (örneğin yanma)."},{"t":"Endotermik","a":"ısı alır","d":"Endotermik tepkime çevreden ısı çeker; ortam ve kap sıcaklığı düşer, kap soğur."}],"ans":"Ekzotermik tepkimede ortam ısınır (ısı verilir), endotermik tepkimede ortam soğur (ısı alınır)."},{"q":"Bir gözlem yapan kişi, kimyasal tepkime belirtisini kesinleştirmek için neden tek bir belirtiyle yetinmemelidir?","steps":[{"t":"Yanıltıcı belirtiler","a":"fiziksel kökenli olabilir","d":"Renk değişimi, ısı açığa çıkışı ya da gaz görünmesi bazen çözünme, seyrelme gibi fiziksel olaylardan da kaynaklanabilir."},{"t":"Doğru yaklaşım","a":"birden çok kanıt","d":"Birden fazla belirtinin birlikte gözlenmesi ve değişimin geri dönüşsüz olması, kimyasal tepkimeyi daha güvenilir biçimde doğrular."}],"ans":"Tek belirti fiziksel kökenli olabileceğinden, kimyasal tepkimeyi kesinleştirmek için birden çok belirti ve geri dönüşsüzlük birlikte değerlendirilmelidir."},{"q":"Koku değişimi neden bir kimyasal tepkime belirtisi sayılır?","steps":[{"t":"Koku ve madde","a":"uçucu maddeler","d":"Koku, havaya karışan uçucu maddelerin burnumuzdaki algılayıcılarla etkileşmesiyle hissedilir."},{"t":"Yeni koku","a":"yeni madde","d":"Ortaya yeni bir kokunun çıkması, daha önce olmayan uçucu yeni maddelerin oluştuğu anlamına gelir; bu da kimyasal değişimi gösterir."}],"ans":"Yeni bir koku, daha önce bulunmayan uçucu maddelerin oluştuğunu gösterdiği için kimyasal tepkime belirtisi sayılır."}],"zor":[{"q":"Yanma ile paslanma her ikisi de demirin oksijenle tepkimesidir; belirtileri neden bu kadar farklı görünür?","fig":"<svg viewBox='0 0 320 150'><text x='80' y='25' font-size='11' text-anchor='middle' fill='#1a2b45'>yanma (hızlı)</text><circle cx='80' cy='75' r='20' fill='#e0552b' stroke='#1a2b45'/><text x='80' y='115' font-size='10' text-anchor='middle' fill='#1a2b45'>ısı + ışık</text><text x='240' y='25' font-size='11' text-anchor='middle' fill='#1a2b45'>paslanma (yavaş)</text><circle cx='240' cy='75' r='20' fill='#e0552b88' stroke='#1a2b45'/><text x='240' y='115' font-size='10' text-anchor='middle' fill='#1a2b45'>renk değişimi</text></svg>","steps":[{"t":"Ortak özellik","a":"oksijenle birleşme","d":"Hem hızlı yanma hem yavaş paslanma, demirin oksijenle birleşerek demir oksit oluşturmasıdır; ikisi de ekzotermiktir."},{"t":"Hız farkı","a":"belirtilerin görünürlüğü","d":"Yanma çok hızlı olduğundan ısı ve ışık aniden açığa çıkar; paslanma çok yavaş olduğundan açığa çıkan ısı belirgin değildir, asıl belirti renk değişimidir."}],"ans":"İkisi de demir-oksijen tepkimesidir; hızın farklı olması nedeniyle yanmada ısı/ışık ani, paslanmada ise belirti yavaş bir renk değişimi olarak görünür."},{"q":"Bir tepkimede gaz çıkışının gözlenmemesi, kimyasal tepkime olmadığı anlamına gelir mi?","steps":[{"t":"Yanlış varsayım","a":"belirti çeşitliliği","d":"Gaz çıkışı yalnızca olası belirtilerden biridir; her tepkimede gaz açığa çıkmaz."},{"t":"Diğer belirtiler","a":"renk/ısı/çökelek","d":"Bir tepkime renk değişimi, çökelek oluşumu ya da ısı alışverişi gibi başka belirtilerle gerçekleşebilir; gaz görülmemesi tepkime olmadığını göstermez."}],"ans":"Hayır; gaz çıkışı yalnızca bir belirtidir, tepkime renk değişimi, çökelek ya da ısı alışverişi gibi başka belirtilerle de gerçekleşebilir."},{"q":"Nötrleşme tepkimesi HCl + NaOH → NaCl + H₂O hangi belirtiyle gözlenebilir, çünkü gözle görünür bir gaz ya da çökelek oluşmaz?","steps":[{"t":"Ürünler","a":"tuz ve su","d":"Asit ve baz birleşince çözünür tuz (NaCl) ve su oluşur; bunlar berraktır, gaz ya da çökelek görünmez."},{"t":"Gözlenebilen belirti","a":"ısı ve pH","d":"Tepkime ekzotermiktir, kap ısınır; ayrıca indikatörle ya da pH ölçümüyle ortamın asitlik/bazlığının nötre yaklaştığı görülür."}],"ans":"HCl + NaOH → NaCl + H₂O tepkimesi, açığa çıkan ısı ve indikatör/pH değişimiyle gözlenir; görünür gaz ya da çökelek oluşmaz."},{"q":"Termal ayrışma olan CaCO₃ → CaO + CO₂ tepkimesinde hangi belirtiler beklenir ve neden ısı 'belirti' değil 'koşul' sayılır?","steps":[{"t":"Belirtiler","a":"gaz çıkışı, kütle azalması","d":"Kalsiyum karbonat ısıtılınca CO₂ gazı açığa çıkar ve katı kütlesi azalır; gaz çıkışı gözlenebilir belirtidir."},{"t":"Isının rolü","a":"endotermik koşul","d":"Bu tepkime endotermiktir; ısı tepkimenin başlaması için dışarıdan verilen bir koşuldur, tepkimenin kendiliğinden açığa çıkardığı bir belirti değildir."}],"ans":"CaCO₃ → CaO + CO₂ tepkimesinde CO₂ gaz çıkışı ve kütle azalması belirtidir; verilen ısı ise tepkimeyi başlatan koşuldur, açığa çıkan bir belirti değildir."},{"q":"Bir öğrenci 'su buharlaşırken kabarcık çıkıyor, demek ki kimyasal tepkime var' diyor. Bu çıkarımı belirti mantığıyla eleştiriniz.","steps":[{"t":"Gözlemin doğası","a":"hâl değişimi","d":"Kaynayan suda görülen kabarcıklar, sıvı suyun gaz hâline (su buharı) geçmesidir; oluşan madde yine sudur."},{"t":"Hatanın nedeni","a":"yeni madde yok","d":"Kimyasal tepkime belirtisi için yeni bir madde oluşmalıdır; burada su buharı soğuyunca yine suya döner, dolayısıyla bu fiziksel bir değişimdir."}],"ans":"Çıkarım yanlıştır; kaynamadaki kabarcıklar yeni madde değil yalnızca su buharıdır, bu fiziksel bir hâl değişimidir, kimyasal tepkime değildir."}]}},"yanmaTepkime":{"ilkokul":{"kolay":[{"q":"Bir maddenin oksijenle birleşip ısı ve ışık vererek yanmasına ne denir?","steps":[{"t":"Oksijenle birleşme","a":"yanar","d":"Yakıt, havadaki oksijenle birleşir."},{"t":"Isı ve ışık","a":"yanma","d":"Bu sırada ısı ve genellikle ışık (alev) açığa çıkar; bu olaya yanma denir."}],"ans":"Bir maddenin oksijenle birleşip ısı ve ışık vererek tepkimesine yanma denir."},{"q":"Bir şeyin yanabilmesi için en gerekli gaz hangisidir?","steps":[{"t":"Hava","a":"oksijen içerir","d":"Yanma havadaki bir gaz sayesinde olur."},{"t":"Gerekli gaz","a":"oksijen","d":"Yanmanın olabilmesi için oksijen (O₂) gazına ihtiyaç vardır."}],"ans":"Bir şeyin yanabilmesi için oksijen (O₂) gazı gereklidir."},{"q":"Mum yandığında etrafa ne yayılır?","fig":"<svg viewBox='0 0 320 160'><rect x='145' y='70' width='30' height='70' fill='#cfd8e8' stroke='#1a2b45'/><path d='M160 35 C 150 55, 152 68, 160 70 C 168 68, 170 55, 160 35 Z' fill='#e0552b' stroke='#1a2b45'/><text x='160' y='155' font-size='11' text-anchor='middle' fill='#1a2b45'>mum alevi</text></svg>","steps":[{"t":"Alev","a":"ışık verir","d":"Yanan mum çevresine ışık yayar."},{"t":"Sıcaklık","a":"ısı verir","d":"Aynı zamanda etrafı ısıtır; yani mum yanarken ısı ve ışık yayılır."}],"ans":"Mum yandığında etrafa ısı ve ışık yayılır."},{"q":"Yanma sonucunda yakıt biter mi, başka maddeye mi dönüşür?","steps":[{"t":"Değişim","a":"dönüşür","d":"Yakıt yanınca yok olmaz, yeni maddelere dönüşür."},{"t":"Yeni maddeler","a":"gaz ve su","d":"Çoğu yakıt yandığında gaz (karbondioksit) ve su buharı oluşur."}],"ans":"Yakıt yanınca yok olmaz; karbondioksit ve su gibi yeni maddelere dönüşür."},{"q":"Yangını söndürmek için neden çoğu zaman su veya örtü kullanılır?","steps":[{"t":"Oksijeni kesmek","a":"havayı engelle","d":"Örtü ya da köpük, yanan yere oksijen gitmesini engeller."},{"t":"Yanma durur","a":"söner","d":"Oksijen olmadan yanma süremez, bu yüzden ateş söner."}],"ans":"Yanma için oksijen gerektiğinden, oksijeni keserek (örtü, köpük, su) yangın söndürülür."}],"zor":[{"q":"Bir mumun üstünü cam bardakla kapatınca neden bir süre sonra söner?","fig":"<svg viewBox='0 0 320 165'><path d='M110 30 h100 v110 h-100 Z' fill='none' stroke='#1a2b45'/><rect x='150' y='95' width='20' height='45' fill='#cfd8e8' stroke='#1a2b45'/><path d='M160 70 C 153 84, 155 93, 160 95 C 165 93, 167 84, 160 70 Z' fill='#e0552b' stroke='#1a2b45'/><text x='160' y='158' font-size='10' text-anchor='middle' fill='#1a2b45'>kapalı bardak</text></svg>","steps":[{"t":"Sınırlı oksijen","a":"bardakta az","d":"Bardağın içindeki oksijen miktarı sınırlıdır."},{"t":"Tükenir","a":"yanma durur","d":"Mum yandıkça oksijen tükenir; oksijen bitince yanma duracağı için mum söner."}],"ans":"Bardak içindeki oksijen sınırlı olduğundan tükenince yanma süremez ve mum söner."},{"q":"Odun yandığında geriye kül kalır; bu kül yakıtın neresinden gelir?","steps":[{"t":"Yanan kısım","a":"gaza döner","d":"Odunun bir kısmı oksijenle birleşip gaz (karbondioksit) ve su buharı olarak havaya gider."},{"t":"Kalan kısım","a":"kül","d":"Yanmayan mineral artıkları geride kül olarak kalır."}],"ans":"Odunun yanan kısmı gaz ve su buharına dönüşüp uçar; yanmayan mineral artıkları geride kül olarak kalır."},{"q":"Doğal gaz sobasının önünü kapatıp havalandırmazsak neden tehlikeli olabilir?","steps":[{"t":"Az oksijen","a":"eksik yanma","d":"Yeterli oksijen olmazsa yakıt tam yanmaz, buna eksik yanma denir."},{"t":"Zehirli gaz","a":"karbonmonoksit","d":"Eksik yanmada zehirli karbonmonoksit (CO) gazı oluşur; bu yüzden ortamı havalandırmak gerekir."}],"ans":"Oksijen yetersizse eksik yanma olur ve zehirli karbonmonoksit (CO) gazı oluşabileceği için tehlikelidir; bu yüzden havalandırma şarttır."},{"q":"İyi yanan bir ocak alevinin mavi, kötü yananın sarı-isli olması ne anlatır?","fig":"<svg viewBox='0 0 320 160'><path d='M90 120 C 80 80, 100 60, 95 40 C 110 60, 110 90, 105 120 Z' fill='#2b6be0' stroke='#1a2b45'/><text x='97' y='140' font-size='10' text-anchor='middle' fill='#1a2b45'>mavi: tam</text><path d='M215 120 C 205 75, 230 55, 222 35 C 240 60, 238 92, 232 120 Z' fill='#e0552b' stroke='#1a2b45'/><text x='225' y='140' font-size='10' text-anchor='middle' fill='#1a2b45'>sarı: eksik</text></svg>","steps":[{"t":"Mavi alev","a":"bol oksijen","d":"Mavi alev oksijenin yeterli olduğunu, yani tam yanmayı gösterir."},{"t":"Sarı-isli alev","a":"az oksijen","d":"Sarı, isli alev oksijenin yetersiz olduğunu, eksik yanma olduğunu gösterir."}],"ans":"Mavi alev yeterli oksijenle tam yanmayı, sarı-isli alev ise oksijen yetersizliğiyle eksik yanmayı gösterir."},{"q":"Yanma sonucu oluşan su buharını nasıl fark edebiliriz?","steps":[{"t":"Soğuk yüzey","a":"buğu yapar","d":"Yanan gazın üstüne soğuk bir cam tutulursa su buharı camda yoğuşur."},{"t":"Su damlası","a":"yoğuşma","d":"Camda oluşan buğu ve su damlaları, yanmada su buharı çıktığını gösterir."}],"ans":"Yanan alevin üstüne soğuk bir cam tutulduğunda camda buğu (su damlaları) oluşur; bu, yanmada su buharı çıktığını gösterir."}]},"ortaokul":{"kolay":[{"q":"Bir yanma tepkimesinde genel olarak girenler ve ürünler nelerdir?","steps":[{"t":"Girenler","a":"yakıt + O₂","d":"Yanmada bir yakıt, havadaki oksijenle (O₂) birleşir."},{"t":"Ürünler","a":"CO₂ + H₂O + ısı","d":"Tam yanmada karbondioksit (CO₂), su (H₂O) ve ısı açığa çıkar."}],"ans":"Yanma tepkimesinde yakıt + O₂ → CO₂ + H₂O olur ve ısı (genelde ışık da) açığa çıkar."},{"q":"Tam yanma ile eksik yanma arasındaki fark nedir?","steps":[{"t":"Tam yanma","a":"yeterli O₂","d":"Oksijen yeterliyse yakıt tam yanar; ürünler CO₂ ve H₂O olur."},{"t":"Eksik yanma","a":"az O₂","d":"Oksijen yetersizse eksik yanma olur; karbonmonoksit (CO) ve is (C) gibi ürünler de oluşur."}],"ans":"Tam yanmada (yeterli O₂) ürünler CO₂ ve H₂O olurken, eksik yanmada (az O₂) ayrıca zehirli CO ve is açığa çıkar."},{"q":"Doğal gazın ana bileşeni metanın tam yanması nasıl gösterilir?","fig":"<svg viewBox='0 0 320 150'><text x='80' y='75' font-size='12' text-anchor='middle' fill='#1a2b45'>CH₄ + 2O₂</text><text x='160' y='75' font-size='16' text-anchor='middle' fill='#1a2b45'>→</text><text x='245' y='75' font-size='12' text-anchor='middle' fill='#1a2b45'>CO₂ + 2H₂O</text><text x='160' y='115' font-size='10' text-anchor='middle' fill='#1a2b45'>+ ısı</text></svg>","steps":[{"t":"Yakıt ve O₂","a":"CH₄ + 2O₂","d":"Metan (CH₄) yeterli oksijenle (2O₂) yanar."},{"t":"Ürünler","a":"CO₂ + 2H₂O","d":"Tam yanma ürünleri karbondioksit ve su olur: CH₄ + 2O₂ → CO₂ + 2H₂O."}],"ans":"Metanın tam yanması CH₄ + 2O₂ → CO₂ + 2H₂O biçimindedir ve ısı açığa çıkar."},{"q":"Yanma tepkimeleri enerji açısından nasıl tepkimelerdir?","steps":[{"t":"Isı verir","a":"dışarı enerji","d":"Yanmada ortama ısı (ve ışık) verilir."},{"t":"Tür","a":"ekzotermik","d":"Dışarıya enerji verildiği için yanma ekzotermik (ısıveren) bir tepkimedir."}],"ans":"Yanma tepkimeleri dışarıya ısı verdiğinden ekzotermik (ısıveren) tepkimelerdir."},{"q":"Yanma için gerekli üç koşul (yanma üçgeni) nelerdir?","steps":[{"t":"Üç öğe","a":"yakıt, O₂, ısı","d":"Yanmanın başlaması için yakıt, oksijen ve tutuşma sıcaklığı (ısı) birlikte gerekir."},{"t":"Birinin yokluğu","a":"yanma durur","d":"Bu üçünden biri ortadan kalkarsa yanma sürmez; söndürme bu öğelerden birini yok etmeye dayanır."}],"ans":"Yanma için yakıt, oksijen ve tutuşma sıcaklığı (ısı) gerekir; bu üçü yanma üçgenini oluşturur ve biri yoksa yanma olmaz."}],"zor":[{"q":"CH₄ + 2O₂ → CO₂ + 2H₂O denkleminin denk olduğunu atom sayarak gösteriniz.","steps":[{"t":"Karbon ve hidrojen","a":"C 1=1, H 4=4","d":"Solda CH₄ → 1 C ve 4 H; sağda CO₂ → 1 C, 2H₂O → 4 H atomu; eşit."},{"t":"Oksijen","a":"4 = 4","d":"Solda 2O₂ → 4 O; sağda CO₂ (2 O) + 2H₂O (2 O) = 4 O atomu; eşit, denklem denktir."}],"ans":"C (1 = 1), H (4 = 4) ve O (4 = 4) atom sayıları iki tarafta eşit olduğundan CH₄ + 2O₂ → CO₂ + 2H₂O denktir."},{"q":"Eksik yanmada neden karbonmonoksit (CO) oluşur ve neden tehlikelidir?","fig":"<svg viewBox='0 0 320 145'><text x='75' y='70' font-size='11' text-anchor='middle' fill='#1a2b45'>2CH₄ + 3O₂</text><text x='150' y='70' font-size='15' text-anchor='middle' fill='#1a2b45'>→</text><text x='235' y='70' font-size='11' text-anchor='middle' fill='#1a2b45'>2CO + 4H₂O</text><text x='160' y='110' font-size='10' text-anchor='middle' fill='#1a2b45'>az oksijen: eksik yanma</text></svg>","steps":[{"t":"Az oksijen","a":"tam oksitlenemez","d":"Oksijen yetersizse karbon CO₂'ye kadar oksitlenemez, ara ürün olarak CO oluşur (örnek: 2CH₄ + 3O₂ → 2CO + 4H₂O)."},{"t":"Zehir etkisi","a":"kana bağlanır","d":"CO renksiz, kokusuz bir gazdır ve kanda oksijenin yerini alarak zehirlenmeye yol açar; bu yüzden çok tehlikelidir."}],"ans":"Yetersiz oksijende karbon tam oksitlenemediğinden CO oluşur; CO renksiz-kokusuz olup kanda oksijenin yerini aldığından zehirleyicidir."},{"q":"2C₂H₂ + 5O₂ → 4CO₂ + 2H₂O (asetilen yanması) denkleminin denk olduğunu gösteriniz.","steps":[{"t":"Karbon ve hidrojen","a":"C 4=4, H 4=4","d":"Solda 2C₂H₂ → 4 C ve 4 H; sağda 4CO₂ → 4 C, 2H₂O → 4 H atomu; eşit."},{"t":"Oksijen","a":"10 = 10","d":"Solda 5O₂ → 10 O; sağda 4CO₂ (8 O) + 2H₂O (2 O) = 10 O atomu; eşit, denklem denktir."}],"ans":"C (4 = 4), H (4 = 4) ve O (10 = 10) atomları iki tarafta eşit olduğundan 2C₂H₂ + 5O₂ → 4CO₂ + 2H₂O denktir."},{"q":"Bir sobanın bacasının iyi çekmemesi (havasız kalması) yanma açısından neden risklidir?","steps":[{"t":"Hava akışı azalır","a":"O₂ azalır","d":"Baca çekmezse taze hava (oksijen) girişi azalır ve ortam oksijence fakirleşir."},{"t":"Eksik yanma","a":"CO birikir","d":"Oksijen azalınca eksik yanma başlar ve zehirli karbonmonoksit (CO) gazı kapalı ortamda birikir."}],"ans":"Baca iyi çekmezse oksijen azalır, eksik yanma olur ve zehirli CO gazı ortamda birikeceğinden zehirlenme riski doğar."},{"q":"Hidrojenin yanması (2H₂ + O₂ → 2H₂O) neden 'temiz yakıt' olarak nitelenir?","fig":"<svg viewBox='0 0 320 140'><text x='80' y='65' font-size='12' text-anchor='middle' fill='#1a2b45'>2H₂ + O₂</text><text x='155' y='65' font-size='16' text-anchor='middle' fill='#1a2b45'>→</text><text x='225' y='65' font-size='12' text-anchor='middle' fill='#1a2b45'>2H₂O</text><text x='160' y='105' font-size='10' text-anchor='middle' fill='#1a2b45'>tek ürün: su</text></svg>","steps":[{"t":"Ürün","a":"sadece su","d":"Hidrojen yandığında tek ürün su (H₂O) olur; karbon içermediği için CO₂ veya CO çıkmaz."},{"t":"Çevre etkisi","a":"temiz","d":"Sera gazı (CO₂) ya da zehirli gaz oluşturmadığından temiz yakıt sayılır."}],"ans":"Hidrojen yanınca tek ürün su olduğundan ve CO₂ ile zehirli CO oluşturmadığından temiz yakıt olarak nitelenir."}]},"lise":{"kolay":[{"q":"Yanma tepkimesi termokimyasal olarak nasıl tanımlanır?","steps":[{"t":"Hızlı oksitlenme","a":"O₂ ile tepkime","d":"Yanma, bir yakıtın oksijenle hızlı ve ekzotermik tepkimesidir."},{"t":"Enerji","a":"ΔH < 0","d":"Tepkime ısı (genellikle ışık da) açığa çıkardığından entalpi değişimi negatiftir (ekzotermik)."}],"ans":"Yanma, bir yakıtın oksijenle hızlı ve ekzotermik (ΔH < 0) tepkimesidir; ürün olarak çoğunlukla CO₂ ve H₂O verir."},{"q":"Hidrokarbonların tam yanma ürünleri nelerdir ve neden bu ürünler oluşur?","steps":[{"t":"Tam oksitlenme","a":"yeterli O₂","d":"Yeterli oksijende karbon CO₂'ye, hidrojen ise H₂O'ya kadar tam oksitlenir."},{"t":"Ürünler","a":"CO₂ + H₂O","d":"Bu yüzden hidrokarbonun tam yanma ürünleri karbondioksit ve sudur."}],"ans":"Yeterli oksijende karbon CO₂'ye, hidrojen H₂O'ya tam oksitlendiğinden hidrokarbonların tam yanma ürünleri CO₂ ve H₂O olur."},{"q":"Eksik yanmanın ürünleri tam yanmadan nasıl farklılaşır?","steps":[{"t":"Sınırlı O₂","a":"kısmi oksitlenme","d":"Oksijen yetersiz olduğunda karbon CO₂'ye kadar oksitlenemez."},{"t":"Ürünler","a":"CO ve C (is)","d":"Bu durumda CO₂ yerine ya da yanında karbonmonoksit (CO) ve serbest karbon (is) oluşur."}],"ans":"Eksik yanmada oksijen yetersiz olduğundan karbon tam oksitlenemez; CO₂ yerine ya da yanında zehirli CO ve is (C) oluşur."},{"q":"Propanın (C₃H₈) tam yanma denklemi nasıl yazılır ve denkleştirilir?","fig":"<svg viewBox='0 0 320 150'><text x='80' y='75' font-size='12' text-anchor='middle' fill='#1a2b45'>C₃H₈ + 5O₂</text><text x='165' y='75' font-size='16' text-anchor='middle' fill='#1a2b45'>→</text><text x='250' y='75' font-size='12' text-anchor='middle' fill='#1a2b45'>3CO₂ + 4H₂O</text></svg>","steps":[{"t":"C ve H denkliği","a":"3CO₂, 4H₂O","d":"3 karbon için 3CO₂, 8 hidrojen için 4H₂O yazılır."},{"t":"O denkliği","a":"5O₂","d":"Sağda 3CO₂ (6 O) + 4H₂O (4 O) = 10 O atomu; bunu sağlamak için solda 5O₂ gerekir."}],"ans":"Propanın tam yanması C₃H₈ + 5O₂ → 3CO₂ + 4H₂O biçiminde denkleşir."},{"q":"Yanmanın başlaması için neden 'aktivasyon enerjisi' (tutuşma) gerekir?","steps":[{"t":"Eşik enerji","a":"bağ kırma","d":"Yakıt ve oksijen molekülleri tepkimeye girmeden önce belli bir eşik enerjiyi aşıp ilk bağların kırılması gerekir."},{"t":"Tutuşma","a":"kıvılcım/ısı","d":"Bir kıvılcım ya da ısı bu aktivasyon enerjisini sağlar; tepkime başladıktan sonra açığa çıkan ısı onu sürdürür."}],"ans":"Yanmanın başlaması için moleküllerin aktivasyon enerjisi eşiğini aşması gerekir; kıvılcım ya da ısı (tutuşma) bu enerjiyi sağlar, sonra ekzotermik ısı tepkimeyi sürdürür."}],"zor":[{"q":"C₃H₈ + 5O₂ → 3CO₂ + 4H₂O denkleminin tüm atomlar için denk olduğunu gösteriniz.","steps":[{"t":"C ve H","a":"C 3=3, H 8=8","d":"Solda C₃H₈ → 3 C ve 8 H; sağda 3CO₂ → 3 C, 4H₂O → 8 H atomu; eşit."},{"t":"Oksijen","a":"10 = 10","d":"Solda 5O₂ → 10 O; sağda 3CO₂ (6 O) + 4H₂O (4 O) = 10 O atomu; eşit, denklem denktir."}],"ans":"C (3 = 3), H (8 = 8) ve O (10 = 10) atom sayıları iki tarafta eşit olduğundan C₃H₈ + 5O₂ → 3CO₂ + 4H₂O denktir."},{"q":"NK'de 1 mol metanın (CH₄) tam yanması için kaç litre O₂ gerekir? (CH₄ + 2O₂ → CO₂ + 2H₂O)","fig":"<svg viewBox='0 0 320 140'><text x='80' y='65' font-size='12' text-anchor='middle' fill='#1a2b45'>CH₄ + 2O₂</text><text x='160' y='65' font-size='16' text-anchor='middle' fill='#1a2b45'>→</text><text x='245' y='65' font-size='12' text-anchor='middle' fill='#1a2b45'>CO₂ + 2H₂O</text><text x='160' y='105' font-size='10' text-anchor='middle' fill='#1a2b45'>1 mol : 2 mol</text></svg>","steps":[{"t":"Mol oranı","a":"1 CH₄ : 2 O₂","d":"Denkleme göre 1 mol CH₄ için 2 mol O₂ gerekir."},{"t":"Hacim","a":"44,8 L","d":"NK'de 1 mol gaz 22,4 L; 2 mol O₂ → 2 × 22,4 = 44,8 L."}],"ans":"1 mol metanın yanması 2 mol O₂ gerektirir; NK'de bu 2 × 22,4 = 44,8 litredir."},{"q":"8 g metan (CH₄) tam yandığında kaç gram CO₂ oluşur? (C=12, H=1, O=16)","steps":[{"t":"Mol CH₄","a":"0,5 mol","d":"CH₄ molmüktarı 16 g/mol; mol = 8 / 16 = 0,5 mol."},{"t":"Mol oranı","a":"1 CH₄ → 1 CO₂","d":"CH₄ + 2O₂ → CO₂ + 2H₂O; 1 mol CH₄, 1 mol CO₂ verir, yani 0,5 mol CO₂ oluşur."},{"t":"Kütle","a":"22 g","d":"CO₂ molmüktarı 44 g/mol; 0,5 × 44 = 22 g CO₂."}],"ans":"8 g metan 0,5 mol eder; 1:1 oranla 0,5 mol (22 g) CO₂ oluşur."},{"q":"Tam yanma ve eksik yanmayı oksijen miktarı, ürünler ve enerji verimi açısından karşılaştırınız.","steps":[{"t":"Tam yanma","a":"bol O₂, yüksek verim","d":"Oksijen yeterlidir; ürünler CO₂ ve H₂O olur, karbon en yüksek oksitlenme basamağına ulaştığından açığa çıkan enerji (ısı verimi) en yüksektir."},{"t":"Eksik yanma","a":"az O₂, düşük verim","d":"Oksijen yetersizdir; CO ve is oluşur, karbon tam oksitlenemediğinden açığa çıkan enerji daha azdır ve zehirli/kirletici ürünler doğar."}],"ans":"Tam yanmada bol oksijenle CO₂ ve H₂O oluşur ve enerji verimi en yüksektir; eksik yanmada oksijen yetersizliğiyle CO ve is oluşur, hem enerji verimi düşer hem zehirli kirletici ürünler açığa çıkar."},{"q":"Etanolün (C₂H₅OH) tam yanma denklemini yazıp denk olduğunu gösteriniz.","steps":[{"t":"Denklem","a":"C₂H₅OH + 3O₂ → 2CO₂ + 3H₂O","d":"Etanolde 2 C ve 6 H vardır; 2CO₂ ve 3H₂O yazılır, oksijen ise denkleştirilir."},{"t":"Atom sayımı","a":"C 2=2, H 6=6, O 6=6","d":"Sağda 2CO₂ (4 O) + 3H₂O (3 O) = 7 O; solda etanolün 1 O'su + 3O₂ (6 O) = 7 O atomu; tüm atomlar eşittir."}],"ans":"Etanolün tam yanması C₂H₅OH + 3O₂ → 2CO₂ + 3H₂O biçimindedir; C (2 = 2), H (6 = 6) ve O (7 = 7) eşit olduğundan denklem denktir."}]}}};
